import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Sender {
  USER = 'USER',
  AI = 'AI',
  SYSTEM = 'SYSTEM'
}

export enum InterviewMode {
  TEXT = 'TEXT', // Standard coding round
  VOICE = 'VOICE', // Live API phone screen
  ANALYSIS = 'ANALYSIS' // Deep thinking evaluation
}

export interface GroundingChunk {
  web?: { uri: string; title: string };
  maps?: { 
    uri: string; 
    title: string; 
    placeAnswerSources?: { reviewSnippets?: { text: string }[] }[] 
  };
}

export interface Message {
  id: string;
  sender: Sender;
  text: string;
  timestamp: number;
  isAudio?: boolean;
  audioData?: string; // Base64
  grounding?: GroundingChunk[];
  isThinking?: boolean;
}

export interface AudioDeviceConfig {
  sampleRate: number;
  numChannels: number;
}

import { Blob } from '@google/genai';

export const decodeAudioData = async (
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number
): Promise<AudioBuffer> => {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
};

export const base64ToBytes = (base64: string): Uint8Array => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export const bytesToBase64 = (bytes: Uint8Array): string => {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
};

export const createPcmBlob = (data: Float32Array): Blob => {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: bytesToBase64(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
};

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { GroundingChunk } from "../types";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- Text & Reasoning ---

export const generateInterviewQuestion = async (
  history: string, 
  useThinking: boolean = false
): Promise<{ text: string, grounding?: GroundingChunk[] }> => {

  const model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const config: any = {
    systemInstruction: "You are a senior technical interviewer. Keep responses concise and strictly text-based. No markdown formatting. Focus on React, TypeScript, and Algorithms.",
  };

  if (useThinking) {
    // Gemini 3 Pro Thinking Mode
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else {
    // Standard config
    config.temperature = 0.7;
  }

  try {
    const response = await ai.models.generateContent({
      model,
      contents: history,
      config
    });

    return {
      text: response.text || "Error generating response.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[]
    };
  } catch (error) {
    console.error("GenAI Text Error:", error);
    return { text: "Connection error with the Interview Engine." };
  }
};

export const fastAck = async (input: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-flash-lite-latest', // Fast model
      contents: `Provide a 3-word acknowledgement for: ${input}`,
    });
    return response.text || "Acknowledged.";
  } catch (e) {
    return "...";
  }
};

// --- Audio Transcription ---

export const transcribeAudioFile = async (base64Audio: string, mimeType: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Audio, mimeType } },
          { text: "Transcribe this audio exactly as spoken." }
        ]
      }
    });
    return response.text || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw error;
  }
};

// --- Maps Grounding ---

export const getGeographicContext = async (query: string, lat?: number, lng?: number): Promise<{ text: string, grounding: GroundingChunk[] }> => {
  try {
    const config: any = {
      tools: [{ googleMaps: {} }],
    };

    if (lat && lng) {
      config.toolConfig = {
        retrievalConfig: {
          latLng: { latitude: lat, longitude: lng }
        }
      };
    }

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash', // Required for Maps
      contents: query,
      config
    });

    return {
      text: response.text || "I couldn't find that location info.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[] || []
    };
  } catch (error) {
    console.error("Maps Error:", error);
    return { text: "Unable to access geographic data.", grounding: [] };
  }
};

// --- TTS ---

export const generateSpeech = async (text: string): Promise<ArrayBuffer> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data returned");

    // Convert base64 to ArrayBuffer for playback
    const binaryString = atob(base64Audio);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;

  } catch (error) {
    console.error("TTS Error:", error);
    throw error;
  }
};

// --- Live API (Exporting the instance wrapper or connection logic) ---

export const getLiveSession = () => {
    return ai.live;
};

import React from 'react';
import { Message, Sender, GroundingChunk } from '../types';

interface TerminalMessageProps {
  message: Message;
  onPlayAudio: (text: string) => void;
}

export const TerminalMessage: React.FC<TerminalMessageProps> = ({ message, onPlayAudio }) => {
  const isUser = message.sender === Sender.USER;
  const isSystem = message.sender === Sender.SYSTEM;

  const renderGrounding = (chunks?: GroundingChunk[]) => {
    if (!chunks || chunks.length === 0) return null;
    return (
      <div className="mt-2 text-xs grid gap-1">
        {chunks.map((chunk, i) => {
          if (chunk.web) {
            return (
              <a key={i} href={chunk.web.uri} target="_blank" rel="noreferrer" className="text-blue-400 hover:underline flex items-center gap-1">
                [SOURCE] {chunk.web.title}
              </a>
            );
          }
          if (chunk.maps) {
            return (
              <div key={i} className="bg-gray-800 p-2 rounded border border-gray-700 mt-1">
                 <a href={chunk.maps.uri} target="_blank" rel="noreferrer" className="text-green-400 font-bold hover:underline">
                  📍 {chunk.maps.title}
                </a>
                {chunk.maps.placeAnswerSources?.map((src, j) => (
                  <div key={j} className="text-gray-400 italic pl-4 border-l-2 border-gray-600 mt-1">
                    "{src.reviewSnippets?.[0]?.text}"
                  </div>
                ))}
              </div>
            );
          }
          return null;
        })}
      </div>
    );
  };

  if (isSystem) {
    return (
      <div className="py-1 text-yellow-500 font-mono text-sm opacity-80">
        <span className="mr-2">SYSTEM &gt;&gt;</span>
        {message.text}
      </div>
    );
  }

  return (
    <div className={`py-2 font-mono flex flex-col ${isUser ? 'items-end' : 'items-start'}`}>
      <div className={`max-w-[85%] ${isUser ? 'text-right' : 'text-left'}`}>
        <div className="flex items-center gap-2 mb-1 opacity-60 text-xs">
          <span className={isUser ? 'text-cyan-400' : 'text-green-400'}>
            {isUser ? 'CANDIDATE' : 'INTERVIEWER_AI'}
          </span>
          <span>{new Date(message.timestamp).toLocaleTimeString([], { hour12: false })}</span>
          {message.isThinking && <span className="text-purple-400 animate-pulse">[DEEP THOUGHT]</span>}
        </div>

        <div className={`whitespace-pre-wrap ${isUser ? 'text-gray-300' : 'text-white'}`}>
          {message.text}
        </div>

        {!isUser && !message.isThinking && message.text && (
            <button 
                onClick={() => onPlayAudio(message.text)}
                className="mt-2 text-xs border border-gray-700 rounded px-2 py-1 text-gray-500 hover:text-green-400 hover:border-green-400 transition-colors flex items-center gap-1"
            >
                ▶ PLAY TTS
            </button>
        )}

        {renderGrounding(message.grounding)}
      </div>
    </div>
  );
};

import React, { useEffect, useRef } from 'react';

interface AudioVisualizerProps {
  isActive: boolean;
}

export const AudioVisualizer: React.FC<AudioVisualizerProps> = ({ isActive }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationId: number;
    let step = 0;

    const draw = () => {
      if (!isActive) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        return;
      }

      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = '#4ade80'; // Green-400

      const bars = 20;
      const width = canvas.width / bars;

      for (let i = 0; i < bars; i++) {
        // Pseudo-random height based on sine wave time
        const height = Math.abs(Math.sin(step * 0.1 + i)) * (canvas.height * 0.8) + 5;
        const x = i * width;
        const y = (canvas.height - height) / 2;

        ctx.fillRect(x + 1, y, width - 2, height);
      }

      step++;
      animationId = requestAnimationFrame(draw);
    };

    if (isActive) {
      draw();
    } else {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
    }

    return () => cancelAnimationFrame(animationId);
  }, [isActive]);

  return (
    <canvas 
      ref={canvasRef} 
      width={200} 
      height={40} 
      className="opacity-80"
    />
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  transcribeAudioFile, 
  getGeographicContext, 
  getLiveSession,
  generateSpeech,
  fastAck
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { Message, Sender, InterviewMode } from './types';
import { createPcmBlob, decodeAudioData, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Refs for Audio
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initial Welcome
  useEffect(() => {
    addMessage(Sender.SYSTEM, "DevInterview AI Console v2.5.0 initialized...");
    addMessage(Sender.AI, "Hello. I am the AI Interviewer Engine. I will conduct your technical assessment today.\n\nWe can proceed via Text (Standard) or Voice (Live Check).\nType 'help' for commands or just start coding/speaking.");
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      const audioBufferData = await generateSpeech(text);
      const audioBuffer = await ctx.decodeAudioData(audioBufferData);

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e) {
      console.error("TTS Playback failed", e);
      addMessage(Sender.SYSTEM, "Error playing audio.");
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    // Command handling
    if (userText.toLowerCase() === '/live') {
      startLiveSession();
      return;
    }
    if (userText.toLowerCase() === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);
    // Don't display ack, just used to simulate "read" status or internal logic, 
    // but here we can optionally log it. For now, we skip displaying it to keep console clean.

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      isComplex
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(`USER (Audio Transcript): ${text}`);
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    setMode(InterviewMode.VOICE);
    addMessage(Sender.SYSTEM, "Connecting to Gemini Live API...");

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 16000});
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        // Connect Logic
        const sessionPromise = liveClient.connect({
            model: 'gemini-2.5-flash-native-audio-preview-12-2025',
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: "You are a friendly but rigorous technical interviewer. Keep responses short and conversational. Ask one coding question at a time.",
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        const blob = createPcmBlob(inputData);
                        sessionPromise.then(session => session.sendRealtimeInput({ media: blob }));
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        const audioBuffer = await decodeAudioData(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: () => {
                    setIsLiveConnected(false);
                    setMode(InterviewMode.TEXT);
                    addMessage(Sender.SYSTEM, "Live session closed.");
                },
                onerror: (e) => {
                    console.error(e);
                    addMessage(Sender.SYSTEM, "Live API Error.");
                }
            }
        });

    } catch (e) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, "Failed to start live session.");
        setMode(InterviewMode.TEXT);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-4 flex justify-between items-center shadow-md z-10">
        <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.5</span></h1>
        </div>
        <div className="flex items-center gap-4 text-xs">
            {mode === InterviewMode.VOICE && <AudioVisualizer isActive={isLiveConnected} />}
            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Terminal Output */}
      <main className="flex-1 overflow-y-auto p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
        {messages.map((msg) => (
          <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
        ))}
        {isLoading && (
           <div className="py-2 text-cyan-500 animate-pulse font-mono">
             &gt; Analyzing response...
           </div>
        )}
        <div ref={messagesEndRef} />
      </main>

      {/* Input Area */}
      <footer className="bg-[#161b22] border-t border-[#30363d] p-4">
        <div className="max-w-4xl mx-auto w-full flex gap-3 items-center">
            <span className="text-green-500 font-bold select-none">{">"}</span>

            <form onSubmit={handleTextSubmit} className="flex-1">
                <input
                    type="text"
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder={mode === InterviewMode.VOICE ? "Voice Active - Speak now..." : "Type your answer or command..."}
                    className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono"
                    disabled={mode === InterviewMode.VOICE || isLoading}
                    autoFocus
                />
            </form>

            {/* Toolbar */}
            <div className="flex items-center gap-2">
                <button 
                    onClick={() => fileInputRef.current?.click()}
                    title="Upload Audio Answer"
                    className="p-2 hover:bg-[#30363d] rounded text-gray-400 hover:text-white transition-colors"
                >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                </button>
                <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="audio/*"
                    onChange={handleFileUpload}
                />

                <button 
                    onClick={mode === InterviewMode.VOICE ? () => window.location.reload() : startLiveSession}
                    className={`px-3 py-1 rounded text-xs font-bold transition-colors ${
                        mode === InterviewMode.VOICE 
                        ? 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/50' 
                        : 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/50'
                    }`}
                >
                    {mode === InterviewMode.VOICE ? 'END CALL' : 'START LIVE CALL'}
                </button>
            </div>
        </div>

        {/* Helper Hints */}
        <div className="max-w-4xl mx-auto w-full mt-2 text-[10px] text-gray-600 flex gap-4">
            <span>Cmds: /live (Voice Mode), /maps (Geo Context)</span>
            <span>Gemini Models: 3-Pro (Reasoning), 3-Flash (Transcribe), 2.5-Live (Voice)</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  transcribeAudioFile, 
  getGeographicContext, 
  getLiveSession,
  generateSpeech,
  fastAck
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { Message, Sender, InterviewMode } from './types';
import { createPcmBlob, decodeAudioData, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

// Polyfill type for Safari/Webkit
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Refs for Audio
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initial Welcome
  useEffect(() => {
    addMessage(Sender.SYSTEM, "DevInterview AI Console v2.5.0 initialized...");
    addMessage(Sender.AI, "Hello. I am the AI Interviewer Engine. I will conduct your technical assessment today.\n\nWe can proceed via Text (Standard) or Voice (Live Check).\nType 'help' for commands or just start coding/speaking.");
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      const audioBufferData = await generateSpeech(text);
      const audioBuffer = await ctx.decodeAudioData(audioBufferData);

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e) {
      console.error("TTS Playback failed", e);
      addMessage(Sender.SYSTEM, "Error playing audio.");
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    // Command handling
    if (userText.toLowerCase() === '/live') {
      startLiveSession();
      return;
    }
    if (userText.toLowerCase() === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);
    // Don't display ack, just used to simulate "read" status or internal logic, 
    // but here we can optionally log it. For now, we skip displaying it to keep console clean.

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      isComplex
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(`USER (Audio Transcript): ${text}`);
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    setMode(InterviewMode.VOICE);
    addMessage(Sender.SYSTEM, "Connecting to Gemini Live API...");

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 16000});
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        // Connect Logic
        const sessionPromise = liveClient.connect({
            model: 'gemini-2.5-flash-native-audio-preview-12-2025',
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: "You are a friendly but rigorous technical interviewer. Keep responses short and conversational. Ask one coding question at a time.",
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        const blob = createPcmBlob(inputData);
                        sessionPromise.then(session => session.sendRealtimeInput({ media: blob }));
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        const audioBuffer = await decodeAudioData(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: () => {
                    setIsLiveConnected(false);
                    setMode(InterviewMode.TEXT);
                    addMessage(Sender.SYSTEM, "Live session closed.");
                },
                onerror: (e) => {
                    console.error(e);
                    addMessage(Sender.SYSTEM, "Live API Error.");
                }
            }
        });

    } catch (e) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, "Failed to start live session.");
        setMode(InterviewMode.TEXT);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-4 flex justify-between items-center shadow-md z-10">
        <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.5</span></h1>
        </div>
        <div className="flex items-center gap-4 text-xs">
            {mode === InterviewMode.VOICE && <AudioVisualizer isActive={isLiveConnected} />}
            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Terminal Output */}
      <main className="flex-1 overflow-y-auto p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
        {messages.map((msg) => (
          <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
        ))}
        {isLoading && (
           <div className="py-2 text-cyan-500 animate-pulse font-mono">
             &gt; Analyzing response...
           </div>
        )}
        <div ref={messagesEndRef} />
      </main>

      {/* Input Area */}
      <footer className="bg-[#161b22] border-t border-[#30363d] p-4">
        <div className="max-w-4xl mx-auto w-full flex gap-3 items-center">
            <span className="text-green-500 font-bold select-none">{">"}</span>

            <form onSubmit={handleTextSubmit} className="flex-1">
                <input
                    type="text"
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder={mode === InterviewMode.VOICE ? "Voice Active - Speak now..." : "Type your answer or command..."}
                    className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono"
                    disabled={mode === InterviewMode.VOICE || isLoading}
                    autoFocus
                />
            </form>

            {/* Toolbar */}
            <div className="flex items-center gap-2">
                <button 
                    onClick={() => fileInputRef.current?.click()}
                    title="Upload Audio Answer"
                    className="p-2 hover:bg-[#30363d] rounded text-gray-400 hover:text-white transition-colors"
                >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                </button>
                <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="audio/*"
                    onChange={handleFileUpload}
                />

                <button 
                    onClick={mode === InterviewMode.VOICE ? () => window.location.reload() : startLiveSession}
                    className={`px-3 py-1 rounded text-xs font-bold transition-colors ${
                        mode === InterviewMode.VOICE 
                        ? 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/50' 
                        : 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/50'
                    }`}
                >
                    {mode === InterviewMode.VOICE ? 'END CALL' : 'START LIVE CALL'}
                </button>
            </div>
        </div>

        {/* Helper Hints */}
        <div className="max-w-4xl mx-auto w-full mt-2 text-[10px] text-gray-600 flex gap-4">
            <span>Cmds: /live (Voice Mode), /maps (Geo Context)</span>
            <span>Gemini Models: 3-Pro (Reasoning), 3-Flash (Transcribe), 2.5-Live (Voice)</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { GroundingChunk } from "../types";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- Text & Reasoning ---

export const generateInterviewQuestion = async (
  history: string, 
  useThinking: boolean = false
): Promise<{ text: string, grounding?: GroundingChunk[] }> => {

  const model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const config: any = {
    // Updated system instruction for Tutoring behavior
    systemInstruction: "You are an expert AI Coding Tutor and Technical Interviewer. Your goal is to help users improve their skills in React, TypeScript, and Algorithms. \n\n1. Analyze the user's response to assess their skill level.\n2. If the user gives a weak answer, provide a clear explanation and a simpler follow-up.\n3. If the user gives a strong answer, challenge them with edge cases or optimization questions.\n4. Act as a mentor: offer constructive feedback, debugging tips, and best practices.\n5. Keep responses strictly text-based (no markdown) and concise. Do not provide full solutions immediately; guide the user to the solution.",
  };

  if (useThinking) {
    // Gemini 3 Pro Thinking Mode
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else {
    // Standard config
    config.temperature = 0.7;
  }

  try {
    const response = await ai.models.generateContent({
      model,
      contents: history,
      config
    });

    return {
      text: response.text || "Error generating response.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[]
    };
  } catch (error) {
    console.error("GenAI Text Error:", error);
    return { text: "Connection error with the Interview Engine." };
  }
};

export const fastAck = async (input: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-flash-lite-latest', // Fast model
      contents: `Provide a 3-word acknowledgement for: ${input}`,
    });
    return response.text || "Acknowledged.";
  } catch (e) {
    return "...";
  }
};

// --- Audio Transcription ---

export const transcribeAudioFile = async (base64Audio: string, mimeType: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Audio, mimeType } },
          { text: "Transcribe this audio exactly as spoken." }
        ]
      }
    });
    return response.text || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw error;
  }
};

// --- Maps Grounding ---

export const getGeographicContext = async (query: string, lat?: number, lng?: number): Promise<{ text: string, grounding: GroundingChunk[] }> => {
  try {
    const config: any = {
      tools: [{ googleMaps: {} }],
    };

    if (lat && lng) {
      config.toolConfig = {
        retrievalConfig: {
          latLng: { latitude: lat, longitude: lng }
        }
      };
    }

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash', // Required for Maps
      contents: query,
      config
    });

    return {
      text: response.text || "I couldn't find that location info.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[] || []
    };
  } catch (error) {
    console.error("Maps Error:", error);
    return { text: "Unable to access geographic data.", grounding: [] };
  }
};

// --- TTS ---

export const generateSpeech = async (text: string): Promise<ArrayBuffer> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data returned");

    // Convert base64 to ArrayBuffer for playback
    const binaryString = atob(base64Audio);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;

  } catch (error) {
    console.error("TTS Error:", error);
    throw error;
  }
};

