            <button 
            onClick={() => { setOutput([]); setError(null); }}
            className="px-3 py-1 text-xs text-gray-400 hover:text-white transition-colors"
            >
            CLEAR
            </button>
            <button 
            onClick={runCode}
            className="px-3 py-1 bg-green-600 hover:bg-green-700 text-white text-xs rounded font-mono transition-colors flex items-center gap-1"
            >
            ▶ RUN
            </button>
        </div>
      </div>

      {/* Editor Area */}
      <textarea
        value={code}
        onChange={(e) => setCode(e.target.value)}
        className="flex-1 bg-[#0d1117] text-[#c9d1d9] p-4 font-mono text-sm resize-none focus:outline-none leading-relaxed"
        spellCheck={false}
        placeholder="// Type JavaScript here..."
      />

      {/* Output Area */}
      <div className="h-1/3 border-t border-[#30363d] bg-[#010409] flex flex-col">
        <div className="px-4 py-1 text-[10px] text-gray-500 border-b border-[#30363d] bg-[#161b22]">CONSOLE OUTPUT</div>
        <div className="flex-1 p-4 font-mono text-xs overflow-auto">
