type LanguageKey = keyof typeof LANGUAGES;

export const CodeEditor: React.FC = () => {
  const [language, setLanguage] = useState<LanguageKey>('javascript');
  const [code, setCode] = useState<string>(LANGUAGES.javascript.snippet);
  const [output, setOutput] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);

  // UI States
  const [isRunning, setIsRunning] = useState(false);
  const [isReviewing, setIsReviewing] = useState(false);
  const [isCollabActive, setIsCollabActive] = useState(false);
  const [peers, setPeers] = useState<Peer[]>([]);

  // Refs for tracking cursor during remote updates
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const lastLocalUpdate = useRef<number>(0);

  // --- Collaboration Hook ---
  useEffect(() => {
    // Subscribe to Peer Updates
    collabService.subscribeToPeers((activePeers) => {
      setPeers(activePeers);
    });

    // Subscribe to Data Updates
    const handleRemoteMessage = (msg: CollabMessage) => {
      if (!isCollabActive) return;

      if (msg.type === 'CODE_UPDATE') {
        const { code: newCode, language: newLang } = msg.payload;

        // Prevent echo if we just sent this (timestamp check could also work)
        if (newCode !== code) {
          // Preserve cursor position
          const textArea = textareaRef.current;
          const currentPos = textArea?.selectionStart || 0;

          setCode(newCode);
          if (newLang !== language) setLanguage(newLang);

          // Restore cursor on next tick
          requestAnimationFrame(() => {
            if (textArea) {
              textArea.selectionStart = currentPos;
              textArea.selectionEnd = currentPos;
            }
          });
        }
      } 
      else if (msg.type === 'LANGUAGE_UPDATE') {
        setLanguage(msg.payload.language);
      }
    };

    collabService.subscribe(handleRemoteMessage);

    return () => {
      collabService.unsubscribe(handleRemoteMessage);
    };
  }, [isCollabActive, code, language]);


  // --- Handlers ---

  const handleLanguageChange = (newLang: LanguageKey) => {
    setLanguage(newLang);
    const newCode = LANGUAGES[newLang].snippet;
    setCode(newCode);
    setOutput([]);
    setError(null);

    if (isCollabActive) {
      collabService.broadcast('CODE_UPDATE', { code: newCode, language: newLang });
    }
  };

  const handleCodeChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const newCode = e.target.value;
    setCode(newCode);
    lastLocalUpdate.current = Date.now();

    if (isCollabActive) {
      collabService.broadcast('CODE_UPDATE', { code: newCode, language });
    }
  };

  const toggleCollab = () => {
    setIsCollabActive(!isCollabActive);
    // Broadcast current state when enabling
    if (!isCollabActive) {
      collabService.broadcast('CODE_UPDATE', { code, language });
    }
  };

  const handleReview = async () => {
    setOutput([]);
    setError(null);
    setIsReviewing(true);
    setOutput(["Analyzing code with Gemini 3 Pro..."]);

    try {
        const result = await reviewCodeWithAI(LANGUAGES[language].name, code);
        setOutput([
            "--- AI CODE REVIEW ---", 
            `Language: ${LANGUAGES[language].name}`, 
            "----------------------", 
            ...result.split('\n')
        ]);
    } catch (e) {
        setError("Failed to complete code review.");
    } finally {
        setIsReviewing(false);
    }
  };

  const runCode = async () => {
    setOutput([]);
    setError(null);
    setIsRunning(true);

    if (language === 'javascript') {
        runLocalJs();
    } else {
        try {
            const result = await runCodeWithAI(LANGUAGES[language].name, code);
            setOutput(result.split('\n'));
        } catch (e) {
            setError("Failed to execute code.");
        } finally {
            setIsRunning(false);
        }
    }
  };

  const runLocalJs = () => {
    const logs: string[] = [];
    const originalLog = console.log;
    const originalError = console.error;
    const originalWarn = console.warn;

    const mockLog = (...args: any[]) => {
      logs.push(args.map(a => {
        try {
            return typeof a === 'object' ? JSON.stringify(a) : String(a);
        } catch (e) {
            return '[Circular]';
        }
      }).join(' '));
    };

    console.log = mockLog;
    console.error = mockLog;
    console.warn = mockLog;

    try {
        // eslint-disable-next-line no-new-func
        new Function(code)();
    } catch (err: any) {
        setError(err.toString());
    } finally {
        console.log = originalLog;
        console.error = originalError;
        console.warn = originalWarn;
        setOutput(logs);
        setIsRunning(false);
    }
  };

  return (
    <div className="flex flex-col h-full border-l border-[#30363d] bg-[#0d1117]">
      {/* Toolbar */}
      <div className="flex items-center justify-between px-4 py-2 bg-[#161b22] border-b border-[#30363d]">
        <div className="flex items-center gap-2">
            <span className="text-xs font-bold text-gray-400">PLAYGROUND</span>
            <select 
                value={language}
                onChange={(e) => handleLanguageChange(e.target.value as LanguageKey)}
                className="bg-[#0d1117] text-xs text-gray-300 border border-[#30363d] rounded px-2 py-1 outline-none focus:border-blue-500"
            >
                {Object.entries(LANGUAGES).map(([key, config]) => (
                    <option key={key} value={key}>{config.name}</option>
                ))}
            </select>
        </div>

        {/* Right Actions */}
        <div className="flex items-center gap-2">
            {/* Collaboration Toggle */}
            <div className={`flex items-center gap-2 px-2 py-1 rounded border border-[#30363d] transition-colors ${isCollabActive ? 'bg-[#1f2937]' : ''}`}>
                <div 
                  className={`w-2 h-2 rounded-full ${isCollabActive ? 'bg-green-500 animate-pulse' : 'bg-gray-600'}`} 
                />
                <button 
                  onClick={toggleCollab}
                  className="text-[10px] font-bold text-gray-300 hover:text-white uppercase tracking-wider"
                >
                  {isCollabActive ? 'LIVE SESSION' : 'OFFLINE'}
                </button>

                {isCollabActive && peers.length > 0 && (
                   <div className="flex -space-x-1 ml-1">
                      {peers.map(peer => (
                        <div 
                          key={peer.id} 
                          className="w-4 h-4 rounded-full border border-[#161b22]" 
                          style={{backgroundColor: peer.color}}
                          title={peer.username}
                        />
                      ))}
                      <span className="text-[10px] text-gray-400 ml-2">+{peers.length}</span>
                   </div>
                )}
            </div>

            <button 
                onClick={() => { setOutput([]); setError(null); }}
                className="px-3 py-1 text-xs text-gray-400 hover:text-white transition-colors"
            >
                CLEAR
            </button>
            <button
                onClick={handleReview}
                disabled={isRunning || isReviewing}
                className={`px-3 py-1 text-white text-xs rounded font-mono transition-colors flex items-center gap-1 ${isReviewing ? 'bg-purple-800 cursor-wait' : 'bg-purple-600 hover:bg-purple-700'}`}
            >
                {isReviewing ? '...' : '🔍 REVIEW'}
            </button>
            <button 
                onClick={runCode}
                disabled={isRunning || isReviewing}
                className={`px-3 py-1 text-white text-xs rounded font-mono transition-colors flex items-center gap-1 ${isRunning ? 'bg-gray-600 cursor-wait' : 'bg-green-600 hover:bg-green-700'}`}
            >
                {isRunning ? '...' : '▶ RUN'}
            </button>
        </div>
      </div>

      {/* Editor Area */}
      <div className="flex-1 relative">
         <textarea
            ref={textareaRef}
            value={code}
            onChange={handleCodeChange}
            className="w-full h-full bg-[#0d1117] text-[#c9d1d9] p-4 font-mono text-sm resize-none focus:outline-none leading-relaxed"
            spellCheck={false}
            placeholder="// Type code here..."
        />
        {/* Simple visual cue for collab mode */}
        {isCollabActive && peers.length > 0 && (
            <div className="absolute top-2 right-4 text-[10px] text-green-500 opacity-50 pointer-events-none">
                ● Peer Connected
            </div>
        )}
      </div>

      {/* Output Area */}
      <div className="h-1/3 border-t border-[#30363d] bg-[#010409] flex flex-col">
        <div className="px-4 py-1 text-[10px] text-gray-500 border-b border-[#30363d] bg-[#161b22] flex justify-between">
            <span>OUTPUT / REVIEW</span>
            {language !== 'javascript' && isRunning && <span className="text-xs text-blue-400 opacity-70">Running via AI Runner</span>}
        </div>
        <div className="flex-1 p-4 font-mono text-xs overflow-auto">
          {output.map((line, i) => (
            <div key={i} className="text-gray-300 mb-1 border-b border-gray-800 pb-1 last:border-0 whitespace-pre-wrap">{line}</div>
          ))}
          {error && <div className="text-red-400 font-bold">{error}</div>}
          {!output.length && !error && <div className="text-gray-700 italic select-none">Run code to execute, or Review to analyze...</div>}
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { GroundingChunk, Persona } from "../types";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- Helper: Retry Logic ---
const callWithRetry = async <T>(fn: () => Promise<T>, retries = 3, baseDelay = 1000): Promise<T> => {
  let attempt = 0;
  while (true) {
    try {
      return await fn();
    } catch (e: any) {
      attempt++;
      if (attempt >= retries) throw e;

      // Retry on network errors, 503 (Service Unavailable), or 429 (Too Many Requests)
      const isNetworkError = e.message?.includes('Network') || e.message?.includes('fetch') || e.cause?.name === 'ConnectTimeoutError';
      const isServerOverload = e.status === 503 || e.status === 429;

      if (isNetworkError || isServerOverload) {
        const delay = baseDelay * Math.pow(2, attempt - 1);
        console.warn(`Attempt ${attempt} failed. Retrying in ${delay}ms...`);
        await new Promise(resolve => setTimeout(resolve, delay));
        continue;
      }

      throw e;
    }
  }
};

// --- Text & Reasoning ---

export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false
): Promise<{ text: string, grounding?: GroundingChunk[] }> => {

  const model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const systemInstructions = {
    [Persona.TUTOR]: "You are an expert AI Coding Tutor. \n\n1. Explain concepts clearly and patiently.\n2. If the user makes a mistake, guide them gently to the solution.\n3. Provide code snippets and examples to illustrate points.\n4. Be encouraging and friendly.\n5. Focus on teaching best practices and theory.",
    [Persona.INTERVIEWER]: "You are a strict Senior Technical Interviewer. \n\n1. Conduct a professional coding interview.\n2. Ask exactly ONE question at a time.\n3. Do NOT provide the full solution. If the user gets stuck, give a minimal hint but note the penalty.\n4. Evaluate efficiency (Big O) and code quality critically.\n5. Keep responses concise and neutral. Do not chit-chat."
  };

  const config: any = {
    systemInstruction: systemInstructions[persona],
  };

  if (useThinking) {
    // Gemini 3 Pro Thinking Mode
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else {
    // Standard config
    config.temperature = 0.7;
  }

  try {
    const response = await callWithRetry(() => ai.models.generateContent({
      model,
      contents: history,
      config
    }));

    return {
      text: response.text || "Error generating response.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[]
    };
  } catch (error: any) {
    console.error("GenAI Text Error:", error);
    // Return a user-friendly message based on the error
    let errorMessage = "Connection error with the Interview Engine. Please check your internet connection.";
    if (error.status === 429) {
      errorMessage = "I'm receiving too many requests right now. Please wait a moment.";
    }
    return { text: errorMessage };
  }
};

export const fastAck = async (input: string): Promise<string> => {
  try {
    // fastAck uses a lighter retry strategy (1 retry) to stay fast
    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-flash-lite-latest', // Fast model
      contents: `Provide a 3-word acknowledgement for: ${input}`,
    }), 1, 500);
    return response.text || "Acknowledged.";
  } catch (e) {
    // Silent failure for ack to avoid cluttering logs
    return "...";
  }
};

// --- Code Execution & Review ---

export const runCodeWithAI = async (language: string, code: string): Promise<string> => {
  try {
    const prompt = `Act as a strictly deterministic compiler and execution engine for ${language}.
Your task is to EXECUTE the provided code and return ONLY the standard output (stdout) and standard error (stderr).

Rules:
1. Output ONLY the execution result. Do not offer explanations, greetings, or markdown code blocks.
2. If the code has a syntax error, simulate the compiler error message.
3. If the code is incomplete, output "Error: Unexpected end of input".

Code to execute:
${code}
`;

    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: prompt,
      config: {
        temperature: 0.0, // Strict deterministic output
      }
    }));

    let text = response.text || "";
    // Clean up if model accidentally adds markdown
    text = text.replace(/^```[\w]*\n?/, '').replace(/\n?```$/, '');
    return text.trim() || "[No Output]";
  } catch (error) {
    console.error("AI Execution Error:", error);
    return "Error: Execution timed out or network failed. Please try again.";
  }
};

export const reviewCodeWithAI = async (language: string, code: string): Promise<string> => {
  try {
    const prompt = `Act as a Senior Software Engineer and Technical Interviewer.
Review the following ${language} code:

${code}

Identify potential bugs, logic errors, style issues, and optimization opportunities. 
Be concise, constructive, and actionable. Format your response as a clear list or short paragraphs.`;

    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Strong reasoning model for code review
      contents: prompt,
    }));

    let text = response.text || "";
    // Clean up if model accidentally adds markdown code blocks around the whole response
    text = text.replace(/^```[\w]*\n?/, '').replace(/\n?```$/, '');
    return text || "No feedback generated.";
  } catch (error) {
    console.error("Review Error:", error);
    return "Error: Failed to retrieve code review from AI.";
  }
};

// --- Audio Transcription ---

export const transcribeAudioFile = async (base64Audio: string, mimeType: string): Promise<string> => {
  try {
    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Audio, mimeType } },
          { text: "Transcribe this audio exactly as spoken." }
        ]
      }
    }));
    return response.text || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw error;
  }
};

// --- Maps Grounding ---

export const getGeographicContext = async (query: string, lat?: number, lng?: number): Promise<{ text: string, grounding: GroundingChunk[] }> => {
  try {
    const config: any = {
      tools: [{ googleMaps: {} }],
    };

    if (lat && lng) {
      config.toolConfig = {
        retrievalConfig: {
          latLng: { latitude: lat, longitude: lng }
        }
      };
    }

    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-2.5-flash', // Required for Maps
      contents: query,
      config
    }));

    return {
      text: response.text || "I couldn't find that location info.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[] || []
    };
  } catch (error) {
    console.error("Maps Error:", error);
    return { text: "Unable to access geographic data.", grounding: [] };
  }
};

// --- TTS ---

export const generateSpeech = async (text: string): Promise<ArrayBuffer> => {
  try {
    // TTS requests can be large, we retry less aggressively but still handle network glitches
    const response = await callWithRetry(() => ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' },
          },
        },
      },
    }), 2);

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data returned");

    // Convert base64 to ArrayBuffer for playback
    const binaryString = atob(base64Audio);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;

  } catch (error) {
    console.error("TTS Error:", error);
    throw error;
  }
};

