export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false
): Promise<{ text: string, grounding?: GroundingChunk[] }> => {

  const model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const systemInstructions = {
    [Persona.TUTOR]: "You are an expert AI Coding Tutor. \n\n1. Explain concepts clearly and patiently.\n2. If the user makes a mistake, guide them gently to the solution.\n3. Provide code snippets and examples to illustrate points.\n4. Be encouraging and friendly.\n5. Focus on teaching best practices and theory.",
    [Persona.INTERVIEWER]: `You are a strict Senior Technical Interviewer.

1. Conduct a professional coding interview.
2. When presenting a new coding problem, YOU MUST use the following format (LeetCode style):
   **[Problem Title]**

   **Description:**
   [Clear, concise problem statement]

   **Example 1:**
   Input: ...
   Output: ...

   **Example 2:**
   Input: ...
   Output: ...

   **Constraints:**
   - [Time/Space constraints]
   - [Input ranges]

3. Ask exactly ONE question at a time.
4. Do NOT provide the full solution. If the user gets stuck, give a minimal hint but note the penalty.
5. Evaluate efficiency (Big O) and code quality critically.
6. Keep responses concise and neutral. Do not chit-chat.`
  };

  const config: any = {
    systemInstruction: systemInstructions[persona],
  };

  if (useThinking) {
    // Gemini 3 Pro Thinking Mode
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else {
    // Standard config
    config.temperature = 0.7;
  }

  try {
    const response = await callWithRetry(() => ai.models.generateContent({
      model,
      contents: history,
      config
    }));

    return {
      text: response.text || "Error generating response.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[]
    };
  } catch (error: any) {
    console.error("GenAI Text Error:", error);
    // Return a user-friendly message based on the error
    let errorMessage = "Connection error with the Interview Engine. Please check your internet connection.";
    if (error.status === 429) {
      errorMessage = "I'm receiving too many requests right now. Please wait a moment.";
    }
    return { text: errorMessage };
  }
};

export const fastAck = async (input: string): Promise<string> => {
  try {
    // fastAck uses a lighter retry strategy (1 retry) to stay fast
    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-flash-lite-latest', // Fast model
      contents: `Provide a 3-word acknowledgement for: ${input}`,
    }), 1, 500);
    return response.text || "Acknowledged.";
  } catch (e) {
    // Silent failure for ack to avoid cluttering logs
    return "...";
  }
};

