export const getGeographicContext = async (query: string, lat?: number, lng?: number): Promise<{ text: string, grounding: GroundingChunk[] }> => {
  try {
    const ai = getClient();
    const config: any = {
      tools: [{ googleMaps: {} }],
    };

    if (lat && lng) {
      config.toolConfig = {
        retrievalConfig: {
          latLng: { latitude: lat, longitude: lng }
        }
      };
    }

    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-2.5-flash', // Required for Maps
      contents: query,
      config
    }));

    return {
      text: response.text || "I couldn't find that location info.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[] || []
    };
  } catch (error) {
    console.error("Maps Error:", error);
    return { text: "Unable to access geographic data.", grounding: [] };
  }
};

// --- TTS ---

export const generateSpeech = async (text: string): Promise<ArrayBuffer> => {
  if (!text || !text.trim()) {
     // Return silent buffer or throw simple error to be caught
     throw new Error("TTS Warning: No text to speak.");
  }

  try {
    const ai = getClient();
    // TTS requests can be large, we retry less aggressively but still handle network glitches
    const response = await callWithRetry(() => ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text.substring(0, 4000) }] }], // Cap text to prevent huge payloads
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' },
          },
        },
      },
    }), 3);

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data returned");

    // Convert base64 to ArrayBuffer for playback
    const binaryString = atob(base64Audio);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;

  } catch (error) {
    // Log simpler error to avoid cluttering console with full JSON stack if it's a known API issue
    console.error("TTS Generation Failed:", error);
    throw error;
  }
};

