const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Refs for Audio & Connection
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Reconnection Refs
  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null); // To track active session for manual close

  // Initial Welcome
  useEffect(() => {
    // Check for API Key presence (simple check)
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing in environment variables. Please add it to your Netlify/Vercel settings.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.7.2 [Stable] initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nI can conduct mock interviews or provide guided tutoring.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR) in the top right.\nUse the 'CODE' button to open the playground.");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      const audioBufferData = await generateSpeech(text);

      if (audioBufferData.byteLength === 0) {
        throw new Error("Received empty audio data");
      }

      // Use safe PCM decoder
      const audioBuffer = decodePCM(
          new Uint8Array(audioBufferData), 
          ctx, 
          24000, 
          1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e: any) {
      console.error("TTS Playback failed", e);
      let msg = "Error playing audio.";
      if (e.message && e.message.includes("500")) {
        msg = "TTS Service busy (500). Please try again.";
      } else if (e.message) {
        msg = `TTS Error: ${e.message}`;
      }
      addMessage(Sender.SYSTEM, msg);
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot process request: API Key is missing.");
        return;
    }

    const lowerText = userText.toLowerCase();

    // Command handling
    if (lowerText === '/live' || lowerText.includes('start live call')) {
      startLiveSession();
      return;
    }
    if (lowerText === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }
    if (lowerText === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(
            `USER (Audio Transcript): ${text}`,
            persona
        );
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    // If already connected, do nothing
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key. Cannot start live session.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; // Mark intentional connection
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 16000});
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        // Resume contexts if suspended (browser policy)
        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructions = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly, encouraging, and adaptive. \n\n1. If the user struggles, offer hints or explain concepts simply.\n2. If the user is advanced, challenge them.\n3. Keep responses conversational and short (under 20 seconds).",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. \n\n1. Ask one distinct interview question at a time.\n2. Be neutral and professional.\n3. Do not help the candidate unless they explicitly ask for a hint.\n4. Keep responses short (under 20 seconds).\n5. IMPORTANT: When you are ready to ask a coding question, DO NOT read the full problem description. Instead, use the `displayCodingProblem` tool to show it on screen, and simply say 'I've posted the problem to the console. Please take a look.'."
        };

        // Connect Logic
        const sessionPromise = liveClient.connect({
            // Fallback to gemini-2.0-flash-exp if 2.5 is not available for the key
            model: 'gemini-2.0-flash-exp', 
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: systemInstructions[persona],
                tools: [{ functionDeclarations: [displayCodingProblemTool] }]
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; // Reset retry counter on success
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        const blob = createPcmBlob(inputData);

                        // Use promise to ensure session is ready before sending
                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) {
                            // Silent fail for chunks to avoid spam
                          }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Tool Calls (e.g., displaying coding problems)
                    // Check for null/undefined explicitly to satisfy TS18048
                    if (msg.toolCall && msg.toolCall.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description, examples, constraints } = fc.args as any;
                                const formattedText = `**${title}**\n\n${description}\n\n**Examples:**\n${examples || ''}\n\n**Constraints:**\n${constraints || ''}`;

                                addMessage(Sender.AI, formattedText);
                                setShowCodeEditor(true); // Auto-open code editor

                                // Send success response back to model
                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "Problem displayed to user successfully." }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        // Use decodePCM here too
                        const audioBuffer = decodePCM(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed:", e);

                    const isAbnormalClose = e.code === 1006 || !e.wasClean;

                    // Reconnection Logic
                    if (shouldReconnectRef.current && isAbnormalClose) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        const delay = 1000 * retryCountRef.current; // Linear backoff: 1s, 2s, 3s
                        addMessage(Sender.SYSTEM, `Network error (Code ${e.code}). Reconnecting in ${delay/1000}s...`);

                        setTimeout(() => {
                           // Recursively try to start again
                           startLiveSession();
                        }, delay);
                        return;
                      } else {
                        addMessage(Sender.SYSTEM, "Failed to restore connection. Please check network and try again.");
                      }
                    } else {
                      addMessage(Sender.SYSTEM, "Live session ended.");
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live API Error Event:", e);
                    // Extract helpful message if available
                    let errorMsg = "Live API Error.";
                    if (e instanceof ErrorEvent) {
                      errorMsg = `Live API Error: ${e.message}`;
                    } else if (typeof e === 'object' && e !== null && 'message' in e) {
                      errorMsg = `Live API Error: ${(e as any).message}`;
                    }
                    // Don't close immediately on error, let onclose handle it, or just notify
                    addMessage(Sender.SYSTEM, errorMsg);
                }
            }
        });

    } catch (e: any) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, `Failed to start live session: ${e.message || "Unknown error"}`);
        setMode(InterviewMode.TEXT);
        shouldReconnectRef.current = false;
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;

      // Stop Gemini Session
      if (activeSessionRef.current) {
          // Attempt to close safely
          try {
            activeSessionRef.current.close();
          } catch(e) { console.log('Session already closed'); }
          activeSessionRef.current = null;
      }

      // Stop Microphone
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(track => track.stop());
          mediaStreamRef.current = null;
      }

      // Close Audio Contexts
      if (inputContextRef.current) {
          try { await inputContextRef.current.close(); } catch(e){}
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          try { await audioContextRef.current.close(); } catch(e){}
          audioContextRef.current = null;
      }

      // Clear Audio Sources
      sourcesRef.current.forEach(s => s.stop());
      sourcesRef.current.clear();

      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
      addMessage(Sender.SYSTEM, "Call ended.");
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.7</span></h1>
        </div>
        <div className="flex items-center gap-4 text-xs">
            {mode === InterviewMode.VOICE && <AudioVisualizer isActive={isLiveConnected} />}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-3 py-1 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    INTERVIEWER
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-3 py-1 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    TUTOR
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-3 py-1 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE CODE' : 'SHOW CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Content Area - Split View */}
      <div className="flex-1 flex overflow-hidden">
        {/* Chat Panel */}
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono">
                    &gt; Analyzing response...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-4 shrink-0">
                <div className="w-full flex gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={handleTextSubmit} className="flex-1">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={mode === InterviewMode.VOICE ? "Voice Active - Speak now..." : apiKeyMissing ? "API KEY MISSING - See System Message" : "Type your answer or command..."}
                            className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono disabled:cursor-not-allowed"
                            disabled={mode === InterviewMode.VOICE || isLoading || apiKeyMissing}
                            autoFocus
                        />
                    </form>

                    {/* Toolbar */}
                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            title="Upload Audio Answer"
                            className="p-2 hover:bg-[#30363d] rounded text-gray-400 hover:text-white transition-colors"
                        >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="audio/*"
                            onChange={handleFileUpload}
                        />

                        <button 
                            onClick={mode === InterviewMode.VOICE ? endLiveSession : startLiveSession}
                            className={`px-3 py-1 rounded text-xs font-bold transition-colors ${
                                mode === InterviewMode.VOICE 
                                ? 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/50' 
                                : 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/50'
                            }`}
                        >
                            {mode === InterviewMode.VOICE ? 'END CALL' : 'START LIVE CALL'}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {/* Code Editor Panel */}
        {showCodeEditor && (
            <div className="w-1/2 h-full">
                <CodeEditor />
            </div>
        )}
      </div>
    </div>
  );
};

export default App;

import { Blob } from '@google/genai';

export const decodePCM = (
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): AudioBuffer => {
  const byteLength = data.length;
  // Ensure even byte length for Int16Array
  const alignedLength = byteLength % 2 === 0 ? byteLength : byteLength - 1;

  if (alignedLength === 0) {
    return ctx.createBuffer(numChannels, 1, sampleRate);
  }

  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, alignedLength / 2);
  const buffer = ctx.createBuffer(numChannels, dataInt16.length, sampleRate);

  const channelData = buffer.getChannelData(0);
  for (let i = 0; i < dataInt16.length; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
  }

  return buffer;
};

export const base64ToBytes = (base64: string): Uint8Array => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export const bytesToBase64 = (bytes: Uint8Array): string => {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
};

export const createPcmBlob = (data: Float32Array, sampleRate: number): Blob => {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: bytesToBase64(new Uint8Array(int16.buffer)),
    mimeType: `audio/pcm;rate=${sampleRate}`,
  };
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  transcribeAudioFile, 
  getGeographicContext, 
  getLiveSession,
  generateSpeech,
  fastAck,
  displayCodingProblemTool
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';
import { createPcmBlob, decodePCM, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

// Polyfill type for Safari/Webkit
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Refs for Audio & Connection
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Reconnection Refs
  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null); // To track active session for manual close

  // Initial Welcome
  useEffect(() => {
    // Check for API Key presence (simple check)
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing in environment variables. Please add it to your Netlify/Vercel settings.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.7.2 [Stable] initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nI can conduct mock interviews or provide guided tutoring.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR) in the top right.\nUse the 'CODE' button to open the playground.");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      const audioBufferData = await generateSpeech(text);

      if (audioBufferData.byteLength === 0) {
        throw new Error("Received empty audio data");
      }

      // Use safe PCM decoder
      const audioBuffer = decodePCM(
          new Uint8Array(audioBufferData), 
          ctx, 
          24000, 
          1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e: any) {
      console.error("TTS Playback failed", e);
      let msg = "Error playing audio.";
      if (e.message && e.message.includes("500")) {
        msg = "TTS Service busy (500). Please try again.";
      } else if (e.message) {
        msg = `TTS Error: ${e.message}`;
      }
      addMessage(Sender.SYSTEM, msg);
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot process request: API Key is missing.");
        return;
    }

    const lowerText = userText.toLowerCase();

    // Command handling
    if (lowerText === '/live' || lowerText.includes('start live call')) {
      startLiveSession();
      return;
    }
    if (lowerText === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }
    if (lowerText === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(
            `USER (Audio Transcript): ${text}`,
            persona
        );
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    // If already connected, do nothing
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key. Cannot start live session.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; // Mark intentional connection
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup - Request 16k, but handle whatever the browser gives
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 16000});
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        // Resume contexts if suspended (browser policy)
        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructions = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly, encouraging, and adaptive. \n\n1. If the user struggles, offer hints or explain concepts simply.\n2. If the user is advanced, challenge them.\n3. Keep responses conversational and short (under 20 seconds).",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. \n\n1. Ask one distinct interview question at a time.\n2. Be neutral and professional.\n3. Do not help the candidate unless they explicitly ask for a hint.\n4. Keep responses short (under 20 seconds).\n5. IMPORTANT: When you are ready to ask a coding question, DO NOT read the full problem description. Instead, use the `displayCodingProblem` tool to show it on screen, and simply say 'I've posted the problem to the console. Please take a look.'."
        };

        // Connect Logic
        const sessionPromise = liveClient.connect({
            // Fallback to gemini-2.0-flash-exp if 2.5 is not available for the key
            model: 'gemini-2.0-flash-exp', 
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: systemInstructions[persona],
                tools: [{ functionDeclarations: [displayCodingProblemTool] }]
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; // Reset retry counter on success
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        // CRITICAL: Send actual sample rate to prevent 1006 disconnects
                        const currentSampleRate = inputContextRef.current?.sampleRate || 16000;
                        const blob = createPcmBlob(inputData, currentSampleRate);

                        // Use promise to ensure session is ready before sending
                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) {
                            // Silent fail for chunks to avoid spam
                          }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Tool Calls (e.g., displaying coding problems)
                    // Check for null/undefined explicitly to satisfy TS18048
                    if (msg.toolCall && msg.toolCall.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description, examples, constraints } = fc.args as any;
                                const formattedText = `**${title}**\n\n${description}\n\n**Examples:**\n${examples || ''}\n\n**Constraints:**\n${constraints || ''}`;

                                addMessage(Sender.AI, formattedText);
                                setShowCodeEditor(true); // Auto-open code editor

                                // Send success response back to model
                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "Problem displayed to user successfully." }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        // Use decodePCM here too
                        const audioBuffer = decodePCM(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed:", e);

                    const isAbnormalClose = e.code === 1006 || !e.wasClean;

                    // Reconnection Logic
                    if (shouldReconnectRef.current && isAbnormalClose) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        const delay = 1000 * retryCountRef.current; // Linear backoff: 1s, 2s, 3s
                        addMessage(Sender.SYSTEM, `Network error (Code ${e.code}). Reconnecting in ${delay/1000}s...`);

                        setTimeout(() => {
                           // Recursively try to start again
                           startLiveSession();
                        }, delay);
                        return;
                      } else {
                        addMessage(Sender.SYSTEM, "Failed to restore connection. Please check network and try again.");
                      }
                    } else {
                      addMessage(Sender.SYSTEM, "Live session ended.");
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live API Error Event:", e);
                    // Extract helpful message if available
                    let errorMsg = "Live API Error.";
                    if (e instanceof ErrorEvent) {
                      errorMsg = `Live API Error: ${e.message}`;
                    } else if (typeof e === 'object' && e !== null && 'message' in e) {
                      errorMsg = `Live API Error: ${(e as any).message}`;
                    }
                    // Don't close immediately on error, let onclose handle it, or just notify
                    addMessage(Sender.SYSTEM, errorMsg);
                }
            }
        });

    } catch (e: any) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, `Failed to start live session: ${e.message || "Unknown error"}`);
        setMode(InterviewMode.TEXT);
        shouldReconnectRef.current = false;
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;

      // Stop Gemini Session
      if (activeSessionRef.current) {
          // Attempt to close safely
          try {
            activeSessionRef.current.close();
          } catch(e) { console.log('Session already closed'); }
          activeSessionRef.current = null;
      }

      // Stop Microphone
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(track => track.stop());
          mediaStreamRef.current = null;
      }

      // Close Audio Contexts
      if (inputContextRef.current) {
          try { await inputContextRef.current.close(); } catch(e){}
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          try { await audioContextRef.current.close(); } catch(e){}
          audioContextRef.current = null;
      }

      // Clear Audio Sources
      sourcesRef.current.forEach(s => s.stop());
      sourcesRef.current.clear();

      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
      addMessage(Sender.SYSTEM, "Call ended.");
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.7</span></h1>
        </div>
        <div className="flex items-center gap-4 text-xs">
            {mode === InterviewMode.VOICE && <AudioVisualizer isActive={isLiveConnected} />}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-3 py-1 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    INTERVIEWER
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-3 py-1 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    TUTOR
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-3 py-1 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE CODE' : 'SHOW CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Content Area - Split View */}
      <div className="flex-1 flex overflow-hidden">
        {/* Chat Panel */}
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono">
                    &gt; Analyzing response...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-4 shrink-0">
                <div className="w-full flex gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={handleTextSubmit} className="flex-1">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={mode === InterviewMode.VOICE ? "Voice Active - Speak now..." : apiKeyMissing ? "API KEY MISSING - See System Message" : "Type your answer or command..."}
                            className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono disabled:cursor-not-allowed"
                            disabled={mode === InterviewMode.VOICE || isLoading || apiKeyMissing}
                            autoFocus
                        />
                    </form>

                    {/* Toolbar */}
                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            title="Upload Audio Answer"
                            className="p-2 hover:bg-[#30363d] rounded text-gray-400 hover:text-white transition-colors"
                        >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="audio/*"
                            onChange={handleFileUpload}
                        />

                        <button 
                            onClick={mode === InterviewMode.VOICE ? endLiveSession : startLiveSession}
                            className={`px-3 py-1 rounded text-xs font-bold transition-colors ${
                                mode === InterviewMode.VOICE 
                                ? 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/50' 
                                : 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/50'
                            }`}
                        >
                            {mode === InterviewMode.VOICE ? 'END CALL' : 'START LIVE CALL'}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {/* Code Editor Panel */}
        {showCodeEditor && (
            <div className="w-1/2 h-full">
                <CodeEditor />
            </div>
        )}
      </div>
    </div>
  );
};

export default App;

import { Blob } from '@google/genai';

export const decodePCM = (
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): AudioBuffer => {
  const byteLength = data.length;
  // Ensure even byte length for Int16Array
  const alignedLength = byteLength % 2 === 0 ? byteLength : byteLength - 1;

  if (alignedLength === 0) {
    return ctx.createBuffer(numChannels, 1, sampleRate);
  }

  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, alignedLength / 2);
  const buffer = ctx.createBuffer(numChannels, dataInt16.length, sampleRate);

  const channelData = buffer.getChannelData(0);
  for (let i = 0; i < dataInt16.length; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
  }

  return buffer;
};

export const base64ToBytes = (base64: string): Uint8Array => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export const bytesToBase64 = (bytes: Uint8Array): string => {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
};

// Internal helper: Downsample incoming float audio to 16kHz Int16
const downsampleTo16k = (buffer: Float32Array, inputRate: number): Int16Array => {
  if (inputRate === 16000) {
    const output = new Int16Array(buffer.length);
    for (let i = 0; i < buffer.length; i++) {
      let s = buffer[i];
      s = Math.max(-1, Math.min(1, s));
      output[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }
    return output;
  }

  const ratio = inputRate / 16000;
  const newLength = Math.round(buffer.length / ratio);
  const result = new Int16Array(newLength);

  for (let i = 0; i < newLength; i++) {
    const idx = i * ratio;
    const idxInt = Math.floor(idx);
    // Linear interpolation for smoother downsampling
    const val1 = buffer[idxInt] || 0;
    const val2 = buffer[idxInt + 1] || val1;
    const frac = idx - idxInt;

    let val = val1 * (1 - frac) + val2 * frac;
    val = Math.max(-1, Math.min(1, val));

    result[i] = val < 0 ? val * 0x8000 : val * 0x7FFF;
  }

  return result;
};

export const createPcmBlob = (data: Float32Array, inputSampleRate: number): Blob => {
  // Always downsample/convert to 16kHz 16-bit PCM for consistent API compatibility
  const pcm16 = downsampleTo16k(data, inputSampleRate);
  const base64 = bytesToBase64(new Uint8Array(pcm16.buffer));

  return {
    data: base64,
    mimeType: "audio/pcm;rate=16000",
  };
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  transcribeAudioFile, 
  getGeographicContext, 
  getLiveSession,
  generateSpeech,
  fastAck,
  displayCodingProblemTool
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';
import { createPcmBlob, decodePCM, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

// Polyfill type for Safari/Webkit
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Refs for Audio & Connection
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Reconnection Refs
  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null); // To track active session for manual close

  // Initial Welcome
  useEffect(() => {
    // Check for API Key presence (simple check)
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing in environment variables. Please add it to your Netlify/Vercel settings.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.7.3 [Stable] initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nI can conduct mock interviews or provide guided tutoring.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR) in the top right.\nUse the 'CODE' button to open the playground.");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      const audioBufferData = await generateSpeech(text);

      if (audioBufferData.byteLength === 0) {
        throw new Error("Received empty audio data");
      }

      // Use safe PCM decoder
      const audioBuffer = decodePCM(
          new Uint8Array(audioBufferData), 
          ctx, 
          24000, 
          1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e: any) {
      console.error("TTS Playback failed", e);
      let msg = "Error playing audio.";
      if (e.message && e.message.includes("500")) {
        msg = "TTS Service busy (500). Please try again.";
      } else if (e.message) {
        msg = `TTS Error: ${e.message}`;
      }
      addMessage(Sender.SYSTEM, msg);
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot process request: API Key is missing.");
        return;
    }

    const lowerText = userText.toLowerCase();

    // Command handling
    if (lowerText === '/live' || lowerText.includes('start live call')) {
      startLiveSession();
      return;
    }
    if (lowerText === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }
    if (lowerText === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(
            `USER (Audio Transcript): ${text}`,
            persona
        );
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    // If already connected, do nothing
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key. Cannot start live session.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; // Mark intentional connection
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup - Allow default sample rate for hardware compatibility
        // We will downsample to 16kHz in the processor
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)();

        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        // Resume contexts if suspended (browser policy)
        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructions = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly, encouraging, and adaptive. \n\n1. If the user struggles, offer hints or explain concepts simply.\n2. If the user is advanced, challenge them.\n3. Keep responses conversational and short (under 20 seconds).",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. \n\n1. Ask one distinct interview question at a time.\n2. Be neutral and professional.\n3. Do not help the candidate unless they explicitly ask for a hint.\n4. Keep responses short (under 20 seconds).\n5. IMPORTANT: When you are ready to ask a coding question, DO NOT read the full problem description. Instead, use the `displayCodingProblem` tool to show it on screen, and simply say 'I've posted the problem to the console. Please take a look.'."
        };

        // Connect Logic
        const sessionPromise = liveClient.connect({
            // Fallback to gemini-2.0-flash-exp if 2.5 is not available for the key
            model: 'gemini-2.0-flash-exp', 
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: systemInstructions[persona],
                tools: [{ functionDeclarations: [displayCodingProblemTool] }]
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; // Reset retry counter on success
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        // Get actual sample rate from context to perform accurate downsampling
                        const currentSampleRate = inputContextRef.current?.sampleRate || 48000;

                        // createPcmBlob now handles downsampling to 16k internally
                        const blob = createPcmBlob(inputData, currentSampleRate);

                        // Use promise to ensure session is ready before sending
                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) {
                            // Silent fail for chunks to avoid spam
                          }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Tool Calls (e.g., displaying coding problems)
                    // Check for null/undefined explicitly to satisfy TS18048
                    if (msg.toolCall && msg.toolCall.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description, examples, constraints } = fc.args as any;
                                const formattedText = `**${title}**\n\n${description}\n\n**Examples:**\n${examples || ''}\n\n**Constraints:**\n${constraints || ''}`;

                                addMessage(Sender.AI, formattedText);
                                setShowCodeEditor(true); // Auto-open code editor

                                // Send success response back to model
                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "Problem displayed to user successfully." }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        // Use decodePCM here too
                        const audioBuffer = decodePCM(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed:", e);

                    const isAbnormalClose = e.code === 1006 || !e.wasClean;

                    // Reconnection Logic
                    if (shouldReconnectRef.current && isAbnormalClose) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        const delay = 1000 * retryCountRef.current; // Linear backoff: 1s, 2s, 3s
                        addMessage(Sender.SYSTEM, `Network error (Code ${e.code}). Reconnecting in ${delay/1000}s...`);

                        setTimeout(() => {
                           // Recursively try to start again
                           startLiveSession();
                        }, delay);
                        return;
                      } else {
                        addMessage(Sender.SYSTEM, "Failed to restore connection. Please check network and try again.");
                      }
                    } else {
                      addMessage(Sender.SYSTEM, "Live session ended.");
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live API Error Event:", e);
                    // Extract helpful message if available
                    let errorMsg = "Live API Error.";
                    if (e instanceof ErrorEvent) {
                      errorMsg = `Live API Error: ${e.message}`;
                    } else if (typeof e === 'object' && e !== null && 'message' in e) {
                      errorMsg = `Live API Error: ${(e as any).message}`;
                    }
                    // Don't close immediately on error, let onclose handle it, or just notify
                    addMessage(Sender.SYSTEM, errorMsg);
                }
            }
        });

    } catch (e: any) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, `Failed to start live session: ${e.message || "Unknown error"}`);
        setMode(InterviewMode.TEXT);
        shouldReconnectRef.current = false;
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;

      // Stop Gemini Session
      if (activeSessionRef.current) {
          // Attempt to close safely
          try {
            activeSessionRef.current.close();
          } catch(e) { console.log('Session already closed'); }
          activeSessionRef.current = null;
      }

      // Stop Microphone
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(track => track.stop());
          mediaStreamRef.current = null;
      }

      // Close Audio Contexts
      if (inputContextRef.current) {
          try { await inputContextRef.current.close(); } catch(e){}
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          try { await audioContextRef.current.close(); } catch(e){}
          audioContextRef.current = null;
      }

      // Clear Audio Sources
      sourcesRef.current.forEach(s => s.stop());
      sourcesRef.current.clear();

      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
      addMessage(Sender.SYSTEM, "Call ended.");
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.7</span></h1>
        </div>
        <div className="flex items-center gap-4 text-xs">
            {mode === InterviewMode.VOICE && <AudioVisualizer isActive={isLiveConnected} />}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-3 py-1 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    INTERVIEWER
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-3 py-1 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    TUTOR
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-3 py-1 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE CODE' : 'SHOW CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Content Area - Split View */}
      <div className="flex-1 flex overflow-hidden">
        {/* Chat Panel */}
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono">
                    &gt; Analyzing response...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-4 shrink-0">
                <div className="w-full flex gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={handleTextSubmit} className="flex-1">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={mode === InterviewMode.VOICE ? "Voice Active - Speak now..." : apiKeyMissing ? "API KEY MISSING - See System Message" : "Type your answer or command..."}
                            className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono disabled:cursor-not-allowed"
                            disabled={mode === InterviewMode.VOICE || isLoading || apiKeyMissing}
                            autoFocus
                        />
                    </form>

                    {/* Toolbar */}
                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            title="Upload Audio Answer"
                            className="p-2 hover:bg-[#30363d] rounded text-gray-400 hover:text-white transition-colors"
                        >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="audio/*"
                            onChange={handleFileUpload}
                        />

                        <button 
                            onClick={mode === InterviewMode.VOICE ? endLiveSession : startLiveSession}
                            className={`px-3 py-1 rounded text-xs font-bold transition-colors ${
                                mode === InterviewMode.VOICE 
                                ? 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/50' 
                                : 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/50'
                            }`}
                        >
                            {mode === InterviewMode.VOICE ? 'END CALL' : 'START LIVE CALL'}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {/* Code Editor Panel */}
        {showCodeEditor && (
            <div className="w-1/2 h-full">
                <CodeEditor />
            </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  transcribeAudioFile, 
  getGeographicContext, 
  getLiveSession,
  generateSpeech,
  fastAck,
  displayCodingProblemTool
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';
import { createPcmBlob, decodePCM, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

// Polyfill type for Safari/Webkit
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Refs for Audio & Connection
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Reconnection Refs
  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null); // To track active session for manual close

  // Initial Welcome
  useEffect(() => {
    // Check for API Key presence (simple check)
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing in environment variables. Please add it to your Netlify/Vercel settings.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.7.4 [Stable] initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nI can conduct mock interviews or provide guided tutoring.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR) in the top right.\nUse the 'CODE' button to open the playground.");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      const audioBufferData = await generateSpeech(text);

      if (audioBufferData.byteLength === 0) {
        throw new Error("Received empty audio data");
      }

      // Use safe PCM decoder
      const audioBuffer = decodePCM(
          new Uint8Array(audioBufferData), 
          ctx, 
          24000, 
          1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e: any) {
      console.error("TTS Playback failed", e);
      let msg = "Error playing audio.";
      if (e.message && e.message.includes("500")) {
        msg = "TTS Service busy (500). Please try again.";
      } else if (e.message) {
        msg = `TTS Error: ${e.message}`;
      }
      addMessage(Sender.SYSTEM, msg);
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot process request: API Key is missing.");
        return;
    }

    const lowerText = userText.toLowerCase();

    // Command handling
    if (lowerText === '/live' || lowerText.includes('start live call')) {
      startLiveSession();
      return;
    }
    if (lowerText === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }
    if (lowerText === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(
            `USER (Audio Transcript): ${text}`,
            persona
        );
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    // If already connected, do nothing
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key. Cannot start live session.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; // Mark intentional connection
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup - Allow default sample rate for hardware compatibility
        // We will downsample to 16kHz in the processor
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)();

        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        // Resume contexts if suspended (browser policy)
        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructions = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly, encouraging, and adaptive. \n\n1. If the user struggles, offer hints or explain concepts simply.\n2. If the user is advanced, challenge them.\n3. Keep responses conversational and short (under 20 seconds).",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. \n\n1. Ask one distinct interview question at a time.\n2. Be neutral and professional.\n3. Do not help the candidate unless they explicitly ask for a hint.\n4. Keep responses short (under 20 seconds).\n5. IMPORTANT: When you are ready to ask a coding question, DO NOT read the full problem description. Instead, use the `displayCodingProblem` tool to show it on screen, and simply say 'I've posted the problem to the console. Please take a look.'."
        };

        // Connect Logic
        const sessionPromise = liveClient.connect({
            // Use the native audio model for best performance with streaming
            model: 'gemini-2.5-flash-native-audio-preview-12-2025', 
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: systemInstructions[persona],
                tools: [{ functionDeclarations: [displayCodingProblemTool] }]
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; // Reset retry counter on success
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        // Get actual sample rate from context to perform accurate downsampling
                        const currentSampleRate = inputContextRef.current?.sampleRate || 48000;

                        // createPcmBlob now handles downsampling to 16k internally
                        const blob = createPcmBlob(inputData, currentSampleRate);

                        // Use promise to ensure session is ready before sending
                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) {
                            // Silent fail for chunks to avoid spam
                          }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Tool Calls (e.g., displaying coding problems)
                    // Check for null/undefined explicitly to satisfy TS18048
                    if (msg.toolCall && msg.toolCall.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description, examples, constraints } = fc.args as any;
                                const formattedText = `**${title}**\n\n${description}\n\n**Examples:**\n${examples || ''}\n\n**Constraints:**\n${constraints || ''}`;

                                addMessage(Sender.AI, formattedText);
                                setShowCodeEditor(true); // Auto-open code editor

                                // Send success response back to model
                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "Problem displayed to user successfully." }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        // Use decodePCM here too
                        const audioBuffer = decodePCM(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed:", e);

                    const isAbnormalClose = e.code === 1006 || !e.wasClean;

                    // Reconnection Logic
                    if (shouldReconnectRef.current && isAbnormalClose) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        const delay = 1000 * retryCountRef.current; // Linear backoff: 1s, 2s, 3s
                        addMessage(Sender.SYSTEM, `Network error (Code ${e.code}). Reconnecting in ${delay/1000}s...`);

                        setTimeout(() => {
                           // Recursively try to start again
                           startLiveSession();
                        }, delay);
                        return;
                      } else {
                        addMessage(Sender.SYSTEM, "Failed to restore connection. Please check network and try again.");
                      }
                    } else {
                      // Log the code if it's not a normal clean close initiated by user
                      const reason = e.reason ? ` Reason: ${e.reason}` : '';
                      addMessage(Sender.SYSTEM, `Live session ended (Code ${e.code}${reason}).`);
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live API Error Event:", e);
                    // Extract helpful message if available
                    let errorMsg = "Live API Error.";
                    if (e instanceof ErrorEvent) {
                      errorMsg = `Live API Error: ${e.message}`;
                    } else if (typeof e === 'object' && e !== null && 'message' in e) {
                      errorMsg = `Live API Error: ${(e as any).message}`;
                    }
                    // Don't close immediately on error, let onclose handle it, or just notify
                    addMessage(Sender.SYSTEM, errorMsg);
                }
            }
        });

    } catch (e: any) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, `Failed to start live session: ${e.message || "Unknown error"}`);
        setMode(InterviewMode.TEXT);
        shouldReconnectRef.current = false;
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;

      // Stop Gemini Session
      if (activeSessionRef.current) {
          // Attempt to close safely
          try {
            activeSessionRef.current.close();
          } catch(e) { console.log('Session already closed'); }
          activeSessionRef.current = null;
      }

      // Stop Microphone
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(track => track.stop());
          mediaStreamRef.current = null;
      }

      // Close Audio Contexts
      if (inputContextRef.current) {
          try { await inputContextRef.current.close(); } catch(e){}
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          try { await audioContextRef.current.close(); } catch(e){}
          audioContextRef.current = null;
      }

      // Clear Audio Sources
      sourcesRef.current.forEach(s => s.stop());
      sourcesRef.current.clear();

      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
      addMessage(Sender.SYSTEM, "Call ended.");
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.7</span></h1>
        </div>
        <div className="flex items-center gap-4 text-xs">
            {mode === InterviewMode.VOICE && <AudioVisualizer isActive={isLiveConnected} />}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-3 py-1 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    INTERVIEWER
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-3 py-1 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    TUTOR
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-3 py-1 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE CODE' : 'SHOW CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Content Area - Split View */}
      <div className="flex-1 flex overflow-hidden">
        {/* Chat Panel */}
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono">
                    &gt; Analyzing response...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-4 shrink-0">
                <div className="w-full flex gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={handleTextSubmit} className="flex-1">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={mode === InterviewMode.VOICE ? "Voice Active - Speak now..." : apiKeyMissing ? "API KEY MISSING - See System Message" : "Type your answer or command..."}
                            className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono disabled:cursor-not-allowed"
                            disabled={mode === InterviewMode.VOICE || isLoading || apiKeyMissing}
                            autoFocus
                        />
                    </form>

                    {/* Toolbar */}
                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            title="Upload Audio Answer"
                            className="p-2 hover:bg-[#30363d] rounded text-gray-400 hover:text-white transition-colors"
                        >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="audio/*"
                            onChange={handleFileUpload}
                        />

                        <button 
                            onClick={mode === InterviewMode.VOICE ? endLiveSession : startLiveSession}
                            className={`px-3 py-1 rounded text-xs font-bold transition-colors ${
                                mode === InterviewMode.VOICE 
                                ? 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/50' 
                                : 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/50'
                            }`}
                        >
                            {mode === InterviewMode.VOICE ? 'END CALL' : 'START LIVE CALL'}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {/* Code Editor Panel */}
        {showCodeEditor && (
            <div className="w-1/2 h-full">
                <CodeEditor />
            </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  transcribeAudioFile, 
  getGeographicContext, 
  getLiveSession,
  generateSpeech,
  fastAck,
  displayCodingProblemTool
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';
import { createPcmBlob, decodePCM, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

// Polyfill type for Safari/Webkit
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Refs for Audio & Connection
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Reconnection Refs
  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null); // To track active session for manual close

  // Initial Welcome
  useEffect(() => {
    // Check for API Key presence (simple check)
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing in environment variables. Please add it to your Netlify/Vercel settings.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.7.5 [Stable] initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nI can conduct mock interviews or provide guided tutoring.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR) in the top right.\nUse the 'CODE' button to open the playground.");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      const audioBufferData = await generateSpeech(text);

      if (audioBufferData.byteLength === 0) {
        throw new Error("Received empty audio data");
      }

      // Use safe PCM decoder
      const audioBuffer = decodePCM(
          new Uint8Array(audioBufferData), 
          ctx, 
          24000, 
          1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e: any) {
      console.error("TTS Playback failed", e);
      let msg = "Error playing audio.";
      if (e.message && e.message.includes("500")) {
        msg = "TTS Service busy (500). Please try again.";
      } else if (e.message) {
        msg = `TTS Error: ${e.message}`;
      }
      addMessage(Sender.SYSTEM, msg);
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot process request: API Key is missing.");
        return;
    }

    const lowerText = userText.toLowerCase();

    // Command handling
    if (lowerText === '/live' || lowerText.includes('start live call')) {
      startLiveSession();
      return;
    }
    if (lowerText === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }
    if (lowerText === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(
            `USER (Audio Transcript): ${text}`,
            persona
        );
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    // If already connected, do nothing
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key. Cannot start live session.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; // Mark intentional connection
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup - Allow default sample rate for hardware compatibility
        // We will downsample to 16kHz in the processor
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)();

        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        // Resume contexts if suspended (browser policy)
        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructions = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly, encouraging, and adaptive. \n\n1. If the user struggles, offer hints or explain concepts simply.\n2. If the user is advanced, challenge them.\n3. Keep responses conversational and short (under 20 seconds).",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. \n\n1. Ask one distinct interview question at a time.\n2. Be neutral and professional.\n3. Do not help the candidate unless they explicitly ask for a hint.\n4. Keep responses short (under 20 seconds).\n5. Verbally describe the coding problem clearly. Do not ask the user to read it from the screen."
        };

        // Connect Logic
        const sessionPromise = liveClient.connect({
            // Use the native audio model for best performance with streaming
            model: 'gemini-2.5-flash-native-audio-preview-12-2025', 
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: { parts: [{ text: systemInstructions[persona] }] },
                // Tools (Function Calling) are NOT supported on the native-audio-preview model.
                // tools: [{ functionDeclarations: [displayCodingProblemTool] }] 
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; // Reset retry counter on success
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        // Get actual sample rate from context to perform accurate downsampling
                        const currentSampleRate = inputContextRef.current?.sampleRate || 48000;

                        // createPcmBlob now handles downsampling to 16k internally
                        const blob = createPcmBlob(inputData, currentSampleRate);

                        // Use promise to ensure session is ready before sending
                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) {
                            // Silent fail for chunks to avoid spam
                          }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Tool Calls (Inactive for now)
                    if (msg.toolCall && msg.toolCall.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description, examples, constraints } = fc.args as any;
                                const formattedText = `**${title}**\n\n${description}\n\n**Examples:**\n${examples || ''}\n\n**Constraints:**\n${constraints || ''}`;

                                addMessage(Sender.AI, formattedText);
                                setShowCodeEditor(true); 

                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "Problem displayed to user successfully." }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        // Use decodePCM here too
                        const audioBuffer = decodePCM(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed:", e);

                    const isAbnormalClose = e.code === 1006 || !e.wasClean;

                    // Reconnection Logic
                    if (shouldReconnectRef.current && isAbnormalClose) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        const delay = 1000 * retryCountRef.current; // Linear backoff: 1s, 2s, 3s
                        addMessage(Sender.SYSTEM, `Network error (Code ${e.code}). Reconnecting in ${delay/1000}s...`);

                        setTimeout(() => {
                           // Recursively try to start again
                           startLiveSession();
                        }, delay);
                        return;
                      } else {
                        addMessage(Sender.SYSTEM, "Failed to restore connection. Please check network and try again.");
                      }
                    } else {
                      // Log the code if it's not a normal clean close initiated by user
                      const reason = e.reason ? ` Reason: ${e.reason}` : '';
                      addMessage(Sender.SYSTEM, `Live session ended (Code ${e.code}${reason}).`);
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live API Error Event:", e);
                    // Extract helpful message if available
                    let errorMsg = "Live API Error.";
                    if (e instanceof ErrorEvent) {
                      errorMsg = `Live API Error: ${e.message}`;
                    } else if (typeof e === 'object' && e !== null && 'message' in e) {
                      errorMsg = `Live API Error: ${(e as any).message}`;
                    }
                    // Don't close immediately on error, let onclose handle it, or just notify
                    addMessage(Sender.SYSTEM, errorMsg);
                }
            }
        });

    } catch (e: any) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, `Failed to start live session: ${e.message || "Unknown error"}`);
        setMode(InterviewMode.TEXT);
        shouldReconnectRef.current = false;
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;

      // Stop Gemini Session
      if (activeSessionRef.current) {
          // Attempt to close safely
          try {
            activeSessionRef.current.close();
          } catch(e) { console.log('Session already closed'); }
          activeSessionRef.current = null;
      }

      // Stop Microphone
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(track => track.stop());
          mediaStreamRef.current = null;
      }

      // Close Audio Contexts
      if (inputContextRef.current) {
          try { await inputContextRef.current.close(); } catch(e){}
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          try { await audioContextRef.current.close(); } catch(e){}
          audioContextRef.current = null;
      }

      // Clear Audio Sources
      sourcesRef.current.forEach(s => s.stop());
      sourcesRef.current.clear();

      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
      addMessage(Sender.SYSTEM, "Call ended.");
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.7</span></h1>
        </div>
        <div className="flex items-center gap-4 text-xs">
            {mode === InterviewMode.VOICE && <AudioVisualizer isActive={isLiveConnected} />}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-3 py-1 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    INTERVIEWER
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-3 py-1 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    TUTOR
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-3 py-1 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE CODE' : 'SHOW CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Content Area - Split View */}
      <div className="flex-1 flex overflow-hidden">
        {/* Chat Panel */}
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono">
                    &gt; Analyzing response...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-4 shrink-0">
                <div className="w-full flex gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={handleTextSubmit} className="flex-1">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={mode === InterviewMode.VOICE ? "Voice Active - Speak now..." : apiKeyMissing ? "API KEY MISSING - See System Message" : "Type your answer or command..."}
                            className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono disabled:cursor-not-allowed"
                            disabled={mode === InterviewMode.VOICE || isLoading || apiKeyMissing}
                            autoFocus
                        />
                    </form>

                    {/* Toolbar */}
                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            title="Upload Audio Answer"
                            className="p-2 hover:bg-[#30363d] rounded text-gray-400 hover:text-white transition-colors"
                        >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="audio/*"
                            onChange={handleFileUpload}
                        />

                        <button 
                            onClick={mode === InterviewMode.VOICE ? endLiveSession : startLiveSession}
                            className={`px-3 py-1 rounded text-xs font-bold transition-colors ${
                                mode === InterviewMode.VOICE 
                                ? 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/50' 
                                : 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/50'
                            }`}
                        >
                            {mode === InterviewMode.VOICE ? 'END CALL' : 'START LIVE CALL'}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {/* Code Editor Panel */}
        {showCodeEditor && (
            <div className="w-1/2 h-full">
                <CodeEditor />
            </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  transcribeAudioFile, 
  getGeographicContext, 
  getLiveSession,
  generateSpeech,
  fastAck,
  displayCodingProblemTool
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';
import { createPcmBlob, decodePCM, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

// Polyfill type for Safari/Webkit
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Refs for Audio & Connection
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Reconnection Refs
  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null); // To track active session for manual close

  // Initial Welcome
  useEffect(() => {
    // Check for API Key presence (simple check)
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing in environment variables. Please add it to your Netlify/Vercel settings.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.7.5 [Stable] initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nI can conduct mock interviews or provide guided tutoring.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR) in the top right.\nUse the 'CODE' button to open the playground.");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      const audioBufferData = await generateSpeech(text);

      if (audioBufferData.byteLength === 0) {
        throw new Error("Received empty audio data");
      }

      // Use safe PCM decoder
      const audioBuffer = decodePCM(
          new Uint8Array(audioBufferData), 
          ctx, 
          24000, 
          1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e: any) {
      console.error("TTS Playback failed", e);
      let msg = "Error playing audio.";
      if (e.message && e.message.includes("500")) {
        msg = "TTS Service busy (500). Please try again.";
      } else if (e.message) {
        msg = `TTS Error: ${e.message}`;
      }
      addMessage(Sender.SYSTEM, msg);
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot process request: API Key is missing.");
        return;
    }

    const lowerText = userText.toLowerCase();

    // Command handling
    if (lowerText === '/live' || lowerText.includes('start live call')) {
      startLiveSession();
      return;
    }
    if (lowerText === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }
    if (lowerText === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(
            `USER (Audio Transcript): ${text}`,
            persona
        );
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    // If already connected, do nothing
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key. Cannot start live session.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; // Mark intentional connection
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup - Allow default sample rate for hardware compatibility
        // We will downsample to 16kHz in the processor
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)();

        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        // Resume contexts if suspended (browser policy)
        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructions = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly, encouraging, and adaptive. \n\n1. If the user struggles, offer hints or explain concepts simply.\n2. If the user is advanced, challenge them.\n3. Keep responses conversational and short (under 20 seconds).",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. \n\n1. Ask one distinct interview question at a time.\n2. Be neutral and professional.\n3. Do not help the candidate unless they explicitly ask for a hint.\n4. Keep responses short (under 20 seconds).\n5. Verbally describe the coding problem clearly. Do not ask the user to read it from the screen."
        };

        // Connect Logic
        const sessionPromise = liveClient.connect({
            // Use the native audio model for best performance with streaming
            model: 'gemini-2.5-flash-native-audio-preview-12-2025', 
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: { parts: [{ text: systemInstructions[persona] }] },
                // Tools (Function Calling) are NOT supported on the native-audio-preview model.
                // tools: [{ functionDeclarations: [displayCodingProblemTool] }] 
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; // Reset retry counter on success
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        // Get actual sample rate from context to perform accurate downsampling
                        const currentSampleRate = inputContextRef.current?.sampleRate || 48000;

                        // createPcmBlob now handles downsampling to 16k internally
                        const blob = createPcmBlob(inputData, currentSampleRate);

                        // Use promise to ensure session is ready before sending
                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) {
                            // Silent fail for chunks to avoid spam
                          }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Tool Calls (Inactive for now)
                    if (msg.toolCall && msg.toolCall.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description, examples, constraints } = fc.args as any;
                                const formattedText = `**${title}**\n\n${description}\n\n**Examples:**\n${examples || ''}\n\n**Constraints:**\n${constraints || ''}`;

                                addMessage(Sender.AI, formattedText);
                                setShowCodeEditor(true); 

                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "Problem displayed to user successfully." }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        // Use decodePCM here too
                        const audioBuffer = decodePCM(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed:", e);

                    const isAbnormalClose = e.code === 1006 || !e.wasClean;

                    // Reconnection Logic
                    if (shouldReconnectRef.current && isAbnormalClose) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        const delay = 1000 * retryCountRef.current; // Linear backoff: 1s, 2s, 3s
                        addMessage(Sender.SYSTEM, `Network error (Code ${e.code}). Reconnecting in ${delay/1000}s...`);

                        setTimeout(() => {
                           // Recursively try to start again
                           startLiveSession();
                        }, delay);
                        return;
                      } else {
                        addMessage(Sender.SYSTEM, "Failed to restore connection. Please check network and try again.");
                      }
                    } else {
                      // Log the code if it's not a normal clean close initiated by user
                      const reason = e.reason ? ` Reason: ${e.reason}` : '';
                      addMessage(Sender.SYSTEM, `Live session ended (Code ${e.code}${reason}).`);
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live API Error Event:", e);
                    // Extract helpful message if available
                    let errorMsg = "Live API Error.";
                    if (e instanceof ErrorEvent) {
                      errorMsg = `Live API Error: ${e.message}`;
                    } else if (typeof e === 'object' && e !== null && 'message' in e) {
                      errorMsg = `Live API Error: ${(e as any).message}`;
                    }
                    // Don't close immediately on error, let onclose handle it, or just notify
                    addMessage(Sender.SYSTEM, errorMsg);
                }
            }
        });

    } catch (e: any) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, `Failed to start live session: ${e.message || "Unknown error"}`);
        setMode(InterviewMode.TEXT);
        shouldReconnectRef.current = false;
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;

      // Stop Gemini Session
      if (activeSessionRef.current) {
          // Attempt to close safely
          try {
            activeSessionRef.current.close();
          } catch(e) { console.log('Session already closed'); }
          activeSessionRef.current = null;
      }

      // Stop Microphone
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(track => track.stop());
          mediaStreamRef.current = null;
      }

      // Close Audio Contexts
      if (inputContextRef.current) {
          try { await inputContextRef.current.close(); } catch(e){}
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          try { await audioContextRef.current.close(); } catch(e){}
          audioContextRef.current = null;
      }

      // Clear Audio Sources
      sourcesRef.current.forEach(s => s.stop());
      sourcesRef.current.clear();

      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
      addMessage(Sender.SYSTEM, "Call ended.");
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-3 md:p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-2 md:gap-3">
            <div className={`w-2 h-2 md:w-3 md:h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight hidden md:block">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.7</span></h1>
            <h1 className="font-bold text-sm tracking-tight md:hidden">DEV_AI</h1>
        </div>
        <div className="flex items-center gap-2 md:gap-4 text-xs">
            {mode === InterviewMode.VOICE && <div className="scale-75 md:scale-100 origin-right"><AudioVisualizer isActive={isLiveConnected} /></div>}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">INTERVIEWER</span>
                    <span className="md:hidden">INT</span>
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">TUTOR</span>
                    <span className="md:hidden">TUTOR</span>
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-2 py-1 md:px-3 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE' : 'CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
