// --- Text & Reasoning ---

export interface ResumeData {
  data: string; // Base64
  mimeType: string;
}

export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false,
  resume?: ResumeData
): Promise<{ text: string, grounding?: GroundingChunk[] }> => {

  // Primary Model Selection
  let model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const systemInstructions = {
    [Persona.TUTOR]: "You are an expert AI Coding Tutor. \n\n1. Explain concepts clearly and patiently.\n2. If the user makes a mistake, guide them gently to the solution.\n3. Provide code snippets and examples to illustrate points.\n4. Be encouraging and friendly.\n5. Focus on teaching best practices and theory.",
    [Persona.INTERVIEWER]: `You are a strict Senior Technical Interviewer.

1. Conduct a professional coding interview.
2. If a resume is provided, PRIORITY is to ask deep questions about the candidate's projects, experience, and skills listed in the resume. Validate their claims.
3. When presenting a new coding problem (if not asking about resume), YOU MUST use the following format (LeetCode style):
   **[Problem Title]**

   **Description:**
   [Clear, concise problem statement]

   **Example 1:**
   Input: ...
   Output: ...

   **Example 2:**
   Input: ...
   Output: ...

   **Constraints:**
   - [Time/Space constraints]
   - [Input ranges]

4. Ask exactly ONE question at a time.
5. Do NOT provide the full solution. If the user gets stuck, give a minimal hint but note the penalty.
6. Evaluate efficiency (Big O) and code quality critically.
7. Keep responses concise and neutral. Do not chit-chat.`
  };

  const config: any = {
    systemInstruction: systemInstructions[persona],
  };

  if (useThinking) {
    // Gemini 3 Pro Thinking Mode
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else {
    // Standard config
    config.temperature = 0.7;
  }

  const ai = getClient();

  // Construct Content Parts
  const parts: any[] = [{ text: history }];

  if (resume) {
    // Add resume context if available
    parts.unshift({
        text: "System Note: The following document is the candidate's resume. Use it to tailor your questions."
    });
    parts.unshift({
        inlineData: {
            data: resume.data,
            mimeType: resume.mimeType
        }
    });
  }

  try {
    const response = await callWithRetry(() => ai.models.generateContent({
      model,
      contents: { parts },
      config
    }));

    return {
      text: response.text || "Error generating response.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[]
    };
  } catch (error: any) {
    console.error(`GenAI Text Error (${model}):`, error);

    // Fallback Logic: If Gemini 3 fails (e.g. 404 Not Found), try Gemini 2.0 Flash Exp
    if (error.status === 404 || error.status === 400 || error.message?.includes('not found')) {
        console.log("Falling back to gemini-2.0-flash-exp...");
        try {
            // Remove thinking config for fallback as 2.0 flash might not support it identically or we want simplicity
            const fallbackConfig = { ...config };
            delete fallbackConfig.thinkingConfig;

            const response = await callWithRetry(() => ai.models.generateContent({
                model: 'gemini-2.0-flash-exp',
                contents: { parts }, // Pass the same parts (including resume)
                config: fallbackConfig
            }));
            return {
                text: response.text || "Error generating response (Fallback).",
                grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[]
            };
        } catch (fallbackError: any) {
             console.error("Fallback Error:", fallbackError);
             return { text: `Error: Both primary and fallback models failed. (${fallbackError.message || fallbackError.status})` };
        }
    }

    // Return detailed error for user debugging
    let errorMessage = "Connection error with the Interview Engine.";
    if (error.status) errorMessage += ` (Status: ${error.status})`;
    if (error.message) errorMessage += ` ${error.message}`;

    if (error.status === 400 && error.message?.includes('API key')) {
        errorMessage = "Error: Invalid API Key. Please check your settings.";
    }

    return { text: errorMessage };
  }
};

export const fastAck = async (input: string): Promise<string> => {
  try {
    const ai = getClient();
    // fastAck uses a lighter retry strategy (1 retry) to stay fast
    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-flash-lite-latest', // Fast model
      contents: `Provide a 3-word acknowledgement for: ${input}`,
    }), 1, 500);
    return response.text || "Acknowledged.";
  } catch (e) {
    // Silent failure for ack to avoid cluttering logs
    return "...";
  }
};

// --- Code Execution & Review ---

export const runCodeWithAI = async (language: string, code: string): Promise<string> => {
  try {
    const ai = getClient();
    const prompt = `Act as a strictly deterministic compiler and execution engine for ${language}.
Your task is to EXECUTE the provided code and return ONLY the standard output (stdout) and standard error (stderr).

Rules:
1. Output ONLY the execution result. Do not offer explanations, greetings, or markdown code blocks.
2. If the code has a syntax error, simulate the compiler error message.
3. If the code is incomplete, output "Error: Unexpected end of input".

Code to execute:
${code}
`;

    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: prompt,
      config: {
        temperature: 0.0, // Strict deterministic output
      }
    }));

    let text = response.text || "";
    // Clean up if model accidentally adds markdown
    text = text.replace(/^```[\w]*\n?/, '').replace(/\n?```$/, '');
    return text.trim() || "[No Output]";
  } catch (error) {
    console.error("AI Execution Error:", error);
    return "Error: Execution timed out or network failed. Please try again.";
  }
};

export const reviewCodeWithAI = async (language: string, code: string): Promise<string> => {
  try {
    const ai = getClient();
    const prompt = `Act as a Senior Software Engineer and Technical Interviewer.
Review the following ${language} code:

${code}

Identify potential bugs, logic errors, style issues, and optimization opportunities. 
Be concise, constructive, and actionable. Format your response as a clear list or short paragraphs.`;

    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Strong reasoning model for code review
      contents: prompt,
    }));

    let text = response.text || "";
    // Clean up if model accidentally adds markdown code blocks around the whole response
    text = text.replace(/^```[\w]*\n?/, '').replace(/\n?```$/, '');
    return text || "No feedback generated.";
  } catch (error) {
    console.error("Review Error:", error);
    return "Error: Failed to retrieve code review from AI.";
  }
};

// --- Audio Transcription ---

export const transcribeAudioFile = async (base64Audio: string, mimeType: string): Promise<string> => {
  try {
    const ai = getClient();
    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Audio, mimeType } },
          { text: "Transcribe this audio exactly as spoken." }
        ]
      }
    }));
    return response.text || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw error;
  }
};

// --- Maps Grounding ---

export const getGeographicContext = async (query: string, lat?: number, lng?: number): Promise<{ text: string, grounding: GroundingChunk[] }> => {
  try {
    const ai = getClient();
    const config: any = {
      tools: [{ googleMaps: {} }],
    };

    if (lat && lng) {
      config.toolConfig = {
        retrievalConfig: {
          latLng: { latitude: lat, longitude: lng }
        }
      };
    }

    const response = await callWithRetry(() => ai.models.generateContent({
      model: 'gemini-2.5-flash', // Required for Maps
      contents: query,
      config
    }));

    return {
      text: response.text || "I couldn't find that location info.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[] || []
    };
  } catch (error) {
    console.error("Maps Error:", error);
    return { text: "Unable to access geographic data.", grounding: [] };
  }
};

// --- TTS ---

export const generateSpeech = async (text: string): Promise<ArrayBuffer> => {
  if (!text || !text.trim()) {
     // Return silent buffer or throw simple error to be caught
     throw new Error("TTS Warning: No text to speak.");
  }

  try {
    const ai = getClient();
    // TTS requests can be large, we retry less aggressively but still handle network glitches
    const response = await callWithRetry(() => ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text.substring(0, 4000) }] }], // Cap text to prevent huge payloads
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' },
          },
        },
      },
    }), 3);

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data returned");

    // Convert base64 to ArrayBuffer for playback
    const binaryString = atob(base64Audio);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;

  } catch (error) {
    // Log simpler error to avoid cluttering console with full JSON stack if it's a known API issue
    console.error("TTS Generation Failed:", error);
    throw error;
  }
};

// --- Live API ---

export const getLiveSession = () => {
    const ai = getClient();
    return ai.live;
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  transcribeAudioFile, 
  getGeographicContext, 
  getLiveSession,
  generateSpeech,
  fastAck,
  displayCodingProblemTool,
  ResumeData
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';
import { createPcmBlob, decodePCM, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

// Polyfill type for Safari/Webkit
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Resume State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);

  // Refs for Audio & Connection
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);
  const resumeInputRef = useRef<HTMLInputElement>(null);

  // Reconnection Refs
  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null); // To track active session for manual close

  // Initial Welcome
  useEffect(() => {
    // Check for API Key presence (simple check)
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing in environment variables. Please add it to your Netlify/Vercel settings.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.7.5 [Stable] initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nI can conduct mock interviews or provide guided tutoring.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR) in the top right.\nUse the 'CODE' button to open the playground.");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      const audioBufferData = await generateSpeech(text);

      if (audioBufferData.byteLength === 0) {
        throw new Error("Received empty audio data");
      }

      // Use safe PCM decoder
      const audioBuffer = decodePCM(
          new Uint8Array(audioBufferData), 
          ctx, 
          24000, 
          1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e: any) {
      console.error("TTS Playback failed", e);
      let msg = "Error playing audio.";
      if (e.message && e.message.includes("500")) {
        msg = "TTS Service busy (500). Please try again.";
      } else if (e.message) {
        msg = `TTS Error: ${e.message}`;
      }
      addMessage(Sender.SYSTEM, msg);
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot process request: API Key is missing.");
        return;
    }

    const lowerText = userText.toLowerCase();

    // Command handling
    if (lowerText === '/live' || lowerText.includes('start live call')) {
      startLiveSession();
      return;
    }
    if (lowerText === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }
    if (lowerText === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex,
      resumeData // Pass resume if loaded
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(
            `USER (Audio Transcript): ${text}`,
            persona
        );
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Resume Upload ---
  const handleResumeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    // Validate type (Basic check)
    if (!file.type.includes('pdf') && !file.type.includes('text')) {
        addMessage(Sender.SYSTEM, "Error: Please upload a PDF or Text file.");
        return;
    }

    addMessage(Sender.SYSTEM, `Reading resume: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        setResumeData({
            data: base64Data,
            mimeType: file.type
        });

        addMessage(Sender.SYSTEM, "Resume successfully loaded into context.");
        addMessage(Sender.AI, "I have received your resume. Would you like me to ask questions based on your experience, or review a specific project?");
      } catch (err) {
        addMessage(Sender.SYSTEM, "Failed to process resume file.");
        console.error(err);
      } finally {
        setIsLoading(false);
        // Clear input so same file can be selected again if needed
        if (resumeInputRef.current) resumeInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    // If already connected, do nothing
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key. Cannot start live session.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; // Mark intentional connection
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup - Allow default sample rate for hardware compatibility
        // We will downsample to 16kHz in the processor
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)();

        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        // Resume contexts if suspended (browser policy)
        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructions = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly, encouraging, and adaptive. \n\n1. If the user struggles, offer hints or explain concepts simply.\n2. If the user is advanced, challenge them.\n3. Keep responses conversational and short (under 20 seconds).",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. \n\n1. Ask one distinct interview question at a time.\n2. Be neutral and professional.\n3. Do not help the candidate unless they explicitly ask for a hint.\n4. Keep responses short (under 20 seconds).\n5. Verbally describe the coding problem clearly. Do not ask the user to read it from the screen."
        };

        // Connect Logic
        const sessionPromise = liveClient.connect({
            // Use the native audio model for best performance with streaming
            model: 'gemini-2.5-flash-native-audio-preview-12-2025', 
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: { parts: [{ text: systemInstructions[persona] }] },
                // Tools (Function Calling) are NOT supported on the native-audio-preview model.
                // tools: [{ functionDeclarations: [displayCodingProblemTool] }] 
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; // Reset retry counter on success
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        // Get actual sample rate from context to perform accurate downsampling
                        const currentSampleRate = inputContextRef.current?.sampleRate || 48000;

                        // createPcmBlob now handles downsampling to 16k internally
                        const blob = createPcmBlob(inputData, currentSampleRate);

                        // Use promise to ensure session is ready before sending
                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) {
                            // Silent fail for chunks to avoid spam
                          }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Tool Calls (Inactive for now)
                    if (msg.toolCall && msg.toolCall.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description, examples, constraints } = fc.args as any;
                                const formattedText = `**${title}**\n\n${description}\n\n**Examples:**\n${examples || ''}\n\n**Constraints:**\n${constraints || ''}`;

                                addMessage(Sender.AI, formattedText);
                                setShowCodeEditor(true); 

                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "Problem displayed to user successfully." }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        // Use decodePCM here too
                        const audioBuffer = decodePCM(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed:", e);

                    const isAbnormalClose = e.code === 1006 || !e.wasClean;

                    // Reconnection Logic
                    if (shouldReconnectRef.current && isAbnormalClose) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        const delay = 1000 * retryCountRef.current; // Linear backoff: 1s, 2s, 3s
                        addMessage(Sender.SYSTEM, `Network error (Code ${e.code}). Reconnecting in ${delay/1000}s...`);

                        setTimeout(() => {
                           // Recursively try to start again
                           startLiveSession();
                        }, delay);
                        return;
                      } else {
                        addMessage(Sender.SYSTEM, "Failed to restore connection. Please check network and try again.");
                      }
                    } else {
                      // Log the code if it's not a normal clean close initiated by user
                      const reason = e.reason ? ` Reason: ${e.reason}` : '';
                      addMessage(Sender.SYSTEM, `Live session ended (Code ${e.code}${reason}).`);
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live API Error Event:", e);
                    // Extract helpful message if available
                    let errorMsg = "Live API Error.";
                    if (e instanceof ErrorEvent) {
                      errorMsg = `Live API Error: ${e.message}`;
                    } else if (typeof e === 'object' && e !== null && 'message' in e) {
                      errorMsg = `Live API Error: ${(e as any).message}`;
                    }
                    // Don't close immediately on error, let onclose handle it, or just notify
                    addMessage(Sender.SYSTEM, errorMsg);
                }
            }
        });

    } catch (e: any) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, `Failed to start live session: ${e.message || "Unknown error"}`);
        setMode(InterviewMode.TEXT);
        shouldReconnectRef.current = false;
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;

      // Stop Gemini Session
      if (activeSessionRef.current) {
          // Attempt to close safely
          try {
            activeSessionRef.current.close();
          } catch(e) { console.log('Session already closed'); }
          activeSessionRef.current = null;
      }

      // Stop Microphone
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(track => track.stop());
          mediaStreamRef.current = null;
      }

      // Close Audio Contexts
      if (inputContextRef.current) {
          try { await inputContextRef.current.close(); } catch(e){}
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          try { await audioContextRef.current.close(); } catch(e){}
          audioContextRef.current = null;
      }

      // Clear Audio Sources
      sourcesRef.current.forEach(s => s.stop());
      sourcesRef.current.clear();

      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
      addMessage(Sender.SYSTEM, "Call ended.");
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-3 md:p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-2 md:gap-3">
            <div className={`w-2 h-2 md:w-3 md:h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight hidden md:block">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.7</span></h1>
            <h1 className="font-bold text-sm tracking-tight md:hidden">DEV_AI</h1>
        </div>
        <div className="flex items-center gap-2 md:gap-4 text-xs">
            {mode === InterviewMode.VOICE && <div className="scale-75 md:scale-100 origin-right"><AudioVisualizer isActive={isLiveConnected} /></div>}

            {resumeData && (
                <div className="flex items-center gap-1 text-green-400 bg-green-900/20 px-2 py-1 rounded border border-green-900/50 animate-fadeIn">
                    <span>📄</span>
                    <span className="hidden md:inline">RESUME ACTIVE</span>
                </div>
            )}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">INTERVIEWER</span>
                    <span className="md:hidden">INT</span>
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">TUTOR</span>
                    <span className="md:hidden">TUTOR</span>
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-2 py-1 md:px-3 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE' : 'CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Content Area - Responsive Split/Stack View */}
      <div className="flex-1 flex overflow-hidden relative">
        {/* Chat Panel - Hidden on mobile if code editor is open */}
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'hidden md:flex md:w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-2 md:p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono text-sm">
                    &gt; Analyzing response...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-3 md:p-4 shrink-0">
                <div className="w-full flex gap-2 md:gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={handleTextSubmit} className="flex-1 min-w-0">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={mode === InterviewMode.VOICE ? "Voice Active..." : apiKeyMissing ? "API KEY MISSING" : "Type answer..."}
                            className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono text-sm md:text-base disabled:cursor-not-allowed"
                            disabled={mode === InterviewMode.VOICE || isLoading || apiKeyMissing}
                            autoFocus
                        />
                    </form>

                    {/* Toolbar */}
                    <div className="flex items-center gap-2">
                        {/* Resume Upload Button */}
                         <button 
                            onClick={() => resumeInputRef.current?.click()}
                            title="Upload Resume (PDF/Txt)"
                            className={`p-1.5 md:p-2 hover:bg-[#30363d] rounded transition-colors ${resumeData ? 'text-green-400' : 'text-gray-400 hover:text-white'}`}
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={resumeInputRef} 
                            className="hidden" 
                            accept=".pdf,.txt,.md"
                            onChange={handleResumeUpload}
                        />

                        {/* Audio Upload Button */}
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            title="Upload Audio Answer"
                            className="p-1.5 md:p-2 hover:bg-[#30363d] rounded text-gray-400 hover:text-white transition-colors"
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="audio/*"
                            onChange={handleFileUpload}
                        />

                        <button 
                            onClick={mode === InterviewMode.VOICE ? endLiveSession : startLiveSession}
                            className={`px-2 py-1 md:px-3 rounded text-[10px] md:text-xs font-bold transition-colors whitespace-nowrap ${
                                mode === InterviewMode.VOICE 
                                ? 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/50' 
                                : 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/50'
                            }`}
                        >
                            {mode === InterviewMode.VOICE ? 'END' : <><span className="hidden md:inline">START LIVE CALL</span><span className="md:hidden">LIVE</span></>}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {/* Code Editor Panel - Full width on mobile when active */}
        {showCodeEditor && (
            <div className={`h-full ${showCodeEditor ? 'w-full md:w-1/2' : 'hidden'}`}>
                <CodeEditor />
            </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  transcribeAudioFile, 
  getGeographicContext, 
  getLiveSession,
  generateSpeech,
  fastAck,
  displayCodingProblemTool,
  ResumeData
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';
import { createPcmBlob, decodePCM, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

// Polyfill type for Safari/Webkit
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Resume State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);

  // Refs for Audio & Connection
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);
  const resumeInputRef = useRef<HTMLInputElement>(null);

  // Reconnection Refs
  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null); // To track active session for manual close

  // Initial Welcome
  useEffect(() => {
    // Check for API Key presence (simple check)
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing in environment variables. Please add it to your Netlify/Vercel settings.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.7.5 [Stable] initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nI can conduct mock interviews or provide guided tutoring.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR) in the top right.\nUse the 'CODE' button to open the playground.");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      const audioBufferData = await generateSpeech(text);

      if (audioBufferData.byteLength === 0) {
        throw new Error("Received empty audio data");
      }

      // Use safe PCM decoder
      const audioBuffer = decodePCM(
          new Uint8Array(audioBufferData), 
          ctx, 
          24000, 
          1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e: any) {
      console.error("TTS Playback failed", e);
      let msg = "Error playing audio.";
      if (e.message && e.message.includes("500")) {
        msg = "TTS Service busy (500). Please try again.";
      } else if (e.message) {
        msg = `TTS Error: ${e.message}`;
      }
      addMessage(Sender.SYSTEM, msg);
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot process request: API Key is missing.");
        return;
    }

    const lowerText = userText.toLowerCase();

    // Command handling
    if (lowerText === '/live' || lowerText.includes('start live call')) {
      startLiveSession();
      return;
    }
    if (lowerText === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }
    if (lowerText === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex,
      resumeData // Pass resume if loaded
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(
            `USER (Audio Transcript): ${text}`,
            persona
        );
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Resume Upload ---
  const handleResumeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    // Validate type (Basic check)
    if (!file.type.includes('pdf') && !file.type.includes('text')) {
        addMessage(Sender.SYSTEM, "Error: Please upload a PDF or Text file.");
        return;
    }

    addMessage(Sender.SYSTEM, `Reading resume: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        setResumeData({
            data: base64Data,
            mimeType: file.type
        });

        addMessage(Sender.SYSTEM, "Resume successfully loaded into context.");
        addMessage(Sender.AI, "I have received your resume. Would you like me to ask questions based on your experience, or review a specific project?");
      } catch (err) {
        addMessage(Sender.SYSTEM, "Failed to process resume file.");
        console.error(err);
      } finally {
        setIsLoading(false);
        // Clear input so same file can be selected again if needed
        if (resumeInputRef.current) resumeInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    // If already connected, do nothing
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key. Cannot start live session.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; // Mark intentional connection
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup - Allow default sample rate for hardware compatibility
        // We will downsample to 16kHz in the processor
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)();

        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        // Resume contexts if suspended (browser policy)
        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructionsText = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly, encouraging, and adaptive. \n\n1. If the user struggles, offer hints or explain concepts simply.\n2. If the user is advanced, challenge them.\n3. Keep responses conversational and short (under 20 seconds).",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. \n\n1. Ask one distinct interview question at a time.\n2. Be neutral and professional.\n3. Do not help the candidate unless they explicitly ask for a hint.\n4. Keep responses short (under 20 seconds).\n5. Verbally describe the coding problem clearly. Do not ask the user to read it from the screen."
        };

        // Construct System Instruction with Resume Context
        const systemInstructionParts: any[] = [
            { text: systemInstructionsText[persona] }
        ];

        if (resumeData) {
            systemInstructionParts.push({ 
                text: "CONTEXT: The candidate has uploaded the following resume. PRIORITY: Base your interview questions on the projects, experience, and skills listed in this document. Ask specific details about their work history." 
            });
            systemInstructionParts.push({
                inlineData: {
                    data: resumeData.data,
                    mimeType: resumeData.mimeType
                }
            });
        }

        // Connect Logic
        const sessionPromise = liveClient.connect({
            // Use the native audio model for best performance with streaming
            model: 'gemini-2.5-flash-native-audio-preview-12-2025', 
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: { parts: systemInstructionParts },
                // Tools (Function Calling) are NOT supported on the native-audio-preview model.
                // tools: [{ functionDeclarations: [displayCodingProblemTool] }] 
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; // Reset retry counter on success
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        // Get actual sample rate from context to perform accurate downsampling
                        const currentSampleRate = inputContextRef.current?.sampleRate || 48000;

                        // createPcmBlob now handles downsampling to 16k internally
                        const blob = createPcmBlob(inputData, currentSampleRate);

                        // Use promise to ensure session is ready before sending
                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) {
                            // Silent fail for chunks to avoid spam
                          }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Tool Calls (Inactive for now)
                    if (msg.toolCall && msg.toolCall.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description, examples, constraints } = fc.args as any;
                                const formattedText = `**${title}**\n\n${description}\n\n**Examples:**\n${examples || ''}\n\n**Constraints:**\n${constraints || ''}`;

                                addMessage(Sender.AI, formattedText);
                                setShowCodeEditor(true); 

                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "Problem displayed to user successfully." }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        // Use decodePCM here too
                        const audioBuffer = decodePCM(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed:", e);

                    const isAbnormalClose = e.code === 1006 || !e.wasClean;

                    // Reconnection Logic
                    if (shouldReconnectRef.current && isAbnormalClose) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        const delay = 1000 * retryCountRef.current; // Linear backoff: 1s, 2s, 3s
                        addMessage(Sender.SYSTEM, `Network error (Code ${e.code}). Reconnecting in ${delay/1000}s...`);

                        setTimeout(() => {
                           // Recursively try to start again
                           startLiveSession();
                        }, delay);
                        return;
                      } else {
                        addMessage(Sender.SYSTEM, "Failed to restore connection. Please check network and try again.");
                      }
                    } else {
                      // Log the code if it's not a normal clean close initiated by user
                      const reason = e.reason ? ` Reason: ${e.reason}` : '';
                      addMessage(Sender.SYSTEM, `Live session ended (Code ${e.code}${reason}).`);
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live API Error Event:", e);
                    // Extract helpful message if available
                    let errorMsg = "Live API Error.";
                    if (e instanceof ErrorEvent) {
                      errorMsg = `Live API Error: ${e.message}`;
                    } else if (typeof e === 'object' && e !== null && 'message' in e) {
                      errorMsg = `Live API Error: ${(e as any).message}`;
                    }
                    // Don't close immediately on error, let onclose handle it, or just notify
                    addMessage(Sender.SYSTEM, errorMsg);
                }
            }
        });

    } catch (e: any) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, `Failed to start live session: ${e.message || "Unknown error"}`);
        setMode(InterviewMode.TEXT);
        shouldReconnectRef.current = false;
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;

      // Stop Gemini Session
      if (activeSessionRef.current) {
          // Attempt to close safely
          try {
            activeSessionRef.current.close();
          } catch(e) { console.log('Session already closed'); }
          activeSessionRef.current = null;
      }

      // Stop Microphone
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(track => track.stop());
          mediaStreamRef.current = null;
      }

      // Close Audio Contexts
      if (inputContextRef.current) {
          try { await inputContextRef.current.close(); } catch(e){}
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          try { await audioContextRef.current.close(); } catch(e){}
          audioContextRef.current = null;
      }

      // Clear Audio Sources
      sourcesRef.current.forEach(s => s.stop());
      sourcesRef.current.clear();

      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
      addMessage(Sender.SYSTEM, "Call ended.");
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-3 md:p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-2 md:gap-3">
            <div className={`w-2 h-2 md:w-3 md:h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight hidden md:block">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.7</span></h1>
            <h1 className="font-bold text-sm tracking-tight md:hidden">DEV_AI</h1>
        </div>
        <div className="flex items-center gap-2 md:gap-4 text-xs">
            {mode === InterviewMode.VOICE && <div className="scale-75 md:scale-100 origin-right"><AudioVisualizer isActive={isLiveConnected} /></div>}

            {resumeData && (
                <div className="flex items-center gap-1 text-green-400 bg-green-900/20 px-2 py-1 rounded border border-green-900/50 animate-fadeIn">
                    <span>📄</span>
                    <span className="hidden md:inline">RESUME ACTIVE</span>
                </div>
            )}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">INTERVIEWER</span>
                    <span className="md:hidden">INT</span>
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">TUTOR</span>
                    <span className="md:hidden">TUTOR</span>
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-2 py-1 md:px-3 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE' : 'CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Content Area - Responsive Split/Stack View */}
      <div className="flex-1 flex overflow-hidden relative">
        {/* Chat Panel - Hidden on mobile if code editor is open */}
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'hidden md:flex md:w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-2 md:p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono text-sm">
                    &gt; Analyzing response...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-3 md:p-4 shrink-0">
                <div className="w-full flex gap-2 md:gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={handleTextSubmit} className="flex-1 min-w-0">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={mode === InterviewMode.VOICE ? "Voice Active..." : apiKeyMissing ? "API KEY MISSING" : "Type answer..."}
                            className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono text-sm md:text-base disabled:cursor-not-allowed"
                            disabled={mode === InterviewMode.VOICE || isLoading || apiKeyMissing}
                            autoFocus
                        />
                    </form>

                    {/* Toolbar */}
                    <div className="flex items-center gap-2">
                        {/* Resume Upload Button */}
                         <button 
                            onClick={() => resumeInputRef.current?.click()}
                            title="Upload Resume (PDF/Txt)"
                            className={`p-1.5 md:p-2 hover:bg-[#30363d] rounded transition-colors ${resumeData ? 'text-green-400' : 'text-gray-400 hover:text-white'}`}
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={resumeInputRef} 
                            className="hidden" 
                            accept=".pdf,.txt,.md"
                            onChange={handleResumeUpload}
                        />

                        {/* Audio Upload Button */}
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            title="Upload Audio Answer"
                            className="p-1.5 md:p-2 hover:bg-[#30363d] rounded text-gray-400 hover:text-white transition-colors"
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="audio/*"
                            onChange={handleFileUpload}
                        />

                        <button 
                            onClick={mode === InterviewMode.VOICE ? endLiveSession : startLiveSession}
                            className={`px-2 py-1 md:px-3 rounded text-[10px] md:text-xs font-bold transition-colors whitespace-nowrap ${
                                mode === InterviewMode.VOICE 
                                ? 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/50' 
                                : 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/50'
                            }`}
                        >
                            {mode === InterviewMode.VOICE ? 'END' : <><span className="hidden md:inline">START LIVE CALL</span><span className="md:hidden">LIVE</span></>}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {/* Code Editor Panel - Full width on mobile when active */}
        {showCodeEditor && (
            <div className={`h-full ${showCodeEditor ? 'w-full md:w-1/2' : 'hidden'}`}>
                <CodeEditor />
            </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  transcribeAudioFile, 
  getGeographicContext, 
  getLiveSession,
  generateSpeech,
  fastAck,
  displayCodingProblemTool,
  ResumeData
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';
import { createPcmBlob, decodePCM, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

// Polyfill type for Safari/Webkit
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Resume State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);

  // Refs for Audio & Connection
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);
  const resumeInputRef = useRef<HTMLInputElement>(null);

  // Reconnection Refs
  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null); // To track active session for manual close

  // Initial Welcome
  useEffect(() => {
    // Check for API Key presence (simple check)
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing in environment variables. Please add it to your Netlify/Vercel settings.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.7.5 [Stable] initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nI can conduct mock interviews or provide guided tutoring.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR) in the top right.\nUse the 'CODE' button to open the playground.");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      const audioBufferData = await generateSpeech(text);

      if (audioBufferData.byteLength === 0) {
        throw new Error("Received empty audio data");
      }

      // Use safe PCM decoder
      const audioBuffer = decodePCM(
          new Uint8Array(audioBufferData), 
          ctx, 
          24000, 
          1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e: any) {
      console.error("TTS Playback failed", e);
      let msg = "Error playing audio.";
      if (e.message && e.message.includes("500")) {
        msg = "TTS Service busy (500). Please try again.";
      } else if (e.message) {
        msg = `TTS Error: ${e.message}`;
      }
      addMessage(Sender.SYSTEM, msg);
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot process request: API Key is missing.");
        return;
    }

    const lowerText = userText.toLowerCase();

    // Command handling
    if (lowerText === '/live' || lowerText.includes('start live call')) {
      startLiveSession();
      return;
    }
    if (lowerText === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }
    if (lowerText === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex,
      resumeData // Pass resume if loaded
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(
            `USER (Audio Transcript): ${text}`,
            persona
        );
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Resume Upload ---
  const handleResumeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    // Validate type (Basic check)
    if (!file.type.includes('pdf') && !file.type.includes('text')) {
        addMessage(Sender.SYSTEM, "Error: Please upload a PDF or Text file.");
        return;
    }

    addMessage(Sender.SYSTEM, `Reading resume: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        setResumeData({
            data: base64Data,
            mimeType: file.type
        });

        addMessage(Sender.SYSTEM, "Resume successfully loaded into context.");
        addMessage(Sender.AI, "I have received your resume. Would you like me to ask questions based on your experience, or review a specific project?");
      } catch (err) {
        addMessage(Sender.SYSTEM, "Failed to process resume file.");
        console.error(err);
      } finally {
        setIsLoading(false);
        // Clear input so same file can be selected again if needed
        if (resumeInputRef.current) resumeInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    // If already connected, do nothing
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key. Cannot start live session.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; // Mark intentional connection
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup - Allow default sample rate for hardware compatibility
        // We will downsample to 16kHz in the processor
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)();

        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        // Resume contexts if suspended (browser policy)
        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructionsText = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly, encouraging, and adaptive. \n\n1. If the user struggles, offer hints or explain concepts simply.\n2. If the user is advanced, challenge them.\n3. Keep responses conversational and short (under 20 seconds).",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. \n\n1. Ask one distinct interview question at a time.\n2. Be neutral and professional.\n3. Do not help the candidate unless they explicitly ask for a hint.\n4. Keep responses short (under 20 seconds).\n5. Verbally describe the coding problem clearly. Do not ask the user to read it from the screen."
        };

        // Construct System Instruction (Text Only for Live API Config)
        // Note: We cannot pass the resume parts here, we must send them in onOpen.
        const systemInstructionParts: any[] = [
            { text: systemInstructionsText[persona] }
        ];

        // Connect Logic
        const sessionPromise = liveClient.connect({
            // Use the native audio model for best performance with streaming
            model: 'gemini-2.5-flash-native-audio-preview-12-2025', 
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: { parts: systemInstructionParts },
                // Tools (Function Calling) are NOT supported on the native-audio-preview model.
                // tools: [{ functionDeclarations: [displayCodingProblemTool] }] 
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; // Reset retry counter on success
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // If Resume Data exists, send it immediately as the first interaction
                    if (resumeData) {
                        addMessage(Sender.SYSTEM, "Sending Resume Context to Live Model...");
                        sessionPromise.then(session => {
                             session.sendRealtimeInput([
                                { text: "System Context: The user has uploaded their resume. Please review the attached document and prioritize asking questions based on their projects and experience listed in it." },
                                { inlineData: { mimeType: resumeData.mimeType, data: resumeData.data } }
                             ]);
                        });
                    }

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        // Get actual sample rate from context to perform accurate downsampling
                        const currentSampleRate = inputContextRef.current?.sampleRate || 48000;

                        // createPcmBlob now handles downsampling to 16k internally
                        const blob = createPcmBlob(inputData, currentSampleRate);

                        // Use promise to ensure session is ready before sending
                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) {
                            // Silent fail for chunks to avoid spam
                          }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Tool Calls (Inactive for now)
                    if (msg.toolCall && msg.toolCall.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description, examples, constraints } = fc.args as any;
                                const formattedText = `**${title}**\n\n${description}\n\n**Examples:**\n${examples || ''}\n\n**Constraints:**\n${constraints || ''}`;

                                addMessage(Sender.AI, formattedText);
                                setShowCodeEditor(true); 

                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "Problem displayed to user successfully." }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        // Use decodePCM here too
                        const audioBuffer = decodePCM(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed:", e);

                    const isAbnormalClose = e.code === 1006 || !e.wasClean;

                    // Reconnection Logic
                    if (shouldReconnectRef.current && isAbnormalClose) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        const delay = 1000 * retryCountRef.current; // Linear backoff: 1s, 2s, 3s
                        addMessage(Sender.SYSTEM, `Network error (Code ${e.code}). Reconnecting in ${delay/1000}s...`);

                        setTimeout(() => {
                           // Recursively try to start again
                           startLiveSession();
                        }, delay);
                        return;
                      } else {
                        addMessage(Sender.SYSTEM, "Failed to restore connection. Please check network and try again.");
                      }
                    } else {
                      // Log the code if it's not a normal clean close initiated by user
                      const reason = e.reason ? ` Reason: ${e.reason}` : '';
                      addMessage(Sender.SYSTEM, `Live session ended (Code ${e.code}${reason}).`);
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live API Error Event:", e);
                    // Extract helpful message if available
                    let errorMsg = "Live API Error.";
                    if (e instanceof ErrorEvent) {
                      errorMsg = `Live API Error: ${e.message}`;
                    } else if (typeof e === 'object' && e !== null && 'message' in e) {
                      errorMsg = `Live API Error: ${(e as any).message}`;
                    }
                    // Don't close immediately on error, let onclose handle it, or just notify
                    addMessage(Sender.SYSTEM, errorMsg);
                }
            }
        });

    } catch (e: any) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, `Failed to start live session: ${e.message || "Unknown error"}`);
        setMode(InterviewMode.TEXT);
        shouldReconnectRef.current = false;
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;

      // Stop Gemini Session
      if (activeSessionRef.current) {
          // Attempt to close safely
          try {
            activeSessionRef.current.close();
          } catch(e) { console.log('Session already closed'); }
          activeSessionRef.current = null;
      }

      // Stop Microphone
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(track => track.stop());
          mediaStreamRef.current = null;
      }

      // Close Audio Contexts
      if (inputContextRef.current) {
          try { await inputContextRef.current.close(); } catch(e){}
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          try { await audioContextRef.current.close(); } catch(e){}
          audioContextRef.current = null;
      }

      // Clear Audio Sources
      sourcesRef.current.forEach(s => s.stop());
      sourcesRef.current.clear();

      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
      addMessage(Sender.SYSTEM, "Call ended.");
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-3 md:p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-2 md:gap-3">
            <div className={`w-2 h-2 md:w-3 md:h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight hidden md:block">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.7</span></h1>
            <h1 className="font-bold text-sm tracking-tight md:hidden">DEV_AI</h1>
        </div>
        <div className="flex items-center gap-2 md:gap-4 text-xs">
            {mode === InterviewMode.VOICE && <div className="scale-75 md:scale-100 origin-right"><AudioVisualizer isActive={isLiveConnected} /></div>}

            {resumeData && (
                <div className="flex items-center gap-1 text-green-400 bg-green-900/20 px-2 py-1 rounded border border-green-900/50 animate-fadeIn">
                    <span>📄</span>
                    <span className="hidden md:inline">RESUME ACTIVE</span>
                </div>
            )}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">INTERVIEWER</span>
                    <span className="md:hidden">INT</span>
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">TUTOR</span>
                    <span className="md:hidden">TUTOR</span>
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-2 py-1 md:px-3 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE' : 'CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Content Area - Responsive Split/Stack View */}
      <div className="flex-1 flex overflow-hidden relative">
        {/* Chat Panel - Hidden on mobile if code editor is open */}
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'hidden md:flex md:w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-2 md:p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono text-sm">
                    &gt; Analyzing response...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-3 md:p-4 shrink-0">
                <div className="w-full flex gap-2 md:gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={handleTextSubmit} className="flex-1 min-w-0">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={mode === InterviewMode.VOICE ? "Voice Active..." : apiKeyMissing ? "API KEY MISSING" : "Type answer..."}
                            className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono text-sm md:text-base disabled:cursor-not-allowed"
                            disabled={mode === InterviewMode.VOICE || isLoading || apiKeyMissing}
                            autoFocus
                        />
                    </form>

                    {/* Toolbar */}
                    <div className="flex items-center gap-2">
                        {/* Resume Upload Button */}
                         <button 
                            onClick={() => resumeInputRef.current?.click()}
                            title="Upload Resume (PDF/Txt)"
                            className={`p-1.5 md:p-2 hover:bg-[#30363d] rounded transition-colors ${resumeData ? 'text-green-400' : 'text-gray-400 hover:text-white'}`}
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={resumeInputRef} 
                            className="hidden" 
                            accept=".pdf,.txt,.md"
                            onChange={handleResumeUpload}
                        />

                        {/* Audio Upload Button */}
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            title="Upload Audio Answer"
                            className="p-1.5 md:p-2 hover:bg-[#30363d] rounded text-gray-400 hover:text-white transition-colors"
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="audio/*"
                            onChange={handleFileUpload}
                        />

                        <button 
                            onClick={mode === InterviewMode.VOICE ? endLiveSession : startLiveSession}
                            className={`px-2 py-1 md:px-3 rounded text-[10px] md:text-xs font-bold transition-colors whitespace-nowrap ${
                                mode === InterviewMode.VOICE 
                                ? 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/50' 
                                : 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/50'
                            }`}
                        >
                            {mode === InterviewMode.VOICE ? 'END' : <><span className="hidden md:inline">START LIVE CALL</span><span className="md:hidden">LIVE</span></>}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {/* Code Editor Panel - Full width on mobile when active */}
        {showCodeEditor && (
            <div className={`h-full ${showCodeEditor ? 'w-full md:w-1/2' : 'hidden'}`}>
                <CodeEditor />
            </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  transcribeAudioFile, 
  getGeographicContext, 
  getLiveSession,
  generateSpeech,
  fastAck,
  displayCodingProblemTool,
  ResumeData
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';
import { createPcmBlob, decodePCM, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

// Polyfill type for Safari/Webkit
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  // Resume State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);

  // Refs for Audio & Connection
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);
  const resumeInputRef = useRef<HTMLInputElement>(null);

  // Reconnection Refs
  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null); // To track active session for manual close

  // Initial Welcome
  useEffect(() => {
    // Check for API Key presence (simple check)
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing in environment variables. Please add it to your Netlify/Vercel settings.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.7.5 [Stable] initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nI can conduct mock interviews or provide guided tutoring.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR) in the top right.\nUse the 'CODE' button to open the playground.");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling ---
  const playTTS = async (text: string) => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      const audioBufferData = await generateSpeech(text);

      if (audioBufferData.byteLength === 0) {
        throw new Error("Received empty audio data");
      }

      // Use safe PCM decoder
      const audioBuffer = decodePCM(
          new Uint8Array(audioBufferData), 
          ctx, 
          24000, 
          1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e: any) {
      console.error("TTS Playback failed", e);
      let msg = "Error playing audio.";
      if (e.message && e.message.includes("500")) {
        msg = "TTS Service busy (500). Please try again.";
      } else if (e.message) {
        msg = `TTS Error: ${e.message}`;
      }
      addMessage(Sender.SYSTEM, msg);
    }
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot process request: API Key is missing.");
        return;
    }

    const lowerText = userText.toLowerCase();

    // Command handling
    if (lowerText === '/live' || lowerText.includes('start live call')) {
      startLiveSession();
      return;
    }
    if (lowerText === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        // Fallback without coords
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }
    if (lowerText === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    setIsLoading(true);

    // Fast acknowledgement for UX (Gemini Flash Lite)
    const ack = await fastAck(userText);

    // Determine complexity for Thinking Model
    const isComplex = userText.length > 50 || userText.includes("algorithm") || userText.includes("optimize");

    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Deep Reasoning (Gemini 3 Pro)...", [], true);
    }

    // Generate main response
    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex,
      resumeData // Pass resume if loaded
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);

        // Auto-reply to transcript
        const response = await generateInterviewQuestion(
            `USER (Audio Transcript): ${text}`,
            persona
        );
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Resume Upload ---
  const handleResumeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot upload: API Key is missing.");
        return;
    }

    // Validate type (Basic check)
    if (!file.type.includes('pdf') && !file.type.includes('text')) {
        addMessage(Sender.SYSTEM, "Error: Please upload a PDF or Text file.");
        return;
    }

    addMessage(Sender.SYSTEM, `Reading resume: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        setResumeData({
            data: base64Data,
            mimeType: file.type
        });

        addMessage(Sender.SYSTEM, "Resume successfully loaded into context.");
        addMessage(Sender.AI, "I have received your resume. Would you like me to ask questions based on your experience, or review a specific project?");
      } catch (err) {
        addMessage(Sender.SYSTEM, "Failed to process resume file.");
        console.error(err);
      } finally {
        setIsLoading(false);
        // Clear input so same file can be selected again if needed
        if (resumeInputRef.current) resumeInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    // If already connected, do nothing
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key. Cannot start live session.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; // Mark intentional connection
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        // Audio Context Setup - Allow default sample rate for hardware compatibility
        // We will downsample to 16kHz in the processor
        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)();

        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        // Resume contexts if suspended (browser policy)
        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructionsText = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly, encouraging, and adaptive. \n\n1. If the user struggles, offer hints or explain concepts simply.\n2. If the user is advanced, challenge them.\n3. Keep responses conversational and short (under 20 seconds).",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. \n\n1. Ask one distinct interview question at a time.\n2. Be neutral and professional.\n3. Do not help the candidate unless they explicitly ask for a hint.\n4. Keep responses short (under 20 seconds).\n5. Verbally describe the coding problem clearly. Do not ask the user to read it from the screen."
        };

        // Construct System Instruction (Text Only for Live API Config)
        const systemInstructionParts: any[] = [
            { text: systemInstructionsText[persona] }
        ];

        // Connect Logic
        const sessionPromise = liveClient.connect({
            // Use the native audio model for best performance with streaming
            model: 'gemini-2.5-flash-native-audio-preview-12-2025', 
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                },
                systemInstruction: { parts: systemInstructionParts },
                // Tools (Function Calling) are NOT supported on the native-audio-preview model.
                // tools: [{ functionDeclarations: [displayCodingProblemTool] }] 
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; // Reset retry counter on success
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    // If Resume Data exists, send it immediately as the first interaction
                    if (resumeData) {
                        addMessage(Sender.SYSTEM, "Sending Resume Context to Live Model...");
                        sessionPromise.then(session => {
                             session.sendRealtimeInput([
                                { text: "System Context: The user has uploaded their resume. Please review the attached document and prioritize asking questions based on their projects and experience listed in it." },
                                { inlineData: { mimeType: resumeData.mimeType, data: resumeData.data } }
                             ]);
                        });
                    }

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        // Get actual sample rate from context to perform accurate downsampling
                        const currentSampleRate = inputContextRef.current?.sampleRate || 48000;

                        // createPcmBlob now handles downsampling to 16k internally
                        const blob = createPcmBlob(inputData, currentSampleRate);

                        // Use promise to ensure session is ready before sending
                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) {
                            // Silent fail for chunks to avoid spam
                          }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Tool Calls (Inactive for now)
                    if (msg.toolCall && msg.toolCall.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description, examples, constraints } = fc.args as any;
                                const formattedText = `**${title}**\n\n${description}\n\n**Examples:**\n${examples || ''}\n\n**Constraints:**\n${constraints || ''}`;

                                addMessage(Sender.AI, formattedText);
                                setShowCodeEditor(true); 

                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "Problem displayed to user successfully." }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    // Handle Audio Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        // Use decodePCM here too
                        const audioBuffer = decodePCM(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    // Handle Interruption
                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed:", e);

                    const isAbnormalClose = e.code === 1006 || !e.wasClean;

                    // Reconnection Logic
                    if (shouldReconnectRef.current && isAbnormalClose) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        const delay = 1000 * retryCountRef.current; // Linear backoff: 1s, 2s, 3s
                        addMessage(Sender.SYSTEM, `Network error (Code ${e.code}). Reconnecting in ${delay/1000}s...`);

                        setTimeout(() => {
                           // Recursively try to start again
                           startLiveSession();
                        }, delay);
                        return;
                      } else {
                        addMessage(Sender.SYSTEM, "Failed to restore connection. Please check network and try again.");
                      }
                    } else {
                      // Log the code if it's not a normal clean close initiated by user
                      const reason = e.reason ? ` Reason: ${e.reason}` : '';
                      addMessage(Sender.SYSTEM, `Live session ended (Code ${e.code}${reason}).`);
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live API Error Event:", e);
                    // Extract helpful message if available
                    let errorMsg = "Live API Error.";
                    if (e instanceof ErrorEvent) {
                      errorMsg = `Live API Error: ${e.message}`;
                    } else if (typeof e === 'object' && e !== null && 'message' in e) {
                      errorMsg = `Live API Error: ${(e as any).message}`;
                    }
                    // Don't close immediately on error, let onclose handle it, or just notify
                    addMessage(Sender.SYSTEM, errorMsg);
                }
            }
        });

    } catch (e: any) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, `Failed to start live session: ${e.message || "Unknown error"}`);
        setMode(InterviewMode.TEXT);
        shouldReconnectRef.current = false;
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;

      // Stop Gemini Session
      if (activeSessionRef.current) {
          // Attempt to close safely
          try {
            activeSessionRef.current.close();
          } catch(e) { console.log('Session already closed'); }
          activeSessionRef.current = null;
      }

      // Stop Microphone
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(track => track.stop());
          mediaStreamRef.current = null;
      }

      // Close Audio Contexts
      if (inputContextRef.current) {
          try { await inputContextRef.current.close(); } catch(e){}
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          try { await audioContextRef.current.close(); } catch(e){}
          audioContextRef.current = null;
      }

      // Clear Audio Sources
      sourcesRef.current.forEach(s => s.stop());
      sourcesRef.current.clear();

      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
      addMessage(Sender.SYSTEM, "Call ended.");
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-3 md:p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-2 md:gap-3">
            <div className={`w-2 h-2 md:w-3 md:h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight hidden md:block">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.7</span></h1>
            <h1 className="font-bold text-sm tracking-tight md:hidden">DEV_AI</h1>
        </div>
        <div className="flex items-center gap-2 md:gap-4 text-xs">
            {mode === InterviewMode.VOICE && <div className="scale-75 md:scale-100 origin-right"><AudioVisualizer isActive={isLiveConnected} /></div>}

            {resumeData && (
                <div className="flex items-center gap-1 text-green-400 bg-green-900/20 px-2 py-1 rounded border border-green-900/50 animate-fadeIn">
                    <span>📄</span>
                    <span className="hidden md:inline">RESUME ACTIVE</span>
                </div>
            )}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">INTERVIEWER</span>
                    <span className="md:hidden">INT</span>
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">TUTOR</span>
                    <span className="md:hidden">TUTOR</span>
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-2 py-1 md:px-3 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE' : 'CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Content Area - Responsive Split/Stack View */}
      <div className="flex-1 flex overflow-hidden relative">
        {/* Chat Panel - Hidden on mobile if code editor is open */}
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'hidden md:flex md:w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-2 md:p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono text-sm">
                    &gt; Analyzing response...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-3 md:p-4 shrink-0">
                <div className="w-full flex gap-2 md:gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={handleTextSubmit} className="flex-1 min-w-0">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={mode === InterviewMode.VOICE ? "Voice Active..." : apiKeyMissing ? "API KEY MISSING" : "Type answer..."}
                            className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono text-sm md:text-base disabled:cursor-not-allowed"
                            disabled={mode === InterviewMode.VOICE || isLoading || apiKeyMissing}
                            autoFocus
                        />
                    </form>

                    {/* Toolbar */}
                    <div className="flex items-center gap-2">
                        {/* Resume Upload Button */}
                         <button 
                            onClick={() => resumeInputRef.current?.click()}
                            title="Upload Resume (PDF/Txt)"
