// --- Text & Reasoning ---

export interface ResumeData {
  data: string; // Base64
  mimeType: string;
}

export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false,
  resume?: ResumeData
): Promise<{ text: string, grounding?: GroundingChunk[] }> => {

  // Primary Model Selection
  let model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const systemInstructions = {
    [Persona.TUTOR]: "You are an expert AI Coding Tutor. \n\n1. Explain concepts clearly and patiently.\n2. If the user makes a mistake, guide them gently to the solution.\n3. Provide code snippets and examples to illustrate points.\n4. Be encouraging and friendly.\n5. Focus on teaching best practices and theory.",
    [Persona.INTERVIEWER]: `You are a strict Senior Technical Interviewer.

1. Conduct a professional coding interview.
2. If a resume is provided, PRIORITY is to ask deep questions about the candidate's projects, experience, and skills listed in the resume. Validate their claims.
3. When presenting a new coding problem (if not asking about resume), YOU MUST use the following format (LeetCode style):
   **[Problem Title]**

   **Description:**
   [Clear, concise problem statement]

   **Example 1:**
   Input: ...
   Output: ...

   **Example 2:**
   Input: ...
   Output: ...

   **Constraints:**
   - [Time/Space constraints]
   - [Input ranges]

4. Ask exactly ONE question at a time.
5. Do NOT provide the full solution. If the user gets stuck, give a minimal hint but note the penalty.
6. Evaluate efficiency (Big O) and code quality critically.
7. Keep responses concise and neutral. Do not chit-chat.`
  };

  const config: any = {
    systemInstruction: systemInstructions[persona],
  };

  if (useThinking) {
    // Gemini 3 Pro Thinking Mode
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else {
    // Standard config
    config.temperature = 0.7;
  }

  const ai = getClient();

  // Construct Content Parts
  const parts: any[] = [{ text: history }];

  if (resume) {
    // Add resume context if available
    parts.unshift({
        text: "System Note: The following document is the candidate's resume. Use it to tailor your questions."
    });
    parts.unshift({
        inlineData: {
            data: resume.data,
            mimeType: resume.mimeType
        }
    });
  }

  try {
    const response = await callWithRetry(() => ai.models.generateContent({
      model,
      contents: { parts },
      config
    }));

    return {
      text: response.text || "Error generating response.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[]
    };
  } catch (error: any) {
    console.error(`GenAI Text Error (${model}):`, error);

    // Fallback Logic: If Gemini 3 fails (e.g. 404 Not Found, 403 Permission Denied, 400 Bad Request), try Gemini 2.0 Flash Exp
    if (
        error.status === 404 || 
        error.status === 400 || 
        error.status === 403 || 
        error.message?.includes('not found') || 
        error.message?.includes('permission')
    ) {
        console.log("Falling back to gemini-2.0-flash-exp...");
        try {
            // Remove thinking config for fallback as 2.0 flash might not support it identically or we want simplicity
            const fallbackConfig = { ...config };
            delete fallbackConfig.thinkingConfig;

            const response = await callWithRetry(() => ai.models.generateContent({
                model: 'gemini-2.0-flash-exp',
                contents: { parts }, // Pass the same parts (including resume)
                config: fallbackConfig
            }));
            return {
                text: response.text || "Error generating response (Fallback).",
                grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[]
            };
        } catch (fallbackError: any) {
             console.error("Fallback Error:", fallbackError);
             return { text: `Error: Both primary and fallback models failed. (${fallbackError.message || fallbackError.status})` };
        }
    }

    // Return detailed error for user debugging
    let errorMessage = "Connection error with the Interview Engine.";
    if (error.status) errorMessage += ` (Status: ${error.status})`;
    if (error.message) errorMessage += ` ${error.message}`;

    if (error.status === 400 && error.message?.includes('API key')) {
        errorMessage = "Error: Invalid API Key. Please check your settings.";
    }

    return { text: errorMessage };
  }
};

