               setIsLiveConnected(false); // Visually indicate stopped listening until user interacts or we restart
            }
        };

        recognitionRef.current = recognition;
        recognition.start();
    }
  };

  // Microphone Button (in Voice Mode) to listen again
  const startListening = () => {
     if (recognitionRef.current && mode === InterviewMode.VOICE) {
         try { recognitionRef.current.start(); setIsLiveConnected(true); } catch(e){}
     }
