// We initialize lazily or ensure we use the global process.env.API_KEY
// Note: process.env.API_KEY is replaced by Vite at build time.
const getClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- Helper: Retry Logic ---
const callWithRetry = async <T>(fn: () => Promise<T>, retries = 3, baseDelay = 1000): Promise<T> => {
  let attempt = 0;
  while (true) {
    try {
      return await fn();
    } catch (e: any) {
      attempt++;
      if (attempt >= retries) throw e;

      // Retry on network errors, 503 (Service Unavailable), 429 (Too Many Requests), or 500 (Internal Error)
      const isNetworkError = e.message?.includes('Network') || e.message?.includes('fetch') || e.cause?.name === 'ConnectTimeoutError';
      const isServerError = e.status === 503 || e.status === 429 || e.status === 500;

      if (isNetworkError || isServerError) {
        const delay = baseDelay * Math.pow(2, attempt - 1);
        console.warn(`Attempt ${attempt} failed (Status ${e.status || 'Network'}). Retrying in ${delay}ms...`);
        await new Promise(resolve => setTimeout(resolve, delay));
        continue;
      }

      throw e;
    }
  }
};

