  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);
  const resumeInputRef = useRef<HTMLInputElement>(null);

  // Reconnection Refs
  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null); // To track active session for manual close

  // Initial Welcome
  useEffect(() => {
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing. Please add it to your environment variables.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.8 (Gemini 2.0 Flash) initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nI can conduct mock interviews or provide guided tutoring.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR) in the top right.\nUse the 'CODE' button to open the playground.");
    }
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  // --- TTS Handling (Browser Fallback since genContent TTS is not used in this mode) ---
  const playTTS = async (text: string) => {
      // Fallback to browser TTS for text mode
      const utterance = new SpeechSynthesisUtterance(text);
      window.speechSynthesis.speak(utterance);
  };

  // --- Text Interview Logic ---
  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Cannot process request: API Key is missing.");
        return;
    }

    const lowerText = userText.toLowerCase();

    // Command handling
    if (lowerText === '/live' || lowerText.includes('start live call')) {
      startLiveSession();
      return;
    }
    if (lowerText === '/maps') {
      setIsLoading(true);
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const res = await getGeographicContext("Where are tech hubs nearby?", pos.coords.latitude, pos.coords.longitude);
        addMessage(Sender.AI, res.text, res.grounding);
        setIsLoading(false);
      }, () => {
        getGeographicContext("Where is Silicon Valley?").then(res => {
            addMessage(Sender.AI, res.text, res.grounding);
            setIsLoading(false);
        });
      });
      return;
    }
    if (lowerText === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    setIsLoading(true);

    const isComplex = userText.length > 50 || userText.includes("algorithm");
    if (isComplex) {
       addMessage(Sender.SYSTEM, "Complex query detected. Engaging Reasoning Model...", [], true);
    }

    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex,
      resumeData 
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  // --- Audio Transcription (File Upload) ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);
        const response = await generateInterviewQuestion(`USER (Audio Transcript): ${text}`, persona);
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Resume Upload ---
  const handleResumeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validate type
    if (!file.type.includes('pdf') && !file.type.includes('text')) {
        addMessage(Sender.SYSTEM, "Error: Please upload a PDF or Text file.");
        return;
    }

    addMessage(Sender.SYSTEM, `Reading resume: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        setResumeData({
            data: base64Data,
            mimeType: file.type
        });

        addMessage(Sender.SYSTEM, "Resume successfully loaded into context.");
        addMessage(Sender.AI, "I have received your resume. Would you like me to ask questions based on your experience?");
      } catch (err) {
        addMessage(Sender.SYSTEM, "Failed to process resume file.");
      } finally {
        setIsLoading(false);
        if (resumeInputRef.current) resumeInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(file);
  };

  // --- Live API Session ---
  const startLiveSession = async () => {
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key. Cannot start live session.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; 
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructionsText = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly, encouraging, and adaptive. \n\n1. If the user struggles, offer hints or explain concepts simply.\n2. If the user is advanced, challenge them.\n3. Keep responses conversational and short (under 20 seconds).",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. \n\n1. Ask one distinct interview question at a time.\n2. Be neutral and professional.\n3. Do not help the candidate unless they explicitly ask for a hint.\n4. Keep responses short (under 20 seconds).\n5. Verbally describe the coding problem clearly. Do not ask the user to read it from the screen."
        };

        const systemInstructionParts: any[] = [
            { text: systemInstructionsText[persona] }
        ];

        // Connect Logic
        const sessionPromise = liveClient.connect({
            model: 'gemini-2.0-flash-exp', // Use 2.0 Flash for reliable Live API support
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
                },
                systemInstruction: { parts: systemInstructionParts },
                tools: [{ functionDeclarations: [displayCodingProblemTool] }] 
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; 
                    addMessage(Sender.SYSTEM, "Live Voice Connection Established. Speak now.");

                    if (resumeData) {
                        addMessage(Sender.SYSTEM, "Sending Resume Context to Live Model...");
                        sessionPromise.then(session => {
                             session.sendRealtimeInput([
                                { text: "System Context: The user has uploaded their resume. Please review the attached document and prioritize asking questions based on their projects and experience listed in it." },
                                { inlineData: { mimeType: resumeData.mimeType, data: resumeData.data } }
                             ]);
                        });
                    }

                    // Input Stream Processing
                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        const currentSampleRate = inputContextRef.current?.sampleRate || 48000;
                        const blob = createPcmBlob(inputData, currentSampleRate);

                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) {
                            // Silent fail
                          }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    if (msg.toolCall && msg.toolCall.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description, examples, constraints } = fc.args as any;
                                const formattedText = `**${title}**\n\n${description}\n\n**Examples:**\n${examples || ''}\n\n**Constraints:**\n${constraints || ''}`;

                                addMessage(Sender.AI, formattedText);
                                setShowCodeEditor(true); 

                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "Problem displayed to user successfully." }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                        const audioBuffer = decodePCM(
                            base64ToBytes(base64Audio), 
                            ctx, 
                            24000, 
                            1
                        );

                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);

                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                        addMessage(Sender.SYSTEM, "Interrupted.");
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed:", e);
                    const isAbnormalClose = e.code === 1006 || !e.wasClean;

                    if (shouldReconnectRef.current && isAbnormalClose) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        const delay = 1000 * retryCountRef.current;
                        addMessage(Sender.SYSTEM, `Network error (Code ${e.code}). Reconnecting in ${delay/1000}s...`);
                        setTimeout(() => {
                           startLiveSession();
                        }, delay);
                        return;
                      } else {
                        addMessage(Sender.SYSTEM, "Failed to restore connection. Please check network and try again.");
                      }
                    } else {
                      addMessage(Sender.SYSTEM, `Live session ended.`);
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live API Error:", e);
                    let errorMsg = "Live API Error.";
                    if (e instanceof ErrorEvent) {
                      errorMsg = `Live API Error: ${e.message}`;
                    } else if (typeof e === 'object' && e !== null && 'message' in e) {
                      errorMsg = `Live API Error: ${(e as any).message}`;
                    }
                    addMessage(Sender.SYSTEM, errorMsg);
                }
            }
        });

    } catch (e: any) {
        console.error("Live Connect Failed", e);
        addMessage(Sender.SYSTEM, `Failed to start live session: ${e.message || "Unknown error"}`);
        setMode(InterviewMode.TEXT);
        shouldReconnectRef.current = false;
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;

      if (activeSessionRef.current) {
          try { activeSessionRef.current.close(); } catch(e) {}
          activeSessionRef.current = null;
      }
      if (mediaStreamRef.current) {
          mediaStreamRef.current.getTracks().forEach(track => track.stop());
          mediaStreamRef.current = null;
      }
      if (inputContextRef.current) {
          try { await inputContextRef.current.close(); } catch(e){}
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          try { await audioContextRef.current.close(); } catch(e){}
          audioContextRef.current = null;
      }

      sourcesRef.current.forEach(s => s.stop());
      sourcesRef.current.clear();

      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
      addMessage(Sender.SYSTEM, "Call ended.");
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-3 md:p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-2 md:gap-3">
            <div className={`w-2 h-2 md:w-3 md:h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight hidden md:block">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.8</span></h1>
            <h1 className="font-bold text-sm tracking-tight md:hidden">DEV_AI</h1>
        </div>
        <div className="flex items-center gap-2 md:gap-4 text-xs">
            {mode === InterviewMode.VOICE && <div className="scale-75 md:scale-100 origin-right"><AudioVisualizer isActive={isLiveConnected} /></div>}

            {resumeData && (
                <div className="flex items-center gap-1 text-green-400 bg-green-900/20 px-2 py-1 rounded border border-green-900/50 animate-fadeIn">
                    <span>📄</span>
                    <span className="hidden md:inline">RESUME ACTIVE</span>
                </div>
            )}

            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">INT</span>
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">TUTOR</span>
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-2 py-1 md:px-3 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE' : 'CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
                MODE: {mode}
            </span>
        </div>
      </header>

      {/* Main Content Area */}
      <div className="flex-1 flex overflow-hidden relative">
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'hidden md:flex md:w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-2 md:p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono text-sm">
                    &gt; Analyzing response...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-3 md:p-4 shrink-0">
                <div className="w-full flex gap-2 md:gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={handleTextSubmit} className="flex-1 min-w-0">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={mode === InterviewMode.VOICE ? "Voice Active..." : apiKeyMissing ? "API KEY MISSING" : "Type answer..."}
                            className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono text-sm md:text-base disabled:cursor-not-allowed"
                            disabled={mode === InterviewMode.VOICE || isLoading || apiKeyMissing}
                            autoFocus
                        />
                    </form>

                    <div className="flex items-center gap-2">
                         <button 
                            onClick={() => resumeInputRef.current?.click()}
                            title="Upload Resume (PDF/Txt)"
                            className={`p-1.5 md:p-2 hover:bg-[#30363d] rounded transition-colors ${resumeData ? 'text-green-400' : 'text-gray-400 hover:text-white'}`}
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={resumeInputRef} 
                            className="hidden" 
                            accept=".pdf,.txt,.md"
                            onChange={handleResumeUpload}
                        />

                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            title="Upload Audio Answer"
                            className="p-1.5 md:p-2 hover:bg-[#30363d] rounded text-gray-400 hover:text-white transition-colors"
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="audio/*"
                            onChange={handleFileUpload}
                        />

                        <button 
                            onClick={mode === InterviewMode.VOICE ? endLiveSession : startLiveSession}
                            className={`px-2 py-1 md:px-3 rounded text-[10px] md:text-xs font-bold transition-colors whitespace-nowrap ${
                                mode === InterviewMode.VOICE 
                                ? 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/50' 
                                : 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/50'
                            }`}
                        >
                            {mode === InterviewMode.VOICE ? 'END' : <><span className="hidden md:inline">START LIVE CALL</span><span className="md:hidden">LIVE</span></>}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {showCodeEditor && (
            <div className={`h-full ${showCodeEditor ? 'w-full md:w-1/2' : 'hidden'}`}>
                <CodeEditor />
            </div>
        )}
      </div>
    </div>
  );
};

