import { GoogleGenAI, Type, Modality, FunctionDeclaration, GenerateContentResponse } from "@google/genai";
import { GroundingChunk, Persona } from "../types";

// Initialize the client
const getClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- Helper: Retry Logic ---
const callWithRetry = async <T>(fn: () => Promise<T>, retries = 3, baseDelay = 1000): Promise<T> => {
  let attempt = 0;
  while (true) {
    try {
      return await fn();
    } catch (e: any) {
      attempt++;
      if (attempt >= retries) throw e;

      // Retry on network errors or specific 5xx/429
      const isNetworkError = e.message?.includes('Network') || e.message?.includes('fetch') || e.cause?.name === 'ConnectTimeoutError';
      const isServerError = e.status === 503 || e.status === 429 || e.status === 500;

      if (isNetworkError || isServerError) {
        const delay = baseDelay * Math.pow(2, attempt - 1);
        console.warn(`Attempt ${attempt} failed. Retrying in ${delay}ms...`);
        await new Promise(resolve => setTimeout(resolve, delay));
        continue;
      }

      throw e;
    }
  }
};

// --- Tools ---

export const displayCodingProblemTool: FunctionDeclaration = {
  name: "displayCodingProblem",
  description: "Display a structured coding problem to the user's screen. Use this EXACTLY ONCE when you present a new coding challenge.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING, description: "The title of the problem (e.g. 'Two Sum')" },
      description: { type: Type.STRING, description: "The full problem description." },
      examples: { type: Type.STRING, description: "Examples of input/output keys." },
      constraints: { type: Type.STRING, description: "Time and space complexity constraints." }
    },
    required: ["title", "description"]
  }
};

// --- Text & Reasoning ---

export interface ResumeData {
  data: string; // Base64
  mimeType: string;
}

export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false,
  resume?: ResumeData
): Promise<{ text: string, grounding?: GroundingChunk[] }> => {

  // Use 2.0 Flash for speed and reasoning capabilities
  const model = 'gemini-2.0-flash-exp';

  const systemInstructions = {
    [Persona.TUTOR]: "You are an expert AI Coding Tutor. Explain concepts clearly, be patient, and provide examples.",
    [Persona.INTERVIEWER]: `You are a strict Senior Technical Interviewer.
1. Ask one distinct question at a time.
2. If a resume is provided, prioritize questions about it.
3. For coding problems, use the displayCodingProblem tool or format clearly with Title, Description, Examples, and Constraints.
4. Do not provide full solutions.
5. Be concise.`
  };

  const config: any = {
    systemInstruction: systemInstructions[persona],
    temperature: 0.7,
  };

  // Note: Thinking config is available on specific models like gemini-2.0-flash-thinking-exp, 
  // but for stability we stick to flash-exp unless explicitly requested for a thinking model.
  if (useThinking) {
      // If thinking is requested, we might try to prompt for chain-of-thought or use a thinking model if available
      // For now, we stick to the stable flash-exp but increase token limit
      config.maxOutputTokens = 2048;
  }

  const ai = getClient();

  const parts: any[] = [{ text: history }];

  if (resume) {
    parts.unshift({
        text: "System Note: The following document is the candidate's resume."
    });
    parts.unshift({
        inlineData: {
            data: resume.data,
            mimeType: resume.mimeType
        }
    });
  }

  try {
    const response = await callWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
      model,
      contents: { parts },
      config
    }));

    return {
      text: response.text || "Error generating response.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[]
    };
  } catch (error: any) {
    console.error(`GenAI Error:`, error);
    return { text: `Connection error: ${error.message || "Unknown error"}` };
  }
};

export const fastAck = async (input: string): Promise<string> => {
  try {
    const ai = getClient();
    const response = await callWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
      model: 'gemini-2.0-flash-exp',
      contents: `Provide a 3-word acknowledgement for: ${input}`,
    }), 1, 500);
    return response.text || "Acknowledged.";
  } catch (e) {
    return "...";
  }
};

// --- Code Execution & Review ---

export const runCodeWithAI = async (language: string, code: string): Promise<string> => {
  try {
    const ai = getClient();
    const prompt = `Act as a strictly deterministic compiler/interpreter for ${language}.
EXECUTE the provided code and return ONLY the stdout/stderr.
Code:
${code}`;

    const response = await callWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
      model: 'gemini-2.0-flash-exp', 
      contents: prompt,
      config: { temperature: 0.0 }
    }));

    let text = response.text || "";
    text = text.replace(/^```[\w]*\n?/, '').replace(/\n?```$/, '');
    return text.trim() || "[No Output]";
  } catch (error) {
    return "Error executing code.";
  }
};

export const reviewCodeWithAI = async (language: string, code: string): Promise<string> => {
  try {
    const ai = getClient();
    const prompt = `Review this ${language} code for bugs and improvements:\n${code}`;

    const response = await callWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
      model: 'gemini-2.0-flash-exp',
      contents: prompt,
    }));

    return response.text || "No feedback.";
  } catch (error) {
    return "Error reviewing code.";
  }
};

// --- Audio Transcription ---

export const transcribeAudioFile = async (base64Audio: string, mimeType: string): Promise<string> => {
  try {
    const ai = getClient();
    const response = await callWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
      model: 'gemini-2.0-flash-exp',
      contents: {
        parts: [
          { inlineData: { data: base64Audio, mimeType } },
          { text: "Transcribe this audio exactly as spoken." }
        ]
      }
    }));
    return response.text || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw error;
  }
};

// --- Maps Grounding ---

export const getGeographicContext = async (query: string, lat?: number, lng?: number): Promise<{ text: string, grounding: GroundingChunk[] }> => {
  try {
    const ai = getClient();
    const config: any = {
      tools: [{ googleMaps: {} }],
    };

    if (lat && lng) {
      config.toolConfig = {
        retrievalConfig: {
          latLng: { latitude: lat, longitude: lng }
        }
      };
    }

    const response = await callWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
      model: 'gemini-2.0-flash-exp',
      contents: query,
      config
    }));

    return {
      text: response.text || "No location info found.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[] || []
    };
  } catch (error) {
    return { text: "Maps access failed.", grounding: [] };
  }
};

