  ResumeData
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';
import { createPcmBlob, decodePCM, base64ToBytes } from './utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

// Polyfill type for Safari/Webkit
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [apiKeyMissing, setApiKeyMissing] = useState(false);

  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);
  const resumeInputRef = useRef<HTMLInputElement>(null);

  const shouldReconnectRef = useRef(false);
  const retryCountRef = useRef(0);
  const activeSessionRef = useRef<any>(null);

  useEffect(() => {
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setApiKeyMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing in environment variables.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console v2.9 (Gemini 2.0) initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer.\n\nSelect your preferred mode (INTERVIEWER vs TUTOR).");
    }
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking
    }]);
  };

  const playTTS = (text: string) => {
      const utterance = new SpeechSynthesisUtterance(text);
      window.speechSynthesis.speak(utterance);
  };

  const handleTextSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;
    setInputValue('');
    addMessage(Sender.USER, userText);

    if (apiKeyMissing) return;

    if (userText.toLowerCase() === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }
    if (userText.toLowerCase() === '/live') {
        startLiveSession();
        return;
    }

    setIsLoading(true);

    const isComplex = userText.length > 50 || userText.includes("algorithm");
    if (isComplex) {
       addMessage(Sender.SYSTEM, "Analyzing request...", [], true);
    }

    const response = await generateInterviewQuestion(
      messages.map(m => `${m.sender}: ${m.text}`).join('\n') + `\nUSER: ${userText}`,
      persona,
      isComplex,
      resumeData 
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text, response.grounding);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    addMessage(Sender.SYSTEM, `Uploading audio: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Audio = (reader.result as string).split(',')[1];
        const text = await transcribeAudioFile(base64Audio, file.type);
        addMessage(Sender.USER, `[Audio Transcript]: ${text}`);
        const response = await generateInterviewQuestion(`USER (Audio Transcript): ${text}`, persona);
        addMessage(Sender.AI, response.text);
      } catch (err) {
        addMessage(Sender.SYSTEM, "Transcription failed.");
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleResumeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.includes('pdf') && !file.type.includes('text')) {
        addMessage(Sender.SYSTEM, "Error: Please upload a PDF or Text file.");
        return;
    }

    addMessage(Sender.SYSTEM, `Reading resume: ${file.name}...`);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        setResumeData({
            data: base64Data,
            mimeType: file.type
        });
        addMessage(Sender.SYSTEM, "Resume loaded. Context updated.");
      } catch (err) {
        addMessage(Sender.SYSTEM, "Failed to process resume file.");
      } finally {
        setIsLoading(false);
        if (resumeInputRef.current) resumeInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(file);
  };

  const startLiveSession = async () => {
    if (isLiveConnected) return;

    if (!process.env.API_KEY || apiKeyMissing) {
        addMessage(Sender.SYSTEM, "Error: Missing API Key.");
        return;
    }

    setMode(InterviewMode.VOICE);
    shouldReconnectRef.current = true; 
    addMessage(Sender.SYSTEM, `Connecting to Gemini Live API (${persona} Mode)...`);

    try {
        const liveClient = getLiveSession();

        inputContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
        }

        if (inputContextRef.current.state === 'suspended') await inputContextRef.current.resume();
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const systemInstructionsText = {
            [Persona.TUTOR]: "You are an expert AI Coding Tutor using voice. Be friendly. Keep responses under 20s.",
            [Persona.INTERVIEWER]: "You are a strict Technical Interviewer using voice. Ask one question at a time. Keep responses under 20s."
        };

        const sessionPromise = liveClient.connect({
            model: 'gemini-2.0-flash-exp',
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
                },
                systemInstruction: { parts: [{ text: systemInstructionsText[persona] }] },
                tools: [{ functionDeclarations: [displayCodingProblemTool] }] 
            },
            callbacks: {
                onopen: () => {
                    setIsLiveConnected(true);
                    retryCountRef.current = 0; 
                    addMessage(Sender.SYSTEM, "Live Connection Established.");

                    if (resumeData) {
                        sessionPromise.then(session => {
                             session.sendRealtimeInput([
                                { text: "System Context: User's resume attached." },
                                { inlineData: { mimeType: resumeData.mimeType, data: resumeData.data } }
                             ]);
                        });
                    }

                    const source = inputContextRef.current!.createMediaStreamSource(stream);
                    const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                        const inputData = e.inputBuffer.getChannelData(0);
                        const currentSampleRate = inputContextRef.current?.sampleRate || 48000;
                        const blob = createPcmBlob(inputData, currentSampleRate);

                        sessionPromise.then(session => {
                          activeSessionRef.current = session;
                          try {
                            session.sendRealtimeInput({ media: blob });
                          } catch (sendError) { }
                        });
                    };

                    source.connect(processor);
                    processor.connect(inputContextRef.current!.destination);
                },
                onmessage: async (msg: LiveServerMessage) => {
                    if (msg.toolCall?.functionCalls) {
                        for (const fc of msg.toolCall.functionCalls) {
                            if (fc.name === 'displayCodingProblem') {
                                const { title, description } = fc.args as any;
                                addMessage(Sender.AI, `**${title}**\n\n${description}`);
                                setShowCodeEditor(true); 
                                sessionPromise.then(session => {
                                    session.sendToolResponse({
                                        functionResponses: [{
                                            id: fc.id,
                                            name: fc.name,
                                            response: { result: "OK" }
                                        }]
                                    });
                                });
                            }
                        }
                    }

                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const ctx = audioContextRef.current;
                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
                        const audioBuffer = decodePCM(base64ToBytes(base64Audio), ctx, 24000, 1);
                        const source = ctx.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(ctx.destination);
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += audioBuffer.duration;
                        sourcesRef.current.add(source);
                        source.onended = () => sourcesRef.current.delete(source);
                    }

                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                    }
                },
                onclose: (e) => {
                    setIsLiveConnected(false);
                    console.log("Session closed", e.code);

                    if (shouldReconnectRef.current && (e.code === 1006 || !e.wasClean)) {
                      if (retryCountRef.current < 3) {
                        retryCountRef.current++;
                        setTimeout(() => startLiveSession(), 1000 * retryCountRef.current);
                        return;
                      }
                      addMessage(Sender.SYSTEM, "Connection lost.");
                    }

                    setMode(InterviewMode.TEXT);
                    shouldReconnectRef.current = false;
                },
                onerror: (e) => {
                    console.error("Live Error:", e);
                }
            }
        });

    } catch (e: any) {
        console.error("Connect Failed", e);
        addMessage(Sender.SYSTEM, `Connection failed: ${e.message}`);
        setMode(InterviewMode.TEXT);
    }
  };

  const endLiveSession = async () => {
      shouldReconnectRef.current = false;
      try { activeSessionRef.current?.close(); } catch(e) {}
      mediaStreamRef.current?.getTracks().forEach(t => t.stop());
      sourcesRef.current.forEach(s => s.stop());
      setIsLiveConnected(false);
      setMode(InterviewMode.TEXT);
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      <header className="bg-[#161b22] border-b border-[#30363d] p-3 md:p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-2 md:gap-3">
            <div className={`w-2 h-2 md:w-3 md:h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight hidden md:block">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v2.9</span></h1>
            <h1 className="font-bold text-sm tracking-tight md:hidden">DEV_AI</h1>
        </div>
        <div className="flex items-center gap-2 md:gap-4 text-xs">
            {mode === InterviewMode.VOICE && <div className="scale-75 md:scale-100 origin-right"><AudioVisualizer isActive={isLiveConnected} /></div>}

            {resumeData && (
                <div className="flex items-center gap-1 text-green-400 bg-green-900/20 px-2 py-1 rounded border border-green-900/50">
                    <span>📄</span>
                    <span className="hidden md:inline">RESUME</span>
                </div>
            )}

            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button onClick={() => setPersona(Persona.INTERVIEWER)} className={`px-2 py-1 ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22]'}`}>INT</button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button onClick={() => setPersona(Persona.TUTOR)} className={`px-2 py-1 ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22]'}`}>TUTOR</button>
            </div>

            <button onClick={() => setShowCodeEditor(!showCodeEditor)} className={`px-2 py-1 rounded border ${showCodeEditor ? 'bg-[#30363d] text-white' : 'border-gray-700'}`}>CODE</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden relative">
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'hidden md:flex md:w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-2 md:p-4 space-y-4 bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && <div className="py-2 text-cyan-500 animate-pulse font-mono text-sm">&gt; Thinking...</div>}
                <div ref={messagesEndRef} />
            </main>

            <footer className="bg-[#161b22] border-t border-[#30363d] p-3 md:p-4 shrink-0">
                <div className="w-full flex gap-2 md:gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>
                    <form onSubmit={handleTextSubmit} className="flex-1 min-w-0">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={mode === InterviewMode.VOICE ? "Voice Active..." : "Type answer..."}
                            className="w-full bg-transparent border-none outline-none text-[#c9d1d9] placeholder-gray-600 font-mono text-sm md:text-base"
                            disabled={mode === InterviewMode.VOICE || isLoading}
                            autoFocus
                        />
                    </form>

                    <div className="flex items-center gap-2">
                        <button onClick={() => resumeInputRef.current?.click()} className={`p-2 rounded ${resumeData ? 'text-green-400' : 'text-gray-400'}`}>📄</button>
                        <input type="file" ref={resumeInputRef} className="hidden" accept=".pdf,.txt" onChange={handleResumeUpload} />

                        <button onClick={() => fileInputRef.current?.click()} className="p-2 rounded text-gray-400">🎤</button>
                        <input type="file" ref={fileInputRef} className="hidden" accept="audio/*" onChange={handleFileUpload} />

                        <button 
                            onClick={mode === InterviewMode.VOICE ? endLiveSession : startLiveSession}
                            className={`px-3 py-1 rounded text-xs font-bold ${mode === InterviewMode.VOICE ? 'bg-red-500/20 text-red-400' : 'bg-green-500/20 text-green-400'}`}
                        >
                            {mode === InterviewMode.VOICE ? 'END CALL' : 'LIVE CALL'}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {showCodeEditor && (
            <div className={`h-full ${showCodeEditor ? 'w-full md:w-1/2' : 'hidden'}`}>
                <CodeEditor />
            </div>
        )}
      </div>
    </div>
  );
};

export default App;

