    const response = await client.chat.completions.create({
      model: TEXT_MODEL_NAME,
      messages: [{ role: "user", content: prompt }],
    });

    return response.choices[0]?.message?.content || "No feedback.";
  } catch (error) {
    return "Error reviewing code.";
