}

export const TerminalMessage: React.FC<TerminalMessageProps> = ({ message, onPlayAudio }) => {
  const isUser = message.sender === Sender.USER;
  const isSystem = message.sender === Sender.SYSTEM;

  const renderGrounding = (chunks?: GroundingChunk[]) => {
    if (!chunks || chunks.length === 0) return null;
    return (
      <div className="mt-2 text-xs grid gap-1">
        {chunks.map((chunk, i) => {
          if (chunk.web) {
            return (
              <a key={i} href={chunk.web.uri} target="_blank" rel="noreferrer" className="text-blue-400 hover:underline flex items-center gap-1">
                [SOURCE] {chunk.web.title}
              </a>
            );
          }
          return null;
        })}
      </div>
    );
  };

  if (isSystem) {
    return (
      <div className="py-1 text-yellow-500 font-mono text-sm opacity-80">
        <span className="mr-2">SYSTEM &gt;&gt;</span>
        {message.text}
      </div>
    );
  }

  return (
    <div className={`py-2 font-mono flex flex-col ${isUser ? 'items-end' : 'items-start'}`}>
      <div className={`max-w-[85%] ${isUser ? 'text-right' : 'text-left'}`}>
        <div className="flex items-center gap-2 mb-1 opacity-60 text-xs">
          <span className={isUser ? 'text-cyan-400' : 'text-green-400'}>
            {isUser ? 'CANDIDATE' : 'INTERVIEWER_AI'}
          </span>
          <span>{new Date(message.timestamp).toLocaleTimeString([], { hour12: false })}</span>
          {message.isThinking && <span className="text-purple-400 animate-pulse">[DEEP THOUGHT]</span>}
        </div>

        <div className={`whitespace-pre-wrap ${isUser ? 'text-gray-300' : 'text-white'}`}>
          {message.text}
        </div>

        {/* Render Generated Image */}
        {message.imageData && (
          <div className="mt-3 border border-gray-700 rounded-md overflow-hidden bg-black/50">
            <img 
              src={message.imageData} 
              alt="Generated Visualization" 
              className="max-w-full h-auto max-h-[400px] object-contain"
              loading="lazy"
