export default App;

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import * as pdfjsLib from 'pdfjs-dist';
import { 
  generateInterviewQuestion, 
  generateImage,
  transcribeAudioFile, 
  ResumeData
} from './services/geminiService';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';

// Web Speech API Types
interface IWindow extends Window {
  webkitSpeechRecognition: any;
  SpeechRecognition: any;
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [tokenMissing, setTokenMissing] = useState(false);
  const [isImageMode, setIsImageMode] = useState(false);

  // Resume State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);

  // Refs
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);
  const resumeInputRef = useRef<HTMLInputElement>(null);
  const modeRef = useRef<InterviewMode>(mode);

  // Sync modeRef for callbacks
  useEffect(() => {
    modeRef.current = mode;
  }, [mode]);

  // Initial Welcome & Config
  useEffect(() => {
    // Configure PDF Worker
    // Handle ESM/CJS interop where pdfjsLib might be the module namespace or the default export
    const pdfjs = pdfjsLib as any;
    const workerOptions = pdfjs.GlobalWorkerOptions || pdfjs.default?.GlobalWorkerOptions || (window as any).pdfjsLib?.GlobalWorkerOptions;

    if (workerOptions) {
        // Use unpkg for the worker to ensure correct MIME type and avoid fake worker fallbacks
        workerOptions.workerSrc = "https://unpkg.com/pdfjs-dist@3.11.174/build/pdf.worker.min.js";
    } else {
        console.warn("Could not find PDFJS GlobalWorkerOptions. PDF parsing might fail.");
    }

    // Check for HF Token (with fallback)
    const key = process.env.HF_TOKEN || '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';

    if (!key || key.trim() === '') {
        setTokenMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: HF_TOKEN is missing. Please check your configuration.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console (GLM-4.7 + Hunyuan) initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer powered by Hugging Face.\n\nToggle the Image button or type '/image <prompt>' to generate visuals.");
    }
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false, imageData?: string) => {
    setMessages(prev => [...prev, {
      id: uuidv4(),
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking,
      imageData
    }]);
  };

  // --- Browser TTS Handling ---
  const playTTS = (text: string) => {
    if (!synthRef.current) return;

    // Stop any current speaking
    synthRef.current.cancel();

    // Strip Markdown for speech
    const cleanText = text.replace(/[*#`_]/g, '');

    const utterance = new SpeechSynthesisUtterance(cleanText);
    const voices = synthRef.current.getVoices();
    // Try to find a good voice
    const preferredVoice = voices.find(v => v.name.includes('Google US English') || v.name.includes('Samantha') || v.lang === 'en-US');
    if (preferredVoice) utterance.voice = preferredVoice;

    utterance.rate = 1.0;
    utterance.pitch = 1.0;

    synthRef.current.speak(utterance);
  };

  // --- Interaction Logic ---
  const handleTextSubmit = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const textToSend = overrideText || inputValue;
    if (!textToSend.trim()) return;

    if (!overrideText) setInputValue('');
    addMessage(Sender.USER, textToSend);

    if (tokenMissing) return;

    // Command: /code
    if (textToSend.toLowerCase() === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    // Command: /image <prompt> or Image Mode Active
    if (isImageMode || textToSend.toLowerCase().startsWith('/image')) {
        const prompt = textToSend.replace(/^\/image\s*/i, '');
        if (!prompt) {
            addMessage(Sender.SYSTEM, "Usage: Enter a description for the image.");
            setIsImageMode(false);
            return;
        }

        setIsLoading(true);
        addMessage(Sender.SYSTEM, `Generating image: "${prompt}"...`);
        setIsImageMode(false); // Reset mode after submission

        try {
            const imgDataUrl = await generateImage(prompt);
            addMessage(Sender.AI, `Here is the visualization for: "${prompt}"`, [], false, imgDataUrl);
        } catch (e: any) {
            addMessage(Sender.SYSTEM, `Image Generation Failed: ${e.message}`);
        } finally {
            setIsLoading(false);
        }
        return;
    }

    setIsLoading(true);

    // Context Construction
    // Limit history to last 6 messages to save tokens/context window
    const history = messages.slice(-6).filter(m => !m.imageData).map(m => `${m.sender}: ${m.text}`).join('\n');

    const response = await generateInterviewQuestion(
      history + `\nUSER: ${textToSend}`,
      persona,
      false,
      resumeData
    );

    setIsLoading(false);
    addMessage(Sender.AI, response.text);

    // Auto-play TTS if in Voice Mode
    if (mode === InterviewMode.VOICE) {
        playTTS(response.text);
    }
  };

  // --- Browser STT (Voice Mode) ---
  const toggleVoiceMode = () => {
    if (mode === InterviewMode.VOICE) {
        // Stop
        setMode(InterviewMode.TEXT);
        setIsLiveConnected(false);
        if (recognitionRef.current) recognitionRef.current.stop();
        synthRef.current.cancel();
        addMessage(Sender.SYSTEM, "Voice Mode Deactivated.");
    } else {
        // Start
        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        if (!SpeechRecognition) {
            addMessage(Sender.SYSTEM, "Error: Browser does not support Speech Recognition. Use Chrome/Safari.");
            return;
        }

        setMode(InterviewMode.VOICE);
        setIsLiveConnected(true);
        addMessage(Sender.SYSTEM, "Voice Mode Activated. Speak now...");

        const recognition = new SpeechRecognition();
        recognition.continuous = false; 
        recognition.interimResults = false;
        recognition.lang = 'en-US';

        recognition.onresult = (event: any) => {
            const transcript = event.results[0][0].transcript;
            handleTextSubmit(undefined, transcript);
        };

        recognition.onend = () => {
            // Use ref to check current mode, avoiding stale closure narrowing issues
            if (modeRef.current === InterviewMode.VOICE) {
               setIsLiveConnected(false); 
            }
        };

        recognitionRef.current = recognition;
        recognition.start();
    }
  };

  const startListening = () => {
     if (recognitionRef.current && mode === InterviewMode.VOICE) {
         try { 
             recognitionRef.current.start(); 
             setIsLiveConnected(true); 
         } catch(e) {
             // Already started
         }
     }
  };

  // --- Resume Upload (Text & PDF) ---
  const handleResumeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    addMessage(Sender.SYSTEM, `Reading resume: ${file.name}...`);
    setIsLoading(true);

    try {
        let text = "";

        if (file.type === 'application/pdf') {
             const arrayBuffer = await file.arrayBuffer();

             // Dynamic accessor for getDocument to handle import discrepancies
             const pdfjs = pdfjsLib as any;
             const getDocument = pdfjs.getDocument || pdfjs.default?.getDocument || (window as any).pdfjsLib?.getDocument;
             const workerOptions = pdfjs.GlobalWorkerOptions || pdfjs.default?.GlobalWorkerOptions || (window as any).pdfjsLib?.GlobalWorkerOptions;

             if (!getDocument) {
                 throw new Error("PDF.js library not properly loaded.");
             }

             // Ensure worker is set again just in case
             if (workerOptions && !workerOptions.workerSrc) {
                 workerOptions.workerSrc = "https://unpkg.com/pdfjs-dist@3.11.174/build/pdf.worker.min.js";
             }

             const loadingTask = getDocument({ data: arrayBuffer });
             const pdf = await loadingTask.promise;

             let fullText = "";
             for (let i = 1; i <= pdf.numPages; i++) {
                 const page = await pdf.getPage(i);
                 const textContent = await page.getTextContent();
                 const pageText = textContent.items.map((item: any) => item.str).join(' ');
                 fullText += pageText + "\n";
             }
             text = fullText;
        } else {
             // Text/MD
             text = await new Promise<string>((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = () => resolve(reader.result as string);
                reader.onerror = reject;
                reader.readAsText(file);
             });
        }

        setResumeData({
            data: text, 
            mimeType: 'text/plain'
        });
        addMessage(Sender.SYSTEM, "Resume loaded. I will tailor questions to your experience.");

    } catch (err: any) {
        console.error(err);
        addMessage(Sender.SYSTEM, `Failed to read file: ${err.message || 'Unknown error'}`);
    } finally {
        setIsLoading(false);
        if (resumeInputRef.current) resumeInputRef.current.value = '';
    }
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-3 md:p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-2 md:gap-3">
            <div className={`w-2 h-2 md:w-3 md:h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight hidden md:block">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v3.0</span></h1>
            <h1 className="font-bold text-sm tracking-tight md:hidden">DEV_AI</h1>
        </div>
        <div className="flex items-center gap-2 md:gap-4 text-xs">
            {mode === InterviewMode.VOICE && <div className="scale-75 md:scale-100 origin-right"><AudioVisualizer isActive={isLiveConnected} /></div>}

            {resumeData && (
                <div className="flex items-center gap-1 text-green-400 bg-green-900/20 px-2 py-1 rounded border border-green-900/50">
                    <span>📄</span>
                    <span className="hidden md:inline">RESUME</span>
                </div>
            )}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">INT</span>
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'}`}
                >
                    <span className="hidden md:inline">TUTOR</span>
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-2 py-1 md:px-3 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE' : 'CODE'}
            </button>

            <span className="px-2 py-1 bg-[#30363d] rounded text-gray-300 hidden md:inline-block">
                {mode}
            </span>
        </div>
      </header>

      {/* Main Content */}
      <div className="flex-1 flex overflow-hidden relative">
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'hidden md:flex md:w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-2 md:p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono text-sm">
                    &gt; Thinking...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-3 md:p-4 shrink-0">
                <div className="w-full flex gap-2 md:gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={(e) => handleTextSubmit(e)} className="flex-1 min-w-0">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={
                                mode === InterviewMode.VOICE ? "Listening..." : 
                                tokenMissing ? "HF_TOKEN MISSING" : 
                                isImageMode ? "Describe image to generate..." :
                                "Type answer..." 
                            }
                            className={`w-full bg-transparent border-none outline-none font-mono text-sm md:text-base disabled:cursor-not-allowed ${isImageMode ? 'text-purple-300 placeholder-purple-700/50' : 'text-[#c9d1d9] placeholder-gray-600'}`}
                            disabled={isLoading || tokenMissing}
                            autoFocus
                        />
                    </form>

                    <div className="flex items-center gap-2">
                        {/* Image Toggle Button */}
                        <button
                            onClick={() => setIsImageMode(!isImageMode)}
                            className={`p-1.5 md:p-2 rounded transition-colors ${isImageMode ? 'text-purple-400 bg-purple-900/20' : 'text-gray-400 hover:text-white'}`}
                            title="Generate Image"
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                            </svg>
                        </button>

                         <button 
                            onClick={() => resumeInputRef.current?.click()}
                            title="Upload Resume (PDF/Text/MD)"
                            className={`p-1.5 md:p-2 hover:bg-[#30363d] rounded transition-colors ${resumeData ? 'text-green-400' : 'text-gray-400 hover:text-white'}`}
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
