            </div>
        )}
      </div>
    </div>
  );
};

export default App;

import { OpenAI } from "openai";
import { HfInference } from "@huggingface/inference";
import { GroundingChunk, Persona } from "../types";

// Token fallback
const HF_TOKEN = process.env.HF_TOKEN || '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';

// Initialize OpenAI client for Hugging Face Text
const getClient = () => new OpenAI({
    baseURL: "https://router.huggingface.co/v1",
    apiKey: HF_TOKEN,
    dangerouslyAllowBrowser: true
});

// Initialize Inference Client for Images
const getInferenceClient = () => new HfInference(HF_TOKEN);

const TEXT_MODEL_NAME = "zai-org/GLM-4.7:novita";
// Switch to a free-tier compatible model on Hugging Face Inference API
const IMAGE_MODEL_NAME = "stabilityai/stable-diffusion-xl-base-1.0";

// --- Tools (Mock for UI compatibility) ---
export const displayCodingProblemTool = {};

// --- Text & Reasoning ---

export interface ResumeData {
  data: string;
  mimeType: string;
}

export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false,
  resume?: ResumeData
): Promise<{ text: string, grounding?: GroundingChunk[] }> => {

  const client = getClient();

  const systemInstructions = {
    [Persona.TUTOR]: "You are an expert AI Coding Tutor. Explain concepts clearly, provide code snippets, and be encouraging.",
    [Persona.INTERVIEWER]: `You are a strict Senior Technical Interviewer. 
1. Ask one distinct question at a time.
2. If a resume is provided, prioritize questions about it.
3. For coding problems, provide Title, Description, Examples, and Constraints.
4. Do not give full solutions.`
  };

  const messages: any[] = [
    { role: "system", content: systemInstructions[persona] }
  ];

  if (resume) {
      messages.push({ role: "system", content: `RESUME CONTEXT:\n${resume.data}` });
  }

  messages.push({ role: "user", content: history });

  try {
    const response = await client.chat.completions.create({
      model: TEXT_MODEL_NAME,
      messages: messages,
      stream: false,
      temperature: 0.7,
      max_tokens: 1024
    });

    return {
      text: response.choices[0]?.message?.content || "Error generating response.",
      grounding: [] 
    };
  } catch (error: any) {
    console.error("HF API Error:", error);
    return { text: `API Error: ${error.message || "Unknown error"}` };
  }
};

export const fastAck = async (input: string): Promise<string> => {
  try {
    const client = getClient();
    const response = await client.chat.completions.create({
      model: TEXT_MODEL_NAME,
      messages: [{ role: "user", content: `Provide a 3-word acknowledgement for: ${input}` }],
      max_tokens: 20
    });
    return response.choices[0]?.message?.content || "Acknowledged.";
  } catch (e) {
    return "...";
  }
};

// --- Image Generation ---

export const generateImage = async (prompt: string): Promise<string> => {
  try {
    const client = getInferenceClient();
    // Removed specific provider "fal-ai" to use default free inference API
    const blob = await client.textToImage({
        model: IMAGE_MODEL_NAME,
        inputs: prompt,
    });

    // Convert Blob to Base64 Data URL
    return await new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onloadend = () => resolve(reader.result as string);
      reader.onerror = reject;
      reader.readAsDataURL(blob);
    });
  } catch (error: any) {
    console.error("Image Gen Error:", error);
    throw new Error(error.message || "Failed to generate image");
  }
};

// --- Code Execution & Review ---

export const runCodeWithAI = async (language: string, code: string): Promise<string> => {
  try {
    const client = getClient();
    const prompt = `Act as a strictly deterministic compiler/interpreter for ${language}.
EXECUTE the code and return ONLY the stdout/stderr.
Code:
${code}`;

    const response = await client.chat.completions.create({
      model: TEXT_MODEL_NAME,
      messages: [{ role: "user", content: prompt }],
      temperature: 0.1
    });

    let text = response.choices[0]?.message?.content || "";
    text = text.replace(/^```[\w]*\n?/, '').replace(/\n?```$/, '');
    return text.trim() || "[No Output]";
  } catch (error) {
    return "Error executing code.";
  }
};

