import { GoogleGenAI, Type } from "@google/genai";
import { GroundingChunk, Persona } from "../types";

// Initialize Gemini Client
// API Key is injected via process.env.API_KEY as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- Tools & Types ---

export interface ResumeData {
  data: string;
  mimeType: string;
}

// --- Text & Reasoning ---

export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false,
  resume?: ResumeData
): Promise<{ text: string, grounding?: GroundingChunk[] }> => {

  const systemInstruction = persona === Persona.TUTOR 
    ? "You are an expert AI Coding Tutor. Explain concepts clearly, provide code snippets, and be encouraging."
    : `You are a strict Senior Technical Interviewer. 
1. Ask one distinct question at a time.
2. If a resume is provided, prioritize questions about it.
3. For coding problems, provide Title, Description, Examples, and Constraints.
4. Do not give full solutions.`;

  let prompt = history;
  if (resume) {
      prompt = `RESUME CONTEXT:\n${resume.data}\n\n${history}`;
  }

  try {
    const model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
    const config: any = {
        systemInstruction,
    };

    // Configure thinking budget if using the pro thinking model
    if (useThinking) {
        config.thinkingConfig = { thinkingBudget: 2048 };
    }

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config
    });

    // Extract grounding if available
    const grounding: GroundingChunk[] = [];
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
        response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
            if (chunk.web) grounding.push({ web: chunk.web });
            // Maps grounding would be here if using googleMaps tool
        });
    }

    return {
      text: response.text || "Error generating response.",
      grounding
    };
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return { text: `API Error: ${error.message || "Unknown error"}` };
  }
};

export const fastAck = async (input: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide a 3-word acknowledgement for: ${input}`,
      config: { maxOutputTokens: 20 }
    });
    return response.text || "Acknowledged.";
  } catch (e) {
    return "...";
  }
};

// --- Image Generation ---

export const generateImage = async (prompt: string): Promise<string> => {
  try {
    // Use gemini-2.5-flash-image for general image generation
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
        config: {
            imageConfig: {
                aspectRatio: "1:1"
            }
        }
    });

    const candidate = response.candidates?.[0];

    // Check if the model refused or stopped for safety
    if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
        throw new Error(`Generation blocked: ${candidate.finishReason}`);
    }

    // Find the image part in the response
    for (const part of candidate?.content?.parts || []) {
        if (part.inlineData && part.inlineData.data) {
            return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
        }
        // If the model returns text instead (refusal/explanation), capture it as error
        if (part.text) {
             throw new Error(`Model: ${part.text}`);
        }
    }

    throw new Error("No image data found in response.");
  } catch (error: any) {
    console.error("Image Gen Error:", error);
    throw new Error(error.message || "Failed to generate image");
  }
};

