export const transcribeAudioFile = async (base64Audio: string, mimeType: string): Promise<string> => {
  try {
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-native-audio-preview-12-2025',
          contents: {
              parts: [
                  { inlineData: { data: base64Audio, mimeType } },
                  { text: "Transcribe this audio verbatim." }
              ]
          }
      });
      return response.text || "";
  } catch (e) {
      console.error(e);
      return "Transcription failed.";
  }
};

// --- Maps Grounding ---
export const getGeographicContext = async (query: string, lat?: number, lng?: number): Promise<{ text: string, grounding: GroundingChunk[] }> => {
  try {
      const config: any = {
          tools: [{ googleMaps: {} }]
      };

      if (lat && lng) {
          config.toolConfig = {
              retrievalConfig: {
                  latLng: { latitude: lat, longitude: lng }
              }
          };
      }

      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash', // Maps only supported on 2.5
          contents: query,
          config
      });

      const grounding: GroundingChunk[] = [];
      if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
           response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
               if (chunk.maps) grounding.push({ maps: chunk.maps });
               if (chunk.web) grounding.push({ web: chunk.web });
           });
      }

      return { text: response.text || "No location info.", grounding };
  } catch (e) {
      return { 
          text: "Geographic context currently unavailable.",
          grounding: [] 
      };
  }
};

