                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={resumeInputRef} 
                            className="hidden" 
                            accept=".pdf,.txt,.md,.json"
                            onChange={handleResumeUpload}
                        />

                        {/* STOP SPEAKING BUTTON */}
                        <button 
                            onClick={handleStopSpeaking}
                            title="Stop Speaking"
                            className="p-1.5 md:p-2 hover:bg-[#30363d] rounded transition-colors text-gray-400 hover:text-red-400"
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="currentColor" viewBox="0 0 24 24">
                                <rect x="6" y="6" width="12" height="12" rx="1" ry="1" />
                            </svg>
                        </button>

                        <button 
                            onClick={toggleVoiceMode}
                            className={`px-3 py-1.5 md:px-4 md:py-2 rounded text-[10px] md:text-xs font-bold transition-all whitespace-nowrap flex items-center gap-2 ${
                                mode === InterviewMode.VOICE 
                                ? 'bg-red-600 hover:bg-red-700 text-white shadow-[0_0_10px_rgba(220,38,38,0.5)]' 
                                : 'bg-green-600 hover:bg-green-700 text-white'
                            }`}
                        >
                            {mode === InterviewMode.VOICE ? (
                                <>
                                    <span className="animate-pulse">●</span> <span className="hidden sm:inline">END CALL</span>
                                </>
                            ) : (
                                <>
                                    <span>🎤</span> <span className="hidden sm:inline">START VOICE</span>
                                </>
                            )}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {showCodeEditor && (
            <div className={`h-full ${showCodeEditor ? 'w-full md:w-1/2' : 'hidden'}`}>
                <CodeEditor onReviewRequest={handleCodeReviewRequest} />
            </div>
        )}
      </div>
    </div>
  );
};

