// Advanced text chunker with sliding window and semantic boundary detection
export const chunkText = (text: string, maxLength: number = 800, overlap: number = 150): string[] => {
    const chunks: string[] = [];
    const cleanedText = text.replace(/\r\n/g, "\n");

    let start = 0;

    while (start < cleanedText.length) {
      let end = start + maxLength;

      // If remaining text is smaller than maxLength, take it all
      if (end >= cleanedText.length) {
        const chunk = cleanedText.slice(start).trim();
        if (chunk.length > 20) chunks.push(chunk);
        break;
      }

      // Smart Split: Find best boundary traversing backwards from 'end'
      // 1. Double Newline (Paragraph)
      let splitIndex = cleanedText.lastIndexOf("\n\n", end);

      // 2. Single Newline
      if (splitIndex === -1 || splitIndex < start) {
        splitIndex = cleanedText.lastIndexOf("\n", end);
      }

      // 3. Sentence End (. ! ?)
      if (splitIndex === -1 || splitIndex < start) {
          const sentenceEnd = Math.max(
              cleanedText.lastIndexOf(". ", end),
              cleanedText.lastIndexOf("! ", end),
              cleanedText.lastIndexOf("? ", end)
          );
          if (sentenceEnd !== -1 && sentenceEnd > start) {
              splitIndex = sentenceEnd + 1; // Include punctuation
          }
      }

      // 4. Word Boundary (Space)
      if (splitIndex === -1 || splitIndex < start) {
          splitIndex = cleanedText.lastIndexOf(" ", end);
      }

      // 5. Hard Cut (if no boundaries found)
      if (splitIndex === -1 || splitIndex < start) {
        splitIndex = end;
      }

      const chunk = cleanedText.slice(start, splitIndex).trim();
      // Only add chunk if it has sufficient content
      if (chunk.length > 20) chunks.push(chunk);

      // Move start pointer for next iteration (apply overlap)
      // Ensure we advance at least 1 character to prevent infinite loops
      start = Math.max(splitIndex - overlap, start + 1);
    }

    return chunks;
  };

  // Calculate Cosine Similarity between two vectors
  export const cosineSimilarity = (vecA: number[], vecB: number[]): number => {
    let dotProduct = 0;
    let normA = 0;
    let normB = 0;

    for (let i = 0; i < vecA.length; i++) {
      dotProduct += vecA[i] * vecB[i];
      normA += vecA[i] * vecA[i];
      normB += vecB[i] * vecB[i];
    }

    if (normA === 0 || normB === 0) return 0;
    return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
  };

  // Helper to retrieve and format top chunks
  export const retrieveRelevantChunks = (
    queryVector: number[], 
    store: { text: string; vector: number[] }[], 
    topK: number = 3,
    minScore: number = 0.50 // Tuned for text-embedding-004
  ): string => {
    const scored = store.map(item => ({
        text: item.text,
        score: cosineSimilarity(queryVector, item.vector)
    }));

    // Sort descending
    scored.sort((a, b) => b.score - a.score);

    // Filter by threshold
    const relevant = scored.filter(item => item.score >= minScore);

    // Debug logs for tuning
    if (relevant.length > 0) {
        console.debug("RAG Matches:", relevant.slice(0, topK).map(r => r.score.toFixed(3)));
    } else {
        console.debug("RAG: No matches above threshold", minScore);
    }

    return relevant.slice(0, topK).map(item => item.text).join("\n\n---\n\n");
  };

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import * as pdfjsLib from 'pdfjs-dist';
import { 
  generateInterviewQuestion, 
  generateImage,
