// --- RAG & Embeddings ---

export const getEmbedding = async (text: string): Promise<number[]> => {
  if (apiKey === "missing_api_key") throw new Error("API Key missing");
  try {
    // text-embedding-004 supports string input directly for contents
    const response = await ai.models.embedContent({
      model: 'text-embedding-004',
      contents: text 
    });
    return response.embedding?.values || [];
  } catch (e: any) {
    console.error("Embedding Error:", e.message || e);
    // Retry logic could be added here, but relying on caller for now.
    return [];
  }
};

// --- Text & Reasoning (Standard API) ---

export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false,
  resume?: ResumeData,
  ragContext?: string // NEW: Accepted Retrieved Context
): Promise<{ text: string, imagePrompt?: string, grounding?: GroundingChunk[], isCodingChallenge?: boolean }> => {

  if (apiKey === "missing_api_key") {
      return { text: "Error: API Key is missing. Please configure it in your deployment settings." };
  }

  const baseInstruction = persona === Persona.TUTOR 
    ? "You are an expert AI Coding Tutor. Explain concepts clearly, provide code snippets, and be encouraging."
    : `You are a strict Senior Technical Interviewer. 
1. Ask one distinct question at a time.
2. If a resume is provided, prioritize questions about it.
3. For coding problems, provide Title, Description, Examples, and Constraints.
4. Do not give full solutions.`;

  let systemInstruction = `${baseInstruction}

  CRITICAL: You must respond in JSON format.
  If the question requires the user to write code (e.g. "Write a function...", "Implement...", "Solve this algorithm..."), set 'is_coding_challenge' to true.
  If the concept involves data structures, algorithms, or architecture that benefits from visualization, provide a 'visual_description'.
  Otherwise, 'visual_description' should be null.`;

  // Inject RAG Context into the prompt
  let prompt = history;

  if (ragContext) {
    prompt = `[KNOWLEDGE BASE CONTEXT]\nUse the following technical documentation/notes to guide your questions or validate the user's answers:\n${ragContext}\n\n[END CONTEXT]\n\n${prompt}`;
  }

  if (resume) {
      prompt = `RESUME CONTEXT:\n${resume.data}\n\n${prompt}`;
  }

  try {
    const model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
    const config: any = {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.OBJECT,
            properties: {
                content: { type: Type.STRING },
                visual_description: { type: Type.STRING, nullable: true },
                is_coding_challenge: { type: Type.BOOLEAN }
            },
            required: ["content", "is_coding_challenge"]
        }
    };

    if (useThinking) {
        config.thinkingConfig = { thinkingBudget: 2048 };
    }

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config
    });

    const grounding: GroundingChunk[] = [];
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
        response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
            if (chunk.web) grounding.push({ web: chunk.web });
        });
    }

    let parsedResponse;
    try {
        parsedResponse = JSON.parse(response.text || "{}");
    } catch (e) {
        return { text: response.text || "Error parsing response." };
    }

    return {
      text: parsedResponse.content || "Error generating content.",
      imagePrompt: parsedResponse.visual_description,
      grounding,
      isCodingChallenge: parsedResponse.is_coding_challenge
    };
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return { text: `API Error: ${error.message || "Unknown error"}` };
  }
};

export const fastAck = async (input: string): Promise<string> => {
