import { GoogleGenAI, Type, LiveServerMessage, Modality } from "@google/genai";
import { HfInference } from "@huggingface/inference";
import { GroundingChunk, Persona } from "../types";
import { createPcmBlob } from "../utils/audioUtils";

// Initialize Gemini Client
// Prevent crash if API_KEY is missing during initialization
const apiKey = process.env.API_KEY || "missing_api_key";
const ai = new GoogleGenAI({ apiKey });

// Initialize Hugging Face Client
const hf = new HfInference(process.env.HF_TOKEN || "missing_hf_token");

// --- Tools & Types ---

export interface ResumeData {
  data: string;
  mimeType: string;
}

// --- RAG & Embeddings ---

export const getEmbedding = async (text: string): Promise<number[]> => {
  if (apiKey === "missing_api_key") throw new Error("API Key missing");
  try {
    const response = await ai.models.embedContent({
      model: 'text-embedding-004',
      contents: { parts: [{ text }] }
    });
    return response.embedding?.values || [];
  } catch (e: any) {
    console.error("Embedding Error", e);
    return [];
  }
};

// --- Text & Reasoning (Standard API) ---

export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false,
  resume?: ResumeData,
  ragContext?: string // NEW: Accepted Retrieved Context
): Promise<{ text: string, imagePrompt?: string, grounding?: GroundingChunk[], isCodingChallenge?: boolean }> => {

  if (apiKey === "missing_api_key") {
      return { text: "Error: API Key is missing. Please configure it in your deployment settings." };
  }

  const baseInstruction = persona === Persona.TUTOR 
    ? "You are an expert AI Coding Tutor. Explain concepts clearly, provide code snippets, and be encouraging."
    : `You are a strict Senior Technical Interviewer. 
1. Ask one distinct question at a time.
2. If a resume is provided, prioritize questions about it.
3. For coding problems, provide Title, Description, Examples, and Constraints.
4. Do not give full solutions.`;

  let systemInstruction = `${baseInstruction}

  CRITICAL: You must respond in JSON format.
  If the question requires the user to write code (e.g. "Write a function...", "Implement...", "Solve this algorithm..."), set 'is_coding_challenge' to true.
  If the concept involves data structures, algorithms, or architecture that benefits from visualization, provide a 'visual_description'.
  Otherwise, 'visual_description' should be null.`;

  // Inject RAG Context into the prompt
  let prompt = history;

  if (ragContext) {
    prompt = `[KNOWLEDGE BASE CONTEXT]\nUse the following technical documentation/notes to guide your questions or validate the user's answers:\n${ragContext}\n\n[END CONTEXT]\n\n${prompt}`;
  }

  if (resume) {
      prompt = `RESUME CONTEXT:\n${resume.data}\n\n${prompt}`;
  }

  try {
    const model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
    const config: any = {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.OBJECT,
            properties: {
                content: { type: Type.STRING },
                visual_description: { type: Type.STRING, nullable: true },
                is_coding_challenge: { type: Type.BOOLEAN }
            },
            required: ["content", "is_coding_challenge"]
        }
    };

    if (useThinking) {
        config.thinkingConfig = { thinkingBudget: 2048 };
    }

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config
    });

    const grounding: GroundingChunk[] = [];
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
        response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
            if (chunk.web) grounding.push({ web: chunk.web });
        });
    }

    let parsedResponse;
    try {
        parsedResponse = JSON.parse(response.text || "{}");
    } catch (e) {
        return { text: response.text || "Error parsing response." };
    }

    return {
      text: parsedResponse.content || "Error generating content.",
      imagePrompt: parsedResponse.visual_description,
      grounding,
      isCodingChallenge: parsedResponse.is_coding_challenge
    };
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return { text: `API Error: ${error.message || "Unknown error"}` };
  }
};

export const fastAck = async (input: string): Promise<string> => {
  if (apiKey === "missing_api_key") return "...";
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide a 3-word acknowledgement for: ${input}`,
      config: { maxOutputTokens: 20 }
    });
    return response.text || "Acknowledged.";
  } catch (e) {
    return "...";
  }
};

// --- Live API (Real-time Audio) ---

export interface LiveSessionConfig {
  onOpen: () => void;
  onAudioData: (base64: string) => void;
  onTranscript: (text: string, isUser: boolean, isFinal: boolean) => void;
  onClose: () => void;
  onError: (err: any) => void;
  onInterrupted: () => void;
  persona: Persona;
}

export const connectToLiveSession = async (config: LiveSessionConfig) => {
  if (apiKey === "missing_api_key") {
      config.onError(new Error("API Key missing"));
      return { sendAudioChunk: () => {}, disconnect: () => {} };
  }

  const model = 'gemini-2.5-flash-native-audio-preview-12-2025';

  const systemInstruction = config.persona === Persona.TUTOR
    ? "You are a helpful and patient Coding Tutor. Listen to the student's questions and guide them. Keep answers concise for spoken conversation."
    : "You are a strict Technical Interviewer. Conduct a professional coding interview. Ask one short, clear question at a time. Do not ramble. Interrupt if the candidate is off track.";

  const sessionPromise = ai.live.connect({
    model,
    callbacks: {
      onopen: () => {
        config.onOpen();
      },
      onmessage: (message: LiveServerMessage) => {
        // Handle Audio Output
        const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
        if (audioData) {
          config.onAudioData(audioData);
        }

        // Handle Transcripts
        if (message.serverContent?.outputTranscription) {
            config.onTranscript(message.serverContent.outputTranscription.text || "", false, !!message.serverContent.turnComplete);
        } else if (message.serverContent?.inputTranscription) {
            config.onTranscript(message.serverContent.inputTranscription.text || "", true, true);
        }

        // Handle Interruption (User spoke while AI was speaking)
        if (message.serverContent?.interrupted) {
            config.onInterrupted();
        }
      },
      onclose: () => {
        config.onClose();
      },
      onerror: (err) => {
        config.onError(err);
      }
    },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
      },
      inputAudioTranscription: {}, 
      outputAudioTranscription: {}, 
      systemInstruction: { parts: [{ text: systemInstruction }] },
    }
  });

  return {
    sendAudioChunk: (data: Float32Array) => {
      const blob = createPcmBlob(data);
      sessionPromise.then(session => {
        session.sendRealtimeInput({ media: blob });
      });
    },
    disconnect: () => {
      sessionPromise.then(session => session.close());
    }
  };
};

// --- Image Generation ---

export const generateImage = async (prompt: string): Promise<string> => {
  if (apiKey === "missing_api_key") throw new Error("API Key missing");

  // 1. Try Gemini 2.5 Flash Image (Primary - Fast & Native)
  try {
      console.log("Generating with Gemini 2.5 Flash Image...");
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: { parts: [{ text: prompt }] },
          config: { 
            imageConfig: { aspectRatio: "16:9" } 
          }
      });
      const candidate = response.candidates?.[0];
      for (const part of candidate?.content?.parts || []) {
          if (part.inlineData && part.inlineData.data) {
              return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
          }
      }
      console.warn("Gemini 2.5 Flash Image returned no image data, checking fallbacks.");
  } catch (error: any) {
      console.warn("Gemini 2.5 Flash Image Error:", error.message);
  }

  // 2. Try Imagen 3 (High Quality Fallback)
  try {
      console.log("Falling back to Imagen 3.0...");
      const response = await ai.models.generateImages({
        model: 'imagen-3.0-generate-001',
        prompt: prompt,
        config: {
          numberOfImages: 1,
          outputMimeType: 'image/jpeg',
          aspectRatio: '16:9',
        },
      });
      const b64 = response.generatedImages?.[0]?.image?.imageBytes;
      if (b64) {
          return `data:image/jpeg;base64,${b64}`;
      }
      throw new Error("No image bytes in Imagen response");
  } catch(e: any) {
      console.warn("Imagen Error:", e.message);
  }

  // 3. Last Resort: Hugging Face
  const hfModels = [
    "runwayml/stable-diffusion-v1-5", 
    "stabilityai/stable-diffusion-2-1",
    "CompVis/stable-diffusion-v1-4"
  ];

  if (process.env.HF_TOKEN && process.env.HF_TOKEN !== "missing_hf_token") {
      for (const model of hfModels) {
        try {
            console.log(`Attempting HF fallback: ${model}...`);
            const blob = await hf.textToImage({
              model: model,
              inputs: prompt,
              parameters: {
                negative_prompt: "blurry, low quality, distortion, ugly, text, watermark",
              }
            });
            return await new Promise((resolve, reject) => {
              const reader = new FileReader();
              reader.onloadend = () => resolve(reader.result as string);
              reader.onerror = reject;
              reader.readAsDataURL(blob as unknown as Blob);
            });
        } catch (error: any) {
            console.warn(`Hugging Face Image Gen Error (${model}):`, error.message);
        }
      }
  }

  throw new Error("Failed to generate visualization.");
};

