// --- RAG & Embeddings ---

export const getEmbedding = async (text: string): Promise<number[]> => {
  if (apiKey === "missing_api_key") throw new Error("API Key missing");
  try {
    const response = await ai.models.embedContent({
      model: 'text-embedding-004',
      contents: { parts: [{ text }] }
    });

    // Fix: Handle potential type definition mismatch (embedding vs embeddings)
    const result = (response as any).embedding || (response as any).embeddings?.[0];
    return result?.values || [];
  } catch (e: any) {
    console.error("Embedding Error", e);
    return [];
  }
};

export const getBatchEmbeddings = async (texts: string[]): Promise<number[][]> => {
  if (apiKey === "missing_api_key") throw new Error("API Key missing");

  // Batch limit: typically 100 requests. 
  const MAX_BATCH_SIZE = 100;
  const allEmbeddings: number[][] = [];

  for (let i = 0; i < texts.length; i += MAX_BATCH_SIZE) {
      const batchTexts = texts.slice(i, i + MAX_BATCH_SIZE);
      try {
          const requests = batchTexts.map(t => ({
              content: { parts: [{ text: t }] }
          }));

          const response = await ai.models.batchEmbedContents({
              model: 'text-embedding-004',
              requests: requests as any
          });

          const embeddings = (response as any).embeddings;
          if (Array.isArray(embeddings)) {
              embeddings.forEach((e: any) => {
                  allEmbeddings.push(e.values || []);
              });
          } else {
              // Fallback if response structure differs
              batchTexts.forEach(() => allEmbeddings.push([]));
          }
      } catch (e) {
          console.error(`Batch embedding failed at index ${i}`, e);
          // Maintain alignment
          batchTexts.forEach(() => allEmbeddings.push([]));
      }
  }
  return allEmbeddings;
};

// --- Text & Reasoning (Streaming API) ---

export const streamInterviewQuestion = async (
  history: string, 
  persona: Persona,
  resume?: ResumeData,
  ragContext?: string
) => {

  if (apiKey === "missing_api_key") {
      throw new Error("API Key is missing. Please configure it in your deployment settings.");
  }

  const baseInstruction = persona === Persona.TUTOR 
    ? "You are an expert AI Coding Tutor. Explain concepts clearly, provide code snippets, and be encouraging."
    : `You are a strict Senior Technical Interviewer. 
1. Ask one distinct question at a time.
2. If a resume is provided, prioritize questions about it.
3. For coding problems, provide Title, Description, Examples, and Constraints.
4. Do not give full solutions.`;

  // We use special tags instead of JSON to allow for slick text streaming
  let systemInstruction = `${baseInstruction}

  RESPONSE FORMATTING RULES:
  1. Output strictly plain text (Markdown supported). Do NOT output JSON.
  2. If the question requires the user to write code (e.g. "Write a function..."), start your response with "[[CODING_CHALLENGE]]" (without quotes).
  3. If a visual diagram or image would explain the concept better, append "[[VISUALIZE: <image_description>]]" at the very end of your response.
  `;

  // Inject RAG Context into the prompt
  let prompt = history;

  if (ragContext) {
    prompt = `[KNOWLEDGE BASE CONTEXT]\nUse the following technical documentation/notes to guide your questions or validate the user's answers:\n${ragContext}\n\n[END CONTEXT]\n\n${prompt}`;
  }

  if (resume) {
      prompt = `RESUME CONTEXT:\n${resume.data}\n\n${prompt}`;
  }

  try {
    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction,
      }
    });

    return responseStream;

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

