import * as pdfjsLib from 'pdfjs-dist';
import { 
  streamInterviewQuestion, // Updated Import
  generateImage,
  connectToLiveSession,
  reviewCodeWithAI,
  getEmbedding,
  getBatchEmbeddings, // New Import
  ResumeData
} from './services/geminiService';
import { chunkText, retrieveRelevantChunks } from './utils/ragEngine';
import { downsampleBuffer, decodeAudioData } from './utils/audioUtils';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona, GroundingChunk } from './types';

// Web Speech API Types (Fallback/Legacy)
interface IWindow extends Window {
  webkitSpeechRecognition: any;
  SpeechRecognition: any;
}

// RAG Types
interface VectorStoreItem {
  text: string;
  vector: number[];
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [tokenMissing, setTokenMissing] = useState(false);

  // Data State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);
  const [hasKnowledgeBase, setHasKnowledgeBase] = useState(false);

  // Refs
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);
  const resumeInputRef = useRef<HTMLInputElement>(null);
  const kbInputRef = useRef<HTMLInputElement>(null);

  // Vector Store (In-Memory RAG)
  const vectorStoreRef = useRef<VectorStoreItem[]>([]);

  // Live API Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const liveSessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<AudioBufferSourceNode[]>([]);

  // Keep track of transcripts to merge them
  const currentTurnTextRef = useRef<string>("");

  // Initial Welcome & Config
  useEffect(() => {
    // Configure PDF Worker
    const pdfjs = pdfjsLib as any;
    const workerOptions = pdfjs.GlobalWorkerOptions || pdfjs.default?.GlobalWorkerOptions || (window as any).pdfjsLib?.GlobalWorkerOptions;

    if (workerOptions) {
        workerOptions.workerSrc = "https://unpkg.com/pdfjs-dist@3.11.174/build/pdf.worker.min.js";
    }

    // Check for Gemini API Key
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setTokenMissing(true);
        addMessage(Sender.SYSTEM, "CRITICAL: API_KEY is missing. Please check your configuration.");
    } else {
        addMessage(Sender.SYSTEM, "DevInterview AI Console (Gemini 3 + 2.5 Live) initialized...");
        addMessage(Sender.AI, "Hello. I am your AI Interviewer. Type to chat, or click 'START VOICE' for a real-time verbal interview.");
    }

    return () => {
        // Cleanup Audio Context on unmount
        if (audioContextRef.current) audioContextRef.current.close();
    };
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false, imageData?: string) => {
    const id = uuidv4();
    setMessages(prev => [...prev, {
      id,
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking,
      imageData
    }]);
    return id;
  };

  const updateLastMessage = (text: string, sender: Sender) => {
      setMessages(prev => {
          const last = prev[prev.length - 1];
          if (last && last.sender === sender) {
              return [
                  ...prev.slice(0, -1),
                  { ...last, text: text }
              ];
          } else {
              // Create new if sender doesn't match or no messages
              return [...prev, {
                  id: uuidv4(),
                  sender,
                  text,
                  timestamp: Date.now()
              }];
          }
      });
  };

  // --- Browser TTS (Fallback for Text Mode) ---
  const playTTS = (text: string) => {
    if (!synthRef.current || mode === InterviewMode.VOICE) return; // Don't use TTS in Live Mode

    synthRef.current.cancel();
    const cleanText = text.replace(/[*#`_]/g, '');
    const utterance = new SpeechSynthesisUtterance(cleanText);
    const voices = synthRef.current.getVoices();
    const preferredVoice = voices.find(v => v.name.includes('Google US English') || v.name.includes('Samantha') || v.lang === 'en-US');
    if (preferredVoice) utterance.voice = preferredVoice;
    synthRef.current.speak(utterance);
  };

  // --- RAG Retrieval Logic ---
  const retrieveContext = async (query: string): Promise<string> => {
    if (vectorStoreRef.current.length === 0) return "";

    try {
      // 1. Embed the query
      const queryVector = await getEmbedding(query);
      if (queryVector.length === 0) return "";

      // 2. Retrieve using refined scoring logic
      const context = retrieveRelevantChunks(queryVector, vectorStoreRef.current);

      if (context) {
        console.log("RAG Context Injected");
      }
      return context;
    } catch (e) {
      console.error("RAG Retrieval Failed", e);
    }
    return "";
  };

  // --- Interaction Logic (Text Mode) ---
  const handleTextSubmit = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const textToSend = overrideText || inputValue;
    if (!textToSend.trim()) return;

    if (!overrideText) setInputValue('');
    addMessage(Sender.USER, textToSend);

    if (tokenMissing) return;

    // Command: /code
    if (textToSend.toLowerCase() === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "Code Editor opened.");
        return;
    }

    // Start UI Loading State
    setIsLoading(true);

    const history = messages.slice(-6).filter(m => !m.imageData).map(m => `${m.sender}: ${m.text}`).join('\n');

    try {
        // RAG STEP: Retrieve relevant context
        let retrievedContext = "";
        if (vectorStoreRef.current.length > 0) {
            retrievedContext = await retrieveContext(textToSend);
        }

        // Start Streaming Response
        const stream = await streamInterviewQuestion(
            history + `\nUSER: ${textToSend}`,
            persona,
            resumeData,
            retrievedContext
        );

        // Create placeholder message to stream into
        const msgId = addMessage(Sender.AI, "");
        // Stop loading spinner immediately as we have the stream
        setIsLoading(false);

        let accumulatedText = "";
        let finalGrounding: GroundingChunk[] = [];
        let hasCheckedCoding = false;

        for await (const chunk of stream) {
           const text = chunk.text; // Access property directly
           if (text) {
               accumulatedText += text;
           }

           // Aggregate Grounding
           if (chunk.groundingMetadata?.groundingChunks) {
                const chunks = chunk.groundingMetadata.groundingChunks;
                // Simple de-duplication could happen here, but append for now
                chunks.forEach((c: any) => {
                    if (c.web) finalGrounding.push({ web: c.web });
                });
           }

           // Process Text for Display (Hide Tags in Real-time)
           let displayText = accumulatedText;

           // Check coding tag
           if (displayText.includes("[[CODING_CHALLENGE]]")) {
               if (!hasCheckedCoding) {
                   setShowCodeEditor(true);
                   addMessage(Sender.SYSTEM, "Opening Code Playground...");
                   hasCheckedCoding = true;
               }
               displayText = displayText.replace("[[CODING_CHALLENGE]]", "").trimStart();
           }

           // Hide visualize tag while streaming
           displayText = displayText.replace(/\[\[VISUALIZE:.*?\]\]/g, "");

           // Update message in place
           setMessages(prev => prev.map(m => 
               m.id === msgId ? { ...m, text: displayText, grounding: finalGrounding } : m
           ));
        }

        // Post-stream processing
        // 1. Check for visualize tag in raw text to trigger image gen
        const vizMatch = accumulatedText.match(/\[\[VISUALIZE:\s*(.*?)\]\]/);
        if (vizMatch) {
            const prompt = vizMatch[1];
            addMessage(Sender.SYSTEM, "Generating visualization...");
            generateImage(prompt).then(url => {
                setMessages(prev => prev.map(m => m.id === msgId ? { ...m, imageData: url } : m));
            }).catch(err => console.error("Auto image generation failed", err));
        }

        // 2. Play TTS for the final clean text
        const cleanFinalText = accumulatedText.replace(/\[\[.*?\]\]/g, "").trim();
        playTTS(cleanFinalText);

    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Error: ${e.message}`);
    }
  };

  // --- Code Review Logic ---
  const handleCodeReviewRequest = async (code: string, language: string) => {
    if (!code || !language) return;

    addMessage(Sender.USER, `Here is my ${language} solution:\n\n\`\`\`${language}\n${code}\n\`\`\``);
    setIsLoading(true);
    addMessage(Sender.SYSTEM, "Analyzing code logic and style...");

    try {
        const feedback = await reviewCodeWithAI(language, code);
        setIsLoading(false);
        addMessage(Sender.AI, feedback);
        playTTS(feedback);
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Review Error: ${e.message}`);
    }
  };

  // --- Live API Management ---

  const stopAudioPlayback = () => {
      audioSourcesRef.current.forEach(source => {
          try { source.stop(); } catch (e) {}
      });
      audioSourcesRef.current = [];
  };

  const handleStopSpeaking = () => {
    if (synthRef.current) {
        synthRef.current.cancel();
    }
    stopAudioPlayback();
  };

  const toggleVoiceMode = async () => {
    if (mode === InterviewMode.VOICE) {
        // --- STOP VOICE ---
        setMode(InterviewMode.TEXT);
        setIsLiveConnected(false);

        if (liveSessionRef.current) {
            liveSessionRef.current.disconnect();
            liveSessionRef.current = null;
        }

        if (processorRef.current) {
            processorRef.current.disconnect();
            processorRef.current = null;
        }
        if (sourceRef.current) {
            sourceRef.current.disconnect();
            sourceRef.current = null;
        }
        if (mediaStreamRef.current) {
            mediaStreamRef.current.getTracks().forEach(track => track.stop());
            mediaStreamRef.current = null;
        }

        stopAudioPlayback();
        if (audioContextRef.current) {
            await audioContextRef.current.close();
            audioContextRef.current = null;
        }

        addMessage(Sender.SYSTEM, "Voice Session Ended.");

    } else {
        // --- START VOICE ---
        try {
            setMode(InterviewMode.VOICE);
            currentTurnTextRef.current = ""; // Reset accumulator

            // 1. Setup Audio Context (Input: 16k preferred, Output: 24k)
            const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
            const ctx = new AudioContextClass({ sampleRate: 24000 }); // Output rate
            audioContextRef.current = ctx;
            nextStartTimeRef.current = ctx.currentTime;

            // 2. Get Microphone Stream
            const stream = await navigator.mediaDevices.getUserMedia({ audio: { channelCount: 1 } });
            mediaStreamRef.current = stream;

            addMessage(Sender.SYSTEM, "Connecting to Gemini Live...");

            // 3. Connect to Gemini Live
            const session = await connectToLiveSession({
                persona,
                onOpen: () => {
                    setIsLiveConnected(true);
                    addMessage(Sender.SYSTEM, "Connected! Start speaking.");
                },
                onAudioData: (base64) => {
                    // Decode and Schedule Playback
                    if (!audioContextRef.current) return;
                    try {
                        const buffer = decodeAudioData(base64, audioContextRef.current, 24000);
                        const source = audioContextRef.current.createBufferSource();
                        source.buffer = buffer;
                        source.connect(audioContextRef.current.destination);

                        // Schedule
                        const now = audioContextRef.current.currentTime;
                        const startTime = Math.max(now, nextStartTimeRef.current);
                        source.start(startTime);
                        nextStartTimeRef.current = startTime + buffer.duration;

                        // Cleanup on end
                        source.onended = () => {
                           const index = audioSourcesRef.current.indexOf(source);
                           if (index > -1) audioSourcesRef.current.splice(index, 1);
                        };
                        audioSourcesRef.current.push(source);

                    } catch (e) {
                        console.error("Audio Decode Error", e);
                    }
                },
                onTranscript: (text, isUser, isFinal) => {
                    if (isUser) {
                        updateLastMessage(text, Sender.USER);
                    } else {
                        currentTurnTextRef.current += text;
                        updateLastMessage(currentTurnTextRef.current, Sender.AI);
                        if (isFinal) {
                            currentTurnTextRef.current = "";
                        }
                    }
                },
                onInterrupted: () => {
                    stopAudioPlayback();
                    nextStartTimeRef.current = audioContextRef.current?.currentTime || 0;
                    currentTurnTextRef.current = ""; 
                    addMessage(Sender.SYSTEM, "[Interrupted]");
                },
                onClose: () => {
                    setIsLiveConnected(false);
                },
                onError: (err) => {
                    console.error(err);
                    addMessage(Sender.SYSTEM, "Live API Error. Disconnecting.");
                    toggleVoiceMode(); // Safe cleanup
                }
            });

            liveSessionRef.current = session;

            // 4. Setup Input Processing (Recorder)
            const source = ctx.createMediaStreamSource(stream);
            sourceRef.current = source;

            const bufferSize = 4096;
            const processor = ctx.createScriptProcessor(bufferSize, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
                if (!liveSessionRef.current) return; 
                const inputData = e.inputBuffer.getChannelData(0);
                const downsampled = downsampleBuffer(inputData, ctx.sampleRate, 16000);
                session.sendAudioChunk(downsampled);
            };

            source.connect(processor);
            processor.connect(ctx.destination); 

        } catch (e: any) {
            console.error(e);
            addMessage(Sender.SYSTEM, "Failed to start voice session: " + e.message);
            setMode(InterviewMode.TEXT);
        }
    }
  };

  // --- File Upload Helpers ---
  const readFileText = async (file: File): Promise<string> => {
      if (file.type === 'application/pdf') {
             const arrayBuffer = await file.arrayBuffer();
             const pdfjs = pdfjsLib as any;
             const getDocument = pdfjs.getDocument || pdfjs.default?.getDocument || (window as any).pdfjsLib?.getDocument;

             if (!getDocument) throw new Error("PDF.js library not properly loaded.");

             const loadingTask = getDocument({ data: arrayBuffer });
             const pdf = await loadingTask.promise;

             let fullText = "";
             for (let i = 1; i <= pdf.numPages; i++) {
                 const page = await pdf.getPage(i);
                 const textContent = await page.getTextContent();
                 const pageText = textContent.items.map((item: any) => item.str).join(' ');
                 fullText += pageText + "\n";
             }
             return fullText;
        } else {
             return await new Promise<string>((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = () => resolve(reader.result as string);
                reader.onerror = reject;
                reader.readAsText(file);
             });
        }
  };

  // --- Resume Upload ---
  const handleResumeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    addMessage(Sender.SYSTEM, `Reading resume: ${file.name}...`);
    setIsLoading(true);

    try {
        const text = await readFileText(file);
        const extractedData = { data: text, mimeType: 'text/plain' };
        setResumeData(extractedData);
        addMessage(Sender.USER, "I've uploaded my resume. Please review it and ask me a relevant technical question.");

        // Immediately trigger AI analysis via Streaming
        const history = messages.slice(-6).filter(m => !m.imageData).map(m => `${m.sender}: ${m.text}`).join('\n');

        try {
            const stream = await streamInterviewQuestion(
                history + `\nUSER: I've uploaded my resume. Please review it and ask me a relevant technical question based on my experience.`,
                persona,
                extractedData
            );

            const msgId = addMessage(Sender.AI, "");
            setIsLoading(false);

            let accumulatedText = "";
            let hasCheckedCoding = false;
            let finalGrounding: GroundingChunk[] = [];

            for await (const chunk of stream) {
                const text = chunk.text;
                if (text) accumulatedText += text;

                if (chunk.groundingMetadata?.groundingChunks) {
                    const chunks = chunk.groundingMetadata.groundingChunks;
                    chunks.forEach((c: any) => { if (c.web) finalGrounding.push({ web: c.web }); });
                }

                let displayText = accumulatedText;
                if (displayText.includes("[[CODING_CHALLENGE]]")) {
                   if (!hasCheckedCoding) {
                       setShowCodeEditor(true);
                       addMessage(Sender.SYSTEM, "Opening Code Playground...");
                       hasCheckedCoding = true;
                   }
                   displayText = displayText.replace("[[CODING_CHALLENGE]]", "").trimStart();
                }
                displayText = displayText.replace(/\[\[VISUALIZE:.*?\]\]/g, "");

                setMessages(prev => prev.map(m => 
                   m.id === msgId ? { ...m, text: displayText, grounding: finalGrounding } : m
                ));
            }

            const cleanFinalText = accumulatedText.replace(/\[\[.*?\]\]/g, "").trim();
            playTTS(cleanFinalText);

        } catch (apiErr: any) {
             setIsLoading(false);
             addMessage(Sender.SYSTEM, `Analysis Error: ${apiErr.message}`);
        }

    } catch (err: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Failed to read file: ${err.message}`);
    } finally {
        if (resumeInputRef.current) resumeInputRef.current.value = '';
    }
  };

  // --- Knowledge Base Upload (RAG) ---
  const handleKBUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    addMessage(Sender.SYSTEM, `Ingesting Knowledge Base: ${file.name}...`);
    setIsLoading(true);

    try {
      // 1. Read File
      const text = await readFileText(file);

      // 2. Chunk Text (Optimized Strategy)
      // Use larger chunks (2000 chars) to reduce API calls and better overlap (200)
      const chunks = chunkText(text, 2000, 200);
      addMessage(Sender.SYSTEM, `Optimized splitting: ${chunks.length} chunks. Generating embeddings...`);

      // 3. Generate Embeddings (Batch Processing)
      const newItems: VectorStoreItem[] = [];
      const vectors = await getBatchEmbeddings(chunks);

      chunks.forEach((chunk, i) => {
          if (vectors[i] && vectors[i].length > 0) {
              newItems.push({ text: chunk, vector: vectors[i] });
          }
      });

      // 4. Update Vector Store
      vectorStoreRef.current = [...vectorStoreRef.current, ...newItems];
      setHasKnowledgeBase(true);
      setIsLoading(false);

      addMessage(Sender.SYSTEM, `RAG Knowledge Base Active. (${vectorStoreRef.current.length} total vectors).`);

    } catch (err: any) {
      setIsLoading(false);
      addMessage(Sender.SYSTEM, `Failed to process Knowledge Base: ${err.message}`);
    } finally {
      if (kbInputRef.current) kbInputRef.current.value = '';
    }
  };

  return (
    <div className="flex flex-col h-[100dvh] bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono">
      {/* Header */}
      <header className="bg-[#161b22] border-b border-[#30363d] p-2 md:p-4 flex justify-between items-center shadow-md z-10 shrink-0">
        <div className="flex items-center gap-2 md:gap-3">
            <div className={`w-2 h-2 md:w-3 md:h-3 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
            <h1 className="font-bold text-lg tracking-tight hidden md:block">DEV_INTERVIEW_OS <span className="text-xs font-normal text-gray-500">v3.0</span></h1>
            <h1 className="font-bold text-sm tracking-tight md:hidden">DEV_AI</h1>
        </div>
        <div className="flex items-center gap-1.5 md:gap-4 text-xs">
            {mode === InterviewMode.VOICE && <div className="scale-75 md:scale-100 origin-right"><AudioVisualizer isActive={isLiveConnected} /></div>}

            {hasKnowledgeBase && (
               <div className="flex items-center gap-1 text-blue-400 bg-blue-900/20 px-2 py-1 rounded border border-blue-900/50">
                    <span>📚</span>
                    <span className="hidden md:inline">RAG ACTIVE</span>
               </div>
            )}

            {resumeData && (
                <div className="flex items-center gap-1 text-green-400 bg-green-900/20 px-2 py-1 rounded border border-green-900/50">
                    <span>📄</span>
                    <span className="hidden md:inline">RESUME</span>
                </div>
            )}

            {/* Persona Switcher */}
            <div className="flex rounded border border-[#30363d] overflow-hidden">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    disabled={mode === InterviewMode.VOICE}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.INTERVIEWER ? 'bg-orange-900 text-orange-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'} ${mode === InterviewMode.VOICE ? 'opacity-50 cursor-not-allowed' : ''}`}
                    title="Interviewer Persona"
                >
                    <span className="md:hidden">INT</span>
                    <span className="hidden md:inline">INTERVIEWER</span>
                </button>
                <div className="w-[1px] bg-[#30363d]"></div>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    disabled={mode === InterviewMode.VOICE}
                    className={`px-2 py-1 md:px-3 transition-colors ${persona === Persona.TUTOR ? 'bg-blue-900 text-blue-200' : 'bg-[#161b22] text-gray-500 hover:bg-[#30363d]'} ${mode === InterviewMode.VOICE ? 'opacity-50 cursor-not-allowed' : ''}`}
                    title="Tutor Persona"
                >
                    <span className="md:hidden">TUT</span>
                    <span className="hidden md:inline">TUTOR</span>
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-2 py-1 md:px-3 rounded border transition-colors ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white' : 'border-gray-700 text-gray-400 hover:border-gray-500'}`}
            >
                {showCodeEditor ? 'HIDE' : 'CODE'}
            </button>

            <span className={`px-2 py-1 rounded text-white font-bold transition-all hidden sm:block ${mode === InterviewMode.VOICE ? 'bg-red-900/80 animate-pulse' : 'bg-[#30363d]'}`}>
                {mode === InterviewMode.VOICE ? 'LIVE AUDIO' : mode}
            </span>
        </div>
      </header>

      {/* Main Content */}
      <div className="flex-1 flex overflow-hidden relative">
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'hidden md:flex md:w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-2 md:p-4 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:16px_16px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                <div className="py-2 text-cyan-500 animate-pulse font-mono text-sm">
                    &gt; Thinking...
                </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-3 md:p-4 shrink-0">
                <div className="w-full flex gap-2 md:gap-3 items-center">
                    <span className="text-green-500 font-bold select-none">{">"}</span>

                    <form onSubmit={(e) => handleTextSubmit(e)} className="flex-1 min-w-0">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={
                                mode === InterviewMode.VOICE ? "Voice Active..." : 
                                tokenMissing ? "API_KEY MISSING" : 
                                "Type answer..." 
                            }
                            className={`w-full bg-transparent border-none outline-none font-mono text-sm md:text-base disabled:cursor-not-allowed text-[#c9d1d9] placeholder-gray-600`}
                            disabled={isLoading || tokenMissing || mode === InterviewMode.VOICE}
                            autoFocus
                        />
                    </form>

                    <div className="flex items-center gap-2">
                         {/* RAG Knowledge Upload */}
                         <button 
                            onClick={() => kbInputRef.current?.click()}
                            title="Upload Knowledge Base (PDF/Text) for RAG"
                            className={`p-1.5 md:p-2 hover:bg-[#30363d] rounded transition-colors ${hasKnowledgeBase ? 'text-blue-400' : 'text-gray-400 hover:text-white'}`}
                        >
                            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
