export const getEmbedding = async (text: string): Promise<number[]> => {
  if (apiKey === "missing_api_key") throw new Error("API Key missing");
  try {
    const response = await ai.models.embedContent({
      model: 'text-embedding-004',
      contents: { parts: [{ text }] }
    });

    // Fix: Handle potential type definition mismatch (embedding vs embeddings)
    const result = (response as any).embedding || (response as any).embeddings?.[0];
    return result?.values || [];
  } catch (e: any) {
    console.error("Embedding Error", e);
    return [];
  }
};

export const getBatchEmbeddings = async (texts: string[]): Promise<number[][]> => {
  if (apiKey === "missing_api_key") throw new Error("API Key missing");

  // SDK v1.35.0 does not expose batchEmbedContents cleanly.
  // We implement a concurrent worker pool to process embeddings in parallel.
  // Chrome allows ~6 concurrent connections per domain.
  const MAX_CONCURRENCY = 6;
  const results: number[][] = new Array(texts.length);

  // Helper to process a single item
  const processItem = async (text: string, index: number) => {
      try {
          const response = await ai.models.embedContent({
              model: 'text-embedding-004',
              contents: { parts: [{ text }] }
          });
          const result = (response as any).embedding || (response as any).embeddings?.[0];
          results[index] = result?.values || [];
      } catch (e) {
          console.warn(`Embedding failed at index ${index}`, e);
          results[index] = [];
      }
  };

  // Queue-based worker execution
  const queue = texts.map((text, index) => ({ text, index }));

  const worker = async () => {
      while (queue.length > 0) {
          const item = queue.shift();
          if (item) {
              await processItem(item.text, item.index);
          }
      }
  };

  const workers = Array(Math.min(texts.length, MAX_CONCURRENCY))
      .fill(null)
      .map(() => worker());

  await Promise.all(workers);

  return results;
};

