export const streamInterviewQuestion = async (
  history: string, 
  persona: Persona,
  resume?: ResumeData,
  ragContext?: string
) => {

  if (apiKey === "missing_api_key") {
      throw new Error("API Key is missing. Please configure it in your deployment settings.");
  }

  const baseInstruction = persona === Persona.TUTOR 
    ? "You are an expert AI Coding Tutor. Explain concepts clearly, provide code snippets, and be encouraging."
    : `You are a strict Senior Technical Interviewer. 
1. Ask one distinct question at a time.
2. If a resume is provided, prioritize questions about it.
3. For coding problems, provide Title, Description, Examples, and Constraints.
4. Do not give full solutions.`;

  // We use special tags instead of JSON to allow for slick text streaming
  let systemInstruction = `${baseInstruction}

  RESPONSE FORMATTING RULES:
  1. Output strictly plain text (Markdown supported). Do NOT output JSON.
  2. If the question requires the user to write code (e.g. "Write a function..."), start your response with "[[CODING_CHALLENGE]]" (without quotes).
  3. If a visual diagram or image would explain the concept better, append "[[VISUALIZE: <image_description>]]" at the very end of your response.
