import React, { useState, useEffect, useRef } from 'react';
import { executeCode } from '../services/compilerService';
import { collabService } from '../services/collaborationService';
import { CollabMessage, Peer } from '../types';

const LANGUAGES = {
  javascript: {
    name: 'JavaScript (Local)',
    snippet: `// Write your solution here\n\nfunction solution() {\n  console.log("Hello from JavaScript!");\n}\n\nsolution();`
  },
  python: {
    name: 'Python 3',
    snippet: `# Write your solution here\n\ndef solution():\n    print("Hello from Python!")\n\nsolution()`
  },
  typescript: {
    name: 'TypeScript',
    snippet: `// Write your solution here\n\nconst solution = (): void => {\n  console.log("Hello from TypeScript!");\n};\n\nsolution();`
  },
  java: {
    name: 'Java',
    snippet: `public class Main {\n    public static void main(String[] args) {\n        System.out.println("Hello from Java!");\n    }\n}`
  },
  cpp: {
    name: 'C++',
    snippet: `#include <iostream>\n\nint main() {\n    std::cout << "Hello from C++!" << std::endl;\n    return 0;\n}`
  },
  go: {
    name: 'Go',
    snippet: `package main\n\nimport "fmt"\n\nfunc main() {\n    fmt.Println("Hello from Go!")\n}`
  },
  rust: {
    name: 'Rust',
    snippet: `fn main() {\n    println!("Hello from Rust!");\n}`
  },
  sql: {
    name: 'SQL',
    snippet: `-- Example Query\nSELECT 'Hello from SQL' as message;`
  }
};

type LanguageKey = keyof typeof LANGUAGES;

interface RemoteCursor {
  start: number;
  end: number;
  lastUpdate: number;
}

interface CodeEditorProps {
    onReviewRequest: (code: string, language: string) => Promise<void>;
}

export const CodeEditor: React.FC<CodeEditorProps> = ({ onReviewRequest }) => {
  const [language, setLanguage] = useState<LanguageKey>('javascript');
  const [code, setCode] = useState<string>(LANGUAGES.javascript.snippet);
  const [output, setOutput] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);

  // UI States
  const [isRunning, setIsRunning] = useState(false);
  const [isReviewing, setIsReviewing] = useState(false);
  const [isCollabActive, setIsCollabActive] = useState(false);
  const [peers, setPeers] = useState<Peer[]>([]);
  const [remoteCursors, setRemoteCursors] = useState<Map<string, RemoteCursor>>(new Map());
  const [isOutputCollapsed, setIsOutputCollapsed] = useState(false);

  // Refs for tracking cursor during remote updates
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const lastLocalUpdate = useRef<number>(0);

  // --- Collaboration Hook ---
  useEffect(() => {
    // Subscribe to Peer Updates
    collabService.subscribeToPeers((activePeers) => {
      setPeers(activePeers);
    });

    // Subscribe to Data Updates
    const handleRemoteMessage = (msg: CollabMessage) => {
      if (!isCollabActive) return;

      if (msg.type === 'CODE_UPDATE') {
        const { code: newCode, language: newLang } = msg.payload;

        // Prevent echo if we just sent this (timestamp check could also work)
        if (newCode !== code) {
          // Preserve cursor position
          const textArea = textareaRef.current;
          const currentPos = textArea?.selectionStart || 0;

          setCode(newCode);
          if (newLang !== language) setLanguage(newLang);

          // Restore cursor on next tick
          requestAnimationFrame(() => {
            if (textArea) {
              textArea.selectionStart = currentPos;
              textArea.selectionEnd = currentPos;
            }
          });
        }
      } 
      else if (msg.type === 'LANGUAGE_UPDATE') {
        setLanguage(msg.payload.language);
      }
      else if (msg.type === 'CURSOR_UPDATE') {
        setRemoteCursors(prev => {
            const next = new Map(prev);
            next.set(msg.senderId, {
                start: msg.payload.selectionStart,
                end: msg.payload.selectionEnd,
                lastUpdate: Date.now()
            });
            return next;
        });
      }
    };

    collabService.subscribe(handleRemoteMessage);

    return () => {
      collabService.unsubscribe(handleRemoteMessage);
    };
  }, [isCollabActive, code, language]);


  // --- Handlers ---

  const handleLanguageChange = (newLang: LanguageKey) => {
    setLanguage(newLang);
    const newCode = LANGUAGES[newLang].snippet;
    setCode(newCode);
    setOutput([]);
    setError(null);

    if (isCollabActive) {
      collabService.broadcast('CODE_UPDATE', { code: newCode, language: newLang });
    }
  };

  const handleCodeChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const newCode = e.target.value;
    setCode(newCode);
    lastLocalUpdate.current = Date.now();

    if (isCollabActive) {
      collabService.broadcast('CODE_UPDATE', { code: newCode, language });
    }
  };

  const handleCursorActivity = () => {
    if (!isCollabActive) return;
    const textArea = textareaRef.current;
    if (textArea) {
        collabService.broadcast('CURSOR_UPDATE', { 
            selectionStart: textArea.selectionStart, 
            selectionEnd: textArea.selectionEnd 
        });
    }
  };

  const toggleCollab = () => {
    setIsCollabActive(!isCollabActive);
    // Broadcast current state when enabling
    if (!isCollabActive) {
      collabService.broadcast('CODE_UPDATE', { code, language });
    }
  };

  const handleReview = async () => {
    setOutput([]);
    setError(null);
    setIsReviewing(true);
    setIsOutputCollapsed(false); // Auto-expand

    // Notify locally
    setOutput(["Sending code to AI Interviewer for review...", "Check the main chat timeline for feedback."]);

    try {
        // Delegate to parent (App.tsx)
        await onReviewRequest(code, LANGUAGES[language].name);
    } catch (e: any) {
        setError("Failed to send code review request: " + e.message);
    } finally {
        setIsReviewing(false);
    }
  };

  const runCode = async () => {
    setOutput([]);
    setError(null);
    setIsRunning(true);
    setIsOutputCollapsed(false); // Auto-expand

    // Keep JS Local for speed/interaction
    if (language === 'javascript') {
        runLocalJs();
        return;
    }

    try {
        const result = await executeCode(language, code);

        if (result.error) {
            setError(result.error);
        } else {
            setOutput(result.output.split('\n'));
        }
    } catch (e: any) {
        setError(`Execution failed: ${e.message}`);
    } finally {
        setIsRunning(false);
    }
  };

  const runLocalJs = () => {
    const logs: string[] = [];
    const originalLog = console.log;
    const originalError = console.error;
    const originalWarn = console.warn;

    const mockLog = (...args: any[]) => {
      logs.push(args.map(a => {
        try {
            return typeof a === 'object' ? JSON.stringify(a) : String(a);
        } catch (e) {
            return '[Circular]';
        }
      }).join(' '));
    };

    console.log = mockLog;
    console.error = mockLog;
    console.warn = mockLog;

    try {
        // eslint-disable-next-line no-new-func
        new Function(code)();
    } catch (err: any) {
        setError(err.toString());
    } finally {
        console.log = originalLog;
        console.error = originalError;
        console.warn = originalWarn;
        setOutput(logs);
        setIsRunning(false);
    }
  };

  const getLineCol = (index: number) => {
    const prefix = code.substring(0, index);
    const lines = prefix.split('\n');
    return { line: lines.length, col: lines[lines.length - 1].length + 1 };
  };

  return (
    <div className="flex flex-col h-full border-l border-[#30363d] bg-[#0d1117]">
      {/* Toolbar */}
      <div className="flex flex-wrap items-center justify-between px-2 md:px-4 py-2 bg-[#161b22] border-b border-[#30363d] gap-2">
        <div className="flex items-center gap-2">
            <span className="text-xs font-bold text-gray-400 hidden sm:inline">PLAYGROUND</span>
            <select 
                value={language}
                onChange={(e) => handleLanguageChange(e.target.value as LanguageKey)}
                className="bg-[#0d1117] text-xs text-gray-300 border border-[#30363d] rounded px-2 py-1 outline-none focus:border-blue-500 max-w-[120px] sm:max-w-none"
            >
                {Object.entries(LANGUAGES).map(([key, config]) => (
                    <option key={key} value={key}>{config.name}</option>
                ))}
            </select>
        </div>

        {/* Right Actions */}
        <div className="flex items-center gap-2">
            {/* Collaboration Toggle */}
            <div className={`flex items-center gap-2 px-2 py-1 rounded border border-[#30363d] transition-colors ${isCollabActive ? 'bg-[#1f2937]' : ''}`}>
                <div 
                  className={`w-2 h-2 rounded-full ${isCollabActive ? 'bg-green-500 animate-pulse' : 'bg-gray-600'}`} 
                />
                <button 
                  onClick={toggleCollab}
                  className="text-[10px] font-bold text-gray-300 hover:text-white uppercase tracking-wider whitespace-nowrap"
                >
                  {isCollabActive ? 'LIVE' : 'OFFLINE'}
                </button>

                {isCollabActive && peers.length > 0 && (
                   <div className="flex -space-x-1 ml-1">
                      {peers.map(peer => (
                        <div 
                          key={peer.id} 
                          className="w-4 h-4 rounded-full border border-[#161b22]" 
                          style={{backgroundColor: peer.color}}
                          title={peer.username}
                        />
                      ))}
                      <span className="text-[10px] text-gray-400 ml-2">+{peers.length}</span>
                   </div>
                )}
            </div>

            {/* Toggle Output Button */}
            <button 
                onClick={() => setIsOutputCollapsed(!isOutputCollapsed)}
                className="hidden sm:block px-3 py-1 text-xs text-gray-400 hover:text-white transition-colors"
                title={isOutputCollapsed ? "Expand Output" : "Collapse Output"}
            >
                {isOutputCollapsed ? 'SHOW OUTPUT' : 'HIDE OUTPUT'}
            </button>

            <button 
                onClick={() => { setOutput([]); setError(null); }}
                className="hidden sm:block px-3 py-1 text-xs text-gray-400 hover:text-white transition-colors"
            >
                CLEAR
            </button>
            <button
                onClick={handleReview}
                disabled={isRunning || isReviewing}
                className={`px-3 py-1 text-white text-xs rounded font-mono transition-colors flex items-center gap-1 ${isReviewing ? 'bg-purple-800 cursor-wait' : 'bg-purple-600 hover:bg-purple-700'}`}
                title="Review Code"
            >
                {isReviewing ? '...' : <><span className="sm:hidden">🔍</span><span className="hidden sm:inline">🔍 REVIEW</span></>}
            </button>
            <button 
                onClick={runCode}
                disabled={isRunning || isReviewing}
                className={`px-3 py-1 text-white text-xs rounded font-mono transition-colors flex items-center gap-1 ${isRunning ? 'bg-gray-600 cursor-wait' : 'bg-green-600 hover:bg-green-700'}`}
            >
                {isRunning ? '...' : <><span className="sm:hidden">▶</span><span className="hidden sm:inline">▶ RUN</span></>}
            </button>
        </div>
      </div>

      {/* Editor Area */}
      <div className="flex-1 relative group">
         <textarea
            ref={textareaRef}
            value={code}
            onChange={(e) => {
                handleCodeChange(e);
                handleCursorActivity();
            }}
            onSelect={handleCursorActivity}
            onClick={handleCursorActivity}
            onKeyUp={handleCursorActivity}
            className="w-full h-full bg-[#0d1117] text-[#c9d1d9] p-2 md:p-4 font-mono text-xs md:text-sm resize-none focus:outline-none leading-relaxed"
            spellCheck={false}
            placeholder="// Type code here..."
        />

        {/* Remote Cursors Overlay (Status Based) */}
        {isCollabActive && peers.length > 0 && (
            <div className="absolute top-2 right-4 flex flex-col items-end pointer-events-none gap-1">
                {peers.map(peer => {
                    const cursor = remoteCursors.get(peer.id);
                    if (!cursor) return null;
                    const { line, col } = getLineCol(cursor.start);
                    return (
                        <div key={peer.id} className="text-[10px] bg-[#161b22]/90 px-2 py-0.5 rounded border border-[#30363d] flex items-center gap-2 animate-fadeIn">
                             <div className="w-2 h-2 rounded-full" style={{backgroundColor: peer.color}} />
                             <span className="text-gray-400">{peer.username}</span>
                             <span className="text-gray-500 font-mono">Ln {line}, Col {col}</span>
                        </div>
                    );
                })}
                <div className="text-[10px] text-green-500 opacity-50 mt-1">● Live Sync Active</div>
            </div>
        )}
      </div>

      {/* Output Area - Responsive Height */}
      <div className={`${isOutputCollapsed ? 'h-8' : 'h-[30%] md:h-1/3'} transition-[height] duration-300 ease-in-out border-t border-[#30363d] bg-[#010409] flex flex-col`}>
        <div 
            className="px-4 py-1 text-[10px] text-gray-500 border-b border-[#30363d] bg-[#161b22] flex justify-between items-center cursor-pointer hover:bg-[#1f2937] select-none h-8"
            onClick={() => setIsOutputCollapsed(!isOutputCollapsed)}
            title={isOutputCollapsed ? "Expand Output" : "Collapse Output"}
        >
            <div className="flex items-center gap-2">
                <span className={`transform transition-transform duration-200 ${isOutputCollapsed ? '-rotate-90' : 'rotate-0'}`}>▼</span>
                <span>OUTPUT / REVIEW</span>
            </div>
            {language !== 'javascript' && isRunning && <span className="text-xs text-blue-400 opacity-70">Running via Piston Engine...</span>}
        </div>

        <div className={`flex-1 p-2 md:p-4 font-mono text-xs overflow-auto ${isOutputCollapsed ? 'hidden' : 'block'}`}>
          {output.map((line, i) => (
            <div key={i} className="text-gray-300 mb-1 border-b border-gray-800 pb-1 last:border-0 whitespace-pre-wrap">{line}</div>
          ))}
          {error && <div className="text-red-400 font-bold">{error}</div>}
          {!output.length && !error && <div className="text-gray-700 italic select-none">Run code to execute, or Review to analyze...</div>}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Message, Sender, GroundingChunk } from '../types';

interface TerminalMessageProps {
  message: Message;
  onPlayAudio: (text: string) => void;
}

export const TerminalMessage: React.FC<TerminalMessageProps> = ({ message, onPlayAudio }) => {
  const isUser = message.sender === Sender.USER;
  const isSystem = message.sender === Sender.SYSTEM;

  const renderGrounding = (chunks?: GroundingChunk[]) => {
    if (!chunks || chunks.length === 0) return null;
    return (
      <div className="mt-3 pt-2 border-t border-gray-700/50 text-[10px] grid gap-1 opacity-70">
        {chunks.map((chunk, i) => {
          if (chunk.web) {
            return (
              <a key={i} href={chunk.web.uri} target="_blank" rel="noreferrer" className="text-blue-400 hover:text-blue-300 hover:underline flex items-center gap-1 transition-colors">
                <span className="w-1 h-1 rounded-full bg-blue-500"></span>
                {chunk.web.title}
              </a>
            );
          }
          return null;
        })}
      </div>
    );
  };

  // Professional System Message (Centered Status Line)
  if (isSystem) {
    return (
      <div className="py-2 flex justify-center animate-slide-up">
        <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-[#161b22] border border-[#30363d] text-xs text-gray-500 font-mono shadow-sm">
          <span className="w-1.5 h-1.5 rounded-full bg-yellow-500/50"></span>
          <span className="tracking-wide uppercase">{message.text}</span>
        </div>
      </div>
    );
  }

  return (
    <div className={`py-3 group animate-slide-up flex flex-col ${isUser ? 'items-end' : 'items-start'}`}>
      <div 
        className={`
          max-w-[85%] md:max-w-[75%] rounded-lg p-3 md:p-4 shadow-sm border
          ${isUser 
            ? 'bg-[#1f242d]/80 border-[#30363d] text-gray-200' 
            : 'bg-[#161b22]/90 border-[#30363d] text-gray-300'
          }
        `}
      >
        {/* Header: Sender & Time */}
        <div className="flex items-center gap-2 mb-2 pb-2 border-b border-white/5 text-[10px] uppercase tracking-wider font-semibold opacity-70 select-none">
          <span className={`flex items-center gap-1.5 ${isUser ? 'text-cyan-400' : 'text-emerald-400'}`}>
            <span className={`w-2 h-2 rounded-sm ${isUser ? 'bg-cyan-500' : 'bg-emerald-500'}`}></span>
            {isUser ? 'Candidate' : 'Interviewer AI'}
          </span>
          <span className="text-gray-600">|</span>
          <span className="text-gray-500 font-mono">{new Date(message.timestamp).toLocaleTimeString([], { hour12: false })}</span>

          {message.isThinking && (
             <span className="ml-auto flex items-center gap-1 text-purple-400 bg-purple-900/20 px-1.5 py-0.5 rounded text-[9px]">
               <span className="animate-pulse">●</span> REASONING
             </span>
          )}
        </div>

        {/* Content */}
        <div className={`whitespace-pre-wrap leading-relaxed font-mono text-sm ${isUser ? 'text-gray-100' : 'text-[#c9d1d9]'}`}>
          {message.text}
        </div>

        {/* Render Generated Image */}
        {message.imageData && (
          <div className="mt-3 rounded-md overflow-hidden bg-black/40 border border-[#30363d] group/image transition-colors hover:border-gray-600">
            <div className="relative">
                <img 
                src={message.imageData} 
                alt="Generated Visualization" 
                className="w-full h-auto max-h-[300px] object-contain bg-[url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI4IiBoZWlnaHQ9IjgiPgo8cmVjdCB3aWR0aD0iOCIgaGVpZ2h0PSI4IiBmaWxsPSIjMWExZDIxIj48L3JlY3Q+CjxwYXRoIGQ9Ik0wIDBMOCA4Wk04IDBMMCA4WiIgc3Ryb2tlPSIjMjIyIj48L3BhdGg+Cjwvc3ZnPg==')]"
                loading="lazy"
                />
                <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_20px_rgba(0,0,0,0.5)]"></div>
            </div>
            <div className="px-3 py-2 bg-[#0d1117] text-[10px] text-gray-500 flex justify-between items-center border-t border-[#30363d]">
                <span className="flex items-center gap-1"><span className="text-purple-400">◆</span> Generated Asset</span>
            </div>
          </div>
        )}

        {/* Action Buttons (Play TTS) */}
        {!isUser && !message.isThinking && message.text && (
            <div className="mt-3 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity duration-200">
                <button 
                    onClick={() => onPlayAudio(message.text)}
                    className="text-[10px] bg-[#0d1117] border border-[#30363d] rounded px-2 py-1 text-gray-500 hover:text-emerald-400 hover:border-emerald-500/50 transition-all flex items-center gap-1.5"
                >
                    <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" /></svg>
                    PLAY AUDIO
                </button>
            </div>
        )}

        {renderGrounding(message.grounding)}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import * as pdfjsLib from 'pdfjs-dist';
import { 
  generateInterviewQuestion, 
  generateImage,
  connectToLiveSession,
  reviewCodeWithAI,
  ResumeData
} from './services/geminiService';
import { downsampleBuffer, decodeAudioData } from './utils/audioUtils';
import { TerminalMessage } from './components/TerminalMessage';
import { AudioVisualizer } from './components/AudioVisualizer';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona } from './types';

// Web Speech API Types (Fallback/Legacy)
interface IWindow extends Window {
  webkitSpeechRecognition: any;
  SpeechRecognition: any;
}

const App: React.FC = () => {
  // State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showCodeEditor, setShowCodeEditor] = useState(false);
  const [tokenMissing, setTokenMissing] = useState(false);

  // Data State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);

  // Refs
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);
  const resumeInputRef = useRef<HTMLInputElement>(null);

  // Live API Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const liveSessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<AudioBufferSourceNode[]>([]);

  // Keep track of transcripts to merge them
  const currentTurnTextRef = useRef<string>("");

  // Initial Welcome & Config
  useEffect(() => {
    // Configure PDF Worker
    const pdfjs = pdfjsLib as any;
    const workerOptions = pdfjs.GlobalWorkerOptions || pdfjs.default?.GlobalWorkerOptions || (window as any).pdfjsLib?.GlobalWorkerOptions;

    if (workerOptions) {
        workerOptions.workerSrc = "https://unpkg.com/pdfjs-dist@3.11.174/build/pdf.worker.min.js";
    }

    // Check for Gemini API Key
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setTokenMissing(true);
        addMessage(Sender.SYSTEM, "Configuration Error: API_KEY is missing.");
    } else {
        // Professional Initialization Sequence
        setTimeout(() => addMessage(Sender.SYSTEM, "System Modules Loaded"), 500);
        setTimeout(() => addMessage(Sender.SYSTEM, "Connection Established"), 1000);
        setTimeout(() => addMessage(Sender.AI, "Hello. I am your AI Interviewer. I am ready to review your resume or start a coding session."), 1500);
    }

    return () => {
        // Cleanup Audio Context on unmount
        if (audioContextRef.current) audioContextRef.current.close();
    };
  }, []);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false, imageData?: string) => {
    const id = uuidv4();
    setMessages(prev => [...prev, {
      id,
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking,
      imageData
    }]);
    return id;
  };

  const updateLastMessage = (text: string, sender: Sender) => {
      setMessages(prev => {
          const last = prev[prev.length - 1];
          if (last && last.sender === sender) {
              return [
                  ...prev.slice(0, -1),
                  { ...last, text: text }
              ];
          } else {
              // Create new if sender doesn't match or no messages
              return [...prev, {
                  id: uuidv4(),
                  sender,
                  text,
                  timestamp: Date.now()
              }];
          }
      });
  };

  // --- Browser TTS (Fallback for Text Mode) ---
  const playTTS = (text: string) => {
    if (!synthRef.current || mode === InterviewMode.VOICE) return; // Don't use TTS in Live Mode

    synthRef.current.cancel();
    const cleanText = text.replace(/[*#`_]/g, '');
    const utterance = new SpeechSynthesisUtterance(cleanText);
    const voices = synthRef.current.getVoices();
    const preferredVoice = voices.find(v => v.name.includes('Google US English') || v.name.includes('Samantha') || v.lang === 'en-US');
    if (preferredVoice) utterance.voice = preferredVoice;
    synthRef.current.speak(utterance);
  };

  // --- Interaction Logic (Text Mode) ---
  const handleTextSubmit = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const textToSend = overrideText || inputValue;
    if (!textToSend.trim()) return;

    if (!overrideText) setInputValue('');
    addMessage(Sender.USER, textToSend);

    if (tokenMissing) return;

    // Command: /code
    if (textToSend.toLowerCase() === '/code') {
        setShowCodeEditor(true);
        addMessage(Sender.SYSTEM, "IDE Environment Active");
        return;
    }

    setIsLoading(true);

    const history = messages.slice(-6).filter(m => !m.imageData).map(m => `${m.sender}: ${m.text}`).join('\n');

    try {
        const response = await generateInterviewQuestion(
            history + `\nUSER: ${textToSend}`,
            persona,
            false,
            resumeData
        );

        setIsLoading(false);
        const msgId = addMessage(Sender.AI, response.text, response.grounding);
        playTTS(response.text);

        if (response.isCodingChallenge) {
          setShowCodeEditor(true);
          addMessage(Sender.SYSTEM, "Coding Challenge Detected: Opening Editor");
        }

        if (response.imagePrompt) {
            console.log("Generating visualization:", response.imagePrompt);
            generateImage(response.imagePrompt)
                .then(url => {
                    setMessages(prev => prev.map(m => 
                        m.id === msgId ? { ...m, imageData: url } : m
                    ));
                })
                .catch(err => console.error("Auto image generation failed", err));
        }
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Error: ${e.message}`);
    }
  };

  // --- Code Review Logic ---
  const handleCodeReviewRequest = async (code: string, language: string) => {
    if (!code || !language) return;

    // 1. Show user's request in chat
    addMessage(Sender.USER, `Submitted ${language} solution for review.`);

    // 2. Show thinking state
    setIsLoading(true);
    addMessage(Sender.SYSTEM, "Analyzing Algorithm Logic...");

    try {
        // 3. Call AI Service
        const feedback = await reviewCodeWithAI(language, code);

        // 4. Show AI Response
        setIsLoading(false);
        const msgId = addMessage(Sender.AI, feedback);
        playTTS(feedback);

    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Review Error: ${e.message}`);
    }
  };

  // --- Live API Management ---

  const stopAudioPlayback = () => {
      audioSourcesRef.current.forEach(source => {
          try { source.stop(); } catch (e) {}
      });
      audioSourcesRef.current = [];
  };

  const handleStopSpeaking = () => {
    if (synthRef.current) {
        synthRef.current.cancel();
    }
    stopAudioPlayback();
  };

  const toggleVoiceMode = async () => {
    if (mode === InterviewMode.VOICE) {
        // --- STOP VOICE ---
        setMode(InterviewMode.TEXT);
        setIsLiveConnected(false);

        if (liveSessionRef.current) {
            liveSessionRef.current.disconnect();
            liveSessionRef.current = null;
        }

        if (processorRef.current) {
            processorRef.current.disconnect();
            processorRef.current = null;
        }
        if (sourceRef.current) {
            sourceRef.current.disconnect();
            sourceRef.current = null;
        }
        if (mediaStreamRef.current) {
            mediaStreamRef.current.getTracks().forEach(track => track.stop());
            mediaStreamRef.current = null;
        }

        stopAudioPlayback();
        if (audioContextRef.current) {
            await audioContextRef.current.close();
            audioContextRef.current = null;
        }

        addMessage(Sender.SYSTEM, "Voice Session Terminated");

    } else {
        // --- START VOICE ---
        try {
            setMode(InterviewMode.VOICE);
            currentTurnTextRef.current = ""; // Reset accumulator

            // 1. Setup Audio Context (Input: 16k preferred, Output: 24k)
            const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
            const ctx = new AudioContextClass({ sampleRate: 24000 }); // Output rate
            audioContextRef.current = ctx;
            nextStartTimeRef.current = ctx.currentTime;

            // 2. Get Microphone Stream
            const stream = await navigator.mediaDevices.getUserMedia({ audio: { channelCount: 1 } });
            mediaStreamRef.current = stream;

            addMessage(Sender.SYSTEM, "Initializing Gemini Live Handshake...");

            // 3. Connect to Gemini Live
            const session = await connectToLiveSession({
                persona,
                onOpen: () => {
                    setIsLiveConnected(true);
                    addMessage(Sender.SYSTEM, "Live Audio Link Active");
                },
                onAudioData: (base64) => {
                    // Decode and Schedule Playback
                    if (!audioContextRef.current) return;
                    try {
                        const buffer = decodeAudioData(base64, audioContextRef.current, 24000);
                        const source = audioContextRef.current.createBufferSource();
                        source.buffer = buffer;
                        source.connect(audioContextRef.current.destination);

                        // Schedule
                        const now = audioContextRef.current.currentTime;
                        const startTime = Math.max(now, nextStartTimeRef.current);
                        source.start(startTime);
                        nextStartTimeRef.current = startTime + buffer.duration;

                        // Cleanup on end
                        source.onended = () => {
                           const index = audioSourcesRef.current.indexOf(source);
                           if (index > -1) audioSourcesRef.current.splice(index, 1);
                        };
                        audioSourcesRef.current.push(source);

                    } catch (e) {
                        console.error("Audio Decode Error", e);
                    }
                },
                onTranscript: (text, isUser, isFinal) => {
                    if (isUser) {
                        // Handle User Transcript
                        updateLastMessage(text, Sender.USER);
                    } else {
                        // AI Transcript
                        currentTurnTextRef.current += text;
                        updateLastMessage(currentTurnTextRef.current, Sender.AI);

                        if (isFinal) {
                            currentTurnTextRef.current = "";
                        }
                    }
                },
                onInterrupted: () => {
                    // User interrupted the AI
                    stopAudioPlayback();
                    nextStartTimeRef.current = audioContextRef.current?.currentTime || 0;
                    currentTurnTextRef.current = ""; // Reset accumulated text
                    addMessage(Sender.SYSTEM, "[Stream Interrupted]");
                },
                onClose: () => {
                    setIsLiveConnected(false);
                },
                onError: (err) => {
                    console.error(err);
                    addMessage(Sender.SYSTEM, "Connection Error. Terminating Session.");
                    toggleVoiceMode(); // Safe cleanup
                }
            });

            liveSessionRef.current = session;

            // 4. Setup Input Processing (Recorder)
            const source = ctx.createMediaStreamSource(stream);
            sourceRef.current = source;

            // Use ScriptProcessor for raw PCM access (AudioWorklet is cleaner but harder in single-file setup)
            const bufferSize = 4096;
            const processor = ctx.createScriptProcessor(bufferSize, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
                if (!liveSessionRef.current) return; // Check active session via ref
                const inputData = e.inputBuffer.getChannelData(0);

                // Downsample to 16kHz for Gemini
                const downsampled = downsampleBuffer(inputData, ctx.sampleRate, 16000);

                // Send to Gemini
                session.sendAudioChunk(downsampled);
            };

            source.connect(processor);
            processor.connect(ctx.destination); // Required for script processor to run, even if output is muted

        } catch (e: any) {
            console.error(e);
            addMessage(Sender.SYSTEM, "Microphone Access Denied or Unavailable: " + e.message);
            setMode(InterviewMode.TEXT);
        }
    }
  };

  // --- File Upload Helpers ---
  const readFileText = async (file: File): Promise<string> => {
      if (file.type === 'application/pdf') {
             const arrayBuffer = await file.arrayBuffer();
             const pdfjs = pdfjsLib as any;
             const getDocument = pdfjs.getDocument || pdfjs.default?.getDocument || (window as any).pdfjsLib?.getDocument;

             if (!getDocument) throw new Error("PDF.js library not properly loaded.");

             const loadingTask = getDocument({ data: arrayBuffer });
             const pdf = await loadingTask.promise;

             let fullText = "";
             for (let i = 1; i <= pdf.numPages; i++) {
                 const page = await pdf.getPage(i);
                 const textContent = await page.getTextContent();
                 const pageText = textContent.items.map((item: any) => item.str).join(' ');
                 fullText += pageText + "\n";
             }
             return fullText;
        } else {
             return await new Promise<string>((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = () => resolve(reader.result as string);
                reader.onerror = reject;
                reader.readAsText(file);
             });
        }
  };

  // --- Resume Upload ---
  const handleResumeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    addMessage(Sender.SYSTEM, `Processing File: ${file.name}`);
    setIsLoading(true);

    try {
        const text = await readFileText(file);
        const extractedData = { data: text, mimeType: 'text/plain' };
        setResumeData(extractedData);
        addMessage(Sender.USER, "I've uploaded my resume.");

        // Immediately trigger AI analysis
        const history = messages.slice(-6).filter(m => !m.imageData).map(m => `${m.sender}: ${m.text}`).join('\n');

        try {
            const response = await generateInterviewQuestion(
                history + `\nUSER: I've uploaded my resume. Please review it and ask me a relevant technical question based on my experience.`,
                persona,
                false,
                extractedData
            );

            setIsLoading(false);
            const msgId = addMessage(Sender.AI, response.text, response.grounding);
            playTTS(response.text);

            if (response.isCodingChallenge) {
                setShowCodeEditor(true);
                addMessage(Sender.SYSTEM, "Coding Challenge detected. Opening Playground...");
            }
        } catch (apiErr: any) {
             setIsLoading(false);
             addMessage(Sender.SYSTEM, `Analysis Error: ${apiErr.message}`);
        }

    } catch (err: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `File Read Error: ${err.message}`);
    } finally {
        if (resumeInputRef.current) resumeInputRef.current.value = '';
    }
  };

  return (
    <div className="flex flex-col h-[100dvh] bg-[#0d1117] text-[#c9d1d9] overflow-hidden font-mono antialiased selection:bg-emerald-500/30">
      {/* Header */}
      <header className="bg-[#161b22]/95 backdrop-blur-md border-b border-[#30363d] p-3 md:p-4 flex justify-between items-center shadow-lg z-10 shrink-0">
        <div className="flex items-center gap-3">
            <div className={`relative w-3 h-3 md:w-3.5 md:h-3.5 rounded-full flex items-center justify-center`}>
                <div className={`absolute inset-0 rounded-full animate-ping opacity-75 ${isLiveConnected ? 'bg-red-500' : 'bg-emerald-500'}`}></div>
                <div className={`relative w-full h-full rounded-full ${isLiveConnected ? 'bg-red-500' : 'bg-emerald-500'}`}></div>
            </div>
            <div className="flex flex-col">
                 <h1 className="font-bold text-base md:text-lg tracking-tight text-white leading-none">DEV_INTERVIEW_OS</h1>
                 <span className="text-[10px] text-gray-500 tracking-widest font-semibold mt-0.5">V3.0 • GEMINI NATIVE</span>
            </div>
        </div>
        <div className="flex items-center gap-2 md:gap-4 text-xs">
            {mode === InterviewMode.VOICE && <div className="scale-75 md:scale-100 origin-right"><AudioVisualizer isActive={isLiveConnected} /></div>}

            {resumeData && (
                <div className="flex items-center gap-1.5 text-emerald-400 bg-emerald-900/10 px-2 py-1 rounded-full border border-emerald-500/20 shadow-sm animate-fade-in">
                    <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                    <span className="hidden md:inline font-semibold">RESUME LOADED</span>
                </div>
            )}

            {/* Persona Switcher */}
            <div className="flex rounded-md border border-[#30363d] bg-[#0d1117] p-0.5">
                <button
                    onClick={() => setPersona(Persona.INTERVIEWER)}
                    disabled={mode === InterviewMode.VOICE}
                    className={`px-3 py-1 rounded-[4px] transition-all duration-200 font-medium ${persona === Persona.INTERVIEWER ? 'bg-[#238636] text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'} ${mode === InterviewMode.VOICE ? 'opacity-50 cursor-not-allowed' : ''}`}
                    title="Interviewer Persona"
                >
                    INTERVIEWER
                </button>
                <button
                    onClick={() => setPersona(Persona.TUTOR)}
                    disabled={mode === InterviewMode.VOICE}
                    className={`px-3 py-1 rounded-[4px] transition-all duration-200 font-medium ${persona === Persona.TUTOR ? 'bg-blue-600 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'} ${mode === InterviewMode.VOICE ? 'opacity-50 cursor-not-allowed' : ''}`}
                    title="Tutor Persona"
                >
                    TUTOR
                </button>
            </div>

            <button
                onClick={() => setShowCodeEditor(!showCodeEditor)}
                className={`px-3 py-1.5 rounded border transition-colors flex items-center gap-1.5 font-medium ${showCodeEditor ? 'bg-[#30363d] border-gray-500 text-white shadow-inner' : 'border-gray-700 text-gray-400 hover:border-gray-500 hover:text-gray-200'}`}
            >
                <span className="text-lg leading-none">{'{}'}</span>
                <span className="hidden md:inline">{showCodeEditor ? 'HIDE EDITOR' : 'CODE EDITOR'}</span>
            </button>
        </div>
      </header>

      {/* Main Content */}
      <div className="flex-1 flex overflow-hidden relative">
        <div className={`flex flex-col h-full transition-all duration-300 ${showCodeEditor ? 'hidden md:flex md:w-1/2 border-r border-[#30363d]' : 'w-full'}`}>
            <main className="flex-1 overflow-y-auto p-3 md:p-6 space-y-4 relative bg-[radial-gradient(#1f242d_1px,transparent_1px)] [background-size:20px_20px]">
                {messages.map((msg) => (
                <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}

                {isLoading && (
                    <div className="py-4 flex flex-col items-center justify-center animate-slide-up">
                        <div className="flex gap-2 mb-2">
                           <div className="w-2 h-2 bg-emerald-500 rounded-full loader-dot"></div>
                           <div className="w-2 h-2 bg-emerald-500 rounded-full loader-dot"></div>
                           <div className="w-2 h-2 bg-emerald-500 rounded-full loader-dot"></div>
                        </div>
                        <span className="text-xs text-emerald-500/70 font-mono animate-pulse">GENERATING RESPONSE</span>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </main>

            {/* Input Area */}
            <footer className="bg-[#161b22] border-t border-[#30363d] p-3 md:p-5 shrink-0 shadow-[0_-5px_15px_rgba(0,0,0,0.2)] z-10">
                <div className="w-full flex gap-3 md:gap-4 items-center">
                    <span className="text-emerald-500 font-bold select-none text-xl">›</span>

                    <form onSubmit={(e) => handleTextSubmit(e)} className="flex-1 min-w-0 relative">
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder={
                                mode === InterviewMode.VOICE ? "Voice Input Active - Microphone On..." : 
                                tokenMissing ? "CONFIGURATION REQUIRED: MISSING API KEY" : 
                                "Type your answer or ask a question..." 
                            }
                            className={`w-full bg-transparent border-none outline-none font-mono text-sm md:text-base disabled:cursor-not-allowed text-gray-200 placeholder-gray-600 caret-emerald-500 py-2`}
                            disabled={isLoading || tokenMissing || mode === InterviewMode.VOICE}
                            autoFocus
                        />
                    </form>

                    <div className="flex items-center gap-2 border-l border-[#30363d] pl-3">
                         {/* Resume Upload */}
                         <button 
                            onClick={() => resumeInputRef.current?.click()}
                            title="Upload Resume (PDF/Text/MD)"
                            className={`p-2 hover:bg-[#30363d] rounded-md transition-colors ${resumeData ? 'text-emerald-400' : 'text-gray-500 hover:text-gray-200'}`}
                        >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                        </button>
                        <input 
                            type="file" 
                            ref={resumeInputRef} 
                            className="hidden" 
                            accept=".pdf,.txt,.md,.json"
                            onChange={handleResumeUpload}
                        />

                        {/* STOP SPEAKING BUTTON */}
                        <button 
                            onClick={handleStopSpeaking}
                            title="Mute Audio Output"
                            className="p-2 hover:bg-[#30363d] rounded-md transition-colors text-gray-500 hover:text-red-400"
                        >
                            <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
                                <rect x="6" y="6" width="12" height="12" rx="1" ry="1" />
                            </svg>
                        </button>

                        <button 
                            onClick={toggleVoiceMode}
                            className={`px-4 py-2 rounded-md text-xs font-bold transition-all whitespace-nowrap flex items-center gap-2 shadow-lg ${
                                mode === InterviewMode.VOICE 
                                ? 'bg-red-600 hover:bg-red-700 text-white ring-2 ring-red-500/50' 
                                : 'bg-[#238636] hover:bg-[#2ea043] text-white'
                            }`}
                        >
                            {mode === InterviewMode.VOICE ? (
                                <>
                                    <span className="w-2 h-2 rounded-full bg-white animate-pulse"></span>
                                    <span className="hidden sm:inline">END SESSION</span>
                                </>
                            ) : (
                                <>
                                    <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 24 24"><path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3z"/><path d="M17 11c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z"/></svg>
                                    <span className="hidden sm:inline">LIVE INTERVIEW</span>
                                </>
                            )}
                        </button>
                    </div>
                </div>
            </footer>
        </div>

        {showCodeEditor && (
            <div className={`h-full ${showCodeEditor ? 'w-full md:w-1/2' : 'hidden'}`}>
                <CodeEditor onReviewRequest={handleCodeReviewRequest} />
            </div>
        )}
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, LiveServerMessage, Modality } from "@google/genai";
import { HfInference } from "@huggingface/inference";
import OpenAI from "openai";
import { GroundingChunk, Persona } from "../types";
import { createPcmBlob } from "../utils/audioUtils";

// Initialize Gemini Client
const apiKey = process.env.API_KEY || "missing_api_key";
const ai = new GoogleGenAI({ apiKey });

// Initialize Hugging Face Inference (For Images)
const hf = new HfInference(process.env.HF_TOKEN || "missing_hf_token");

// Initialize OpenAI Client for HF Router (Fallback - DeepSeek)
const hfRouter = new OpenAI({
  baseURL: "https://router.huggingface.co/v1",
  apiKey: process.env.HF_TOKEN || "missing_hf_token",
  dangerouslyAllowBrowser: true
});

const DEEPSEEK_MODEL = "deepseek-ai/DeepSeek-V3.2";

// --- Tools & Types ---

export interface ResumeData {
  data: string;
  mimeType: string;
}

// --- DeepSeek Integration (OpenAI Compatibility Layer) ---

const generateWithDeepSeek = async (
  systemPrompt: string, 
  userPrompt: string
): Promise<{ text: string, imagePrompt?: string, isCodingChallenge?: boolean } | null> => {
    if (process.env.HF_TOKEN === "missing_hf_token") return null;

    try {
        console.log(`Attempting generation with ${DEEPSEEK_MODEL} via HF Router...`);

        const jsonInstruction = `
        CRITICAL INSTRUCTION: You must respond with valid JSON only. Do not add markdown code blocks.
        JSON Schema:
        {
            "content": "string (the interview question)",
            "visual_description": "string | null (description for an image if needed)",
            "is_coding_challenge": "boolean"
        }`;

        const completion = await hfRouter.chat.completions.create({
            model: DEEPSEEK_MODEL,
            messages: [
                { role: "system", content: systemPrompt + jsonInstruction },
                { role: "user", content: userPrompt }
            ],
            max_tokens: 1024,
            temperature: 0.7,
            stream: false
        });

        const rawContent = completion.choices[0]?.message?.content || "{}";
        const cleanContent = rawContent.replace(/```json/g, "").replace(/```/g, "").trim();

        let parsed;
        try {
            parsed = JSON.parse(cleanContent);
        } catch (parseErr) {
            console.warn("DeepSeek JSON Parse Failed, using raw text:", rawContent);
            return {
                text: rawContent,
                isCodingChallenge: false
            };
        }

        return {
            text: parsed.content || rawContent,
            imagePrompt: parsed.visual_description,
            isCodingChallenge: !!parsed.is_coding_challenge
        };
    } catch (e: any) {
        console.warn(`DeepSeek (${DEEPSEEK_MODEL}) failed:`, e.message);
        return null;
    }
};

// --- Text & Reasoning (Standard API) ---

export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false,
  resume?: ResumeData
): Promise<{ text: string, imagePrompt?: string, grounding?: GroundingChunk[], isCodingChallenge?: boolean }> => {

  if (apiKey === "missing_api_key") {
      return { text: "Error: API Key is missing. Please configure it in your deployment settings." };
  }

  const baseInstruction = persona === Persona.TUTOR 
    ? "You are an expert AI Coding Tutor. Explain concepts clearly, provide code snippets, and be encouraging."
    : `You are a strict Senior Technical Interviewer. 
1. Ask one distinct question at a time.
2. If a resume is provided, prioritize questions about it.
3. For coding problems, provide Title, Description, Examples, and Constraints.
4. Do not give full solutions.`;

  let prompt = history;

  if (resume) {
      prompt = `RESUME CONTEXT:\n${resume.data}\n\n${prompt}`;
  }

  // --- Default: Gemini ---
  let systemInstruction = `${baseInstruction}

  CRITICAL: You must respond in JSON format.
  If the question requires the user to write code (e.g. "Write a function...", "Implement...", "Solve this algorithm..."), set 'is_coding_challenge' to true.
  If the concept involves data structures, algorithms, or architecture that benefits from visualization, provide a 'visual_description'.
  Otherwise, 'visual_description' should be null.`;

  try {
    const model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
    const config: any = {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.OBJECT,
            properties: {
                content: { type: Type.STRING },
                visual_description: { type: Type.STRING, nullable: true },
                is_coding_challenge: { type: Type.BOOLEAN }
            },
            required: ["content", "is_coding_challenge"]
        }
    };

    if (useThinking) {
        config.thinkingConfig = { thinkingBudget: 2048 };
    }

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config
    });

    const grounding: GroundingChunk[] = [];
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
        response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
            if (chunk.web) grounding.push({ web: chunk.web });
        });
    }

    let parsedResponse;
    try {
        parsedResponse = JSON.parse(response.text || "{}");
    } catch (e) {
        return { text: response.text || "Error parsing response." };
    }

    return {
      text: parsedResponse.content || "Error generating content.",
      imagePrompt: parsedResponse.visual_description,
      grounding,
      isCodingChallenge: parsedResponse.is_coding_challenge
    };
  } catch (error: any) {
    console.error("Gemini API Error:", error);

    // Final Attempt: Try DeepSeek as fallback if Gemini failed
    const deepSeekFallback = await generateWithDeepSeek(baseInstruction, prompt);
    if (deepSeekFallback) {
          return {
              ...deepSeekFallback,
              text: `${deepSeekFallback.text}\n\n[Fallback: ${DEEPSEEK_MODEL}]`
          };
    }

    return { text: `API Error: ${error.message || "Unknown error"}` };
  }
};

export const fastAck = async (input: string): Promise<string> => {
