import { createPcmBlob } from "../utils/audioUtils";

// Initialize Gemini Client
const apiKey = process.env.API_KEY || "missing_api_key";
const ai = new GoogleGenAI({ apiKey });

// Initialize Hugging Face Inference (For Images)
const hf = new HfInference(process.env.HF_TOKEN || "missing_hf_token");

// Initialize OpenAI Client for HF Router (Fallback - DeepSeek)
const hfRouter = new OpenAI({
  baseURL: "https://router.huggingface.co/v1",
  apiKey: process.env.HF_TOKEN || "missing_hf_token",
  dangerouslyAllowBrowser: true
});

const DEEPSEEK_MODEL = "deepseek-ai/DeepSeek-V3.2";

// --- Tools & Types ---

export interface ResumeData {
  data: string;
  mimeType: string;
}

// --- DeepSeek Integration (OpenAI Compatibility Layer) ---

const generateWithDeepSeek = async (
  systemPrompt: string, 
  userPrompt: string
): Promise<{ text: string, imagePrompt?: string, isCodingChallenge?: boolean } | null> => {
    if (process.env.HF_TOKEN === "missing_hf_token") return null;

    try {
        console.log(`Attempting generation with ${DEEPSEEK_MODEL} via HF Router...`);

        const jsonInstruction = `
        CRITICAL INSTRUCTION: You must respond with valid JSON only. Do not add markdown code blocks.
        JSON Schema:
        {
            "content": "string (the interview question)",
            "visual_description": "string | null (description for an image if needed)",
            "is_coding_challenge": "boolean"
        }`;

        const completion = await hfRouter.chat.completions.create({
            model: DEEPSEEK_MODEL,
            messages: [
                { role: "system", content: systemPrompt + jsonInstruction },
                { role: "user", content: userPrompt }
            ],
            max_tokens: 1024,
            temperature: 0.7,
            stream: false
        });

        const rawContent = completion.choices[0]?.message?.content || "{}";
        const cleanContent = rawContent.replace(/```json/g, "").replace(/```/g, "").trim();

        let parsed;
        try {
            parsed = JSON.parse(cleanContent);
        } catch (parseErr) {
            console.warn("DeepSeek JSON Parse Failed, using raw text:", rawContent);
            return {
                text: rawContent,
                isCodingChallenge: false
            };
        }

        return {
            text: parsed.content || rawContent,
            imagePrompt: parsed.visual_description,
            isCodingChallenge: !!parsed.is_coding_challenge
        };
    } catch (e: any) {
        console.warn(`DeepSeek (${DEEPSEEK_MODEL}) failed:`, e.message);
        return null;
    }
};

// --- Text & Reasoning (Standard API) ---

export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false,
  resume?: ResumeData,
  imageContext?: { mimeType: string; data: string }
): Promise<{ text: string, imagePrompt?: string, grounding?: GroundingChunk[], isCodingChallenge?: boolean }> => {

  if (apiKey === "missing_api_key") {
      return { text: "Error: API Key is missing. Please configure it in your deployment settings." };
  }

  const baseInstruction = persona === Persona.TUTOR 
    ? "You are an expert AI Coding Tutor. Explain concepts clearly, provide code snippets, and be encouraging."
    : `You are a strict Senior Technical Interviewer. 
1. Ask one distinct question at a time.
2. If a resume is provided, prioritize questions about it.
3. For coding problems, provide Title, Description, Examples, and Constraints.
4. Do not give full solutions.`;

  let prompt = history;

  if (resume) {
      prompt = `RESUME CONTEXT:\n${resume.data}\n\n${prompt}`;
  }

  // --- Default: Gemini ---
  let systemInstruction = `${baseInstruction}

  CRITICAL: You must respond in JSON format.
  If the question requires the user to write code (e.g. "Write a function...", "Implement...", "Solve this algorithm..."), set 'is_coding_challenge' to true.
  If the concept involves data structures, algorithms, or architecture that benefits from visualization, provide a 'visual_description'.
  Otherwise, 'visual_description' should be null.`;

  try {
    const model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
    const config: any = {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.OBJECT,
            properties: {
                content: { type: Type.STRING },
                visual_description: { type: Type.STRING, nullable: true },
                is_coding_challenge: { type: Type.BOOLEAN }
            },
            required: ["content", "is_coding_challenge"]
        }
    };

    if (useThinking) {
        config.thinkingConfig = { thinkingBudget: 2048 };
    }

    let contents: any = prompt;

    if (imageContext) {
        // Construct multimodal content
        contents = {
            parts: [
                { text: prompt },
                {
                    inlineData: {
                        mimeType: imageContext.mimeType,
                        data: imageContext.data.includes(',') ? imageContext.data.split(',')[1] : imageContext.data
                    }
                }
            ]
        };
    }

    const response = await ai.models.generateContent({
      model,
      contents,
      config
    });

    const grounding: GroundingChunk[] = [];
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
        response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
            if (chunk.web) grounding.push({ web: chunk.web });
        });
    }

    let parsedResponse;
    try {
        parsedResponse = JSON.parse(response.text || "{}");
    } catch (e) {
        return { text: response.text || "Error parsing response." };
    }

    return {
      text: parsedResponse.content || "Error generating content.",
      imagePrompt: parsedResponse.visual_description,
      grounding,
      isCodingChallenge: parsedResponse.is_coding_challenge
    };
  } catch (error: any) {
    console.error("Gemini API Error:", error);

    // Final Attempt: Try DeepSeek as fallback if Gemini failed
    const deepSeekFallback = await generateWithDeepSeek(baseInstruction, prompt);
    if (deepSeekFallback) {
          return {
              ...deepSeekFallback,
              text: `${deepSeekFallback.text}\n\n[Fallback: ${DEEPSEEK_MODEL}]`
          };
    }

    return { text: `API Error: ${error.message || "Unknown error"}` };
  }
};

