// --- Live API (Real-time Audio) ---

export interface LiveSessionConfig {
  onOpen: () => void;
  onAudioData: (base64: string) => void;
  onTranscript: (text: string, isUser: boolean, isFinal: boolean) => void;
  onClose: () => void;
  onError: (err: any) => void;
  onInterrupted: () => void;
  persona: Persona;
}

export const connectToLiveSession = async (config: LiveSessionConfig) => {
  if (apiKey === "missing_api_key") {
      config.onError(new Error("API Key missing"));
      return { sendAudioChunk: () => {}, disconnect: () => {} };
  }

  const model = 'gemini-2.5-flash-native-audio-preview-12-2025';

  const systemInstruction = config.persona === Persona.TUTOR
    ? "You are a helpful and patient Coding Tutor. Listen to the student's questions and guide them. Keep answers concise for spoken conversation."
    : "You are a strict Technical Interviewer. Conduct a professional coding interview. Ask one short, clear question at a time. Do not ramble. Interrupt if the candidate is off track.";

  const sessionPromise = ai.live.connect({
    model,
    callbacks: {
      onopen: () => {
        config.onOpen();
      },
      onmessage: (message: LiveServerMessage) => {
        // Handle Audio Output
        const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
        if (audioData) {
          config.onAudioData(audioData);
        }

        // Handle Transcripts
        if (message.serverContent?.outputTranscription) {
            config.onTranscript(message.serverContent.outputTranscription.text || "", false, !!message.serverContent.turnComplete);
        } else if (message.serverContent?.inputTranscription) {
            config.onTranscript(message.serverContent.inputTranscription.text || "", true, true);
        }

        // Handle Interruption (User spoke while AI was speaking)
        if (message.serverContent?.interrupted) {
            config.onInterrupted();
        }
      },
      onclose: () => {
        config.onClose();
      },
      onerror: (err) => {
        config.onError(err);
      }
    },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
      },
      inputAudioTranscription: {}, 
      outputAudioTranscription: {}, 
      systemInstruction: { parts: [{ text: systemInstruction }] },
    }
  });

  return {
    sendAudioChunk: (data: Float32Array) => {
      const blob = createPcmBlob(data);
      sessionPromise.then(session => {
        session.sendRealtimeInput({ media: blob });
      });
    },
    disconnect: () => {
      sessionPromise.then(session => session.close());
    }
  };
};

// --- Image Generation ---

export const generateImage = async (prompt: string): Promise<string> => {
  if (apiKey === "missing_api_key") throw new Error("API Key missing");

  // 1. Primary: Gemini 2.5 Flash Image (Fast, Native)
  try {
      console.log("Generating with Gemini 2.5 Flash Image...");
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: { parts: [{ text: prompt }] },
          config: { imageConfig: { aspectRatio: "16:9" } }
      });
      for (const part of response.candidates?.[0]?.content?.parts || []) {
          if (part.inlineData && part.inlineData.data) {
              return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
          }
      }
      console.warn("Gemini 2.5 Flash Image returned no image data.");
  } catch (error: any) {
      console.warn("Gemini 2.5 Flash Image Error:", error.message);
  }

  // 2. Secondary: Imagen 3 (High Quality)
  try {
      console.log("Fallback: Generating with Imagen 3.0...");
      const response = await ai.models.generateImages({
        model: 'imagen-3.0-generate-001',
        prompt: prompt,
        config: {
          numberOfImages: 1,
          outputMimeType: 'image/jpeg',
          aspectRatio: '16:9',
        },
      });
      const b64 = response.generatedImages?.[0]?.image?.imageBytes;
      if (b64) {
          return `data:image/jpeg;base64,${b64}`;
      }
      console.warn("Imagen 3.0 returned no image data.");
  } catch(e: any) {
      console.warn("Imagen 3.0 Error:", e.message);
  }

  // 3. Last Resort: Hugging Face (External)
  const hfModels = [
    "runwayml/stable-diffusion-v1-5", 
    "stabilityai/stable-diffusion-2-1"
  ];

  for (const model of hfModels) {
    try {
        if (process.env.HF_TOKEN === "missing_hf_token") continue;
        console.log(`Attempting image gen with HF model: ${model}...`);
        const blob = await hf.textToImage({
          model: model,
          inputs: prompt,
          parameters: {
            negative_prompt: "blurry, low quality, distortion, ugly, text, watermark",
          }
        });
        return await new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.onerror = reject;
          reader.readAsDataURL(blob as unknown as Blob);
        });
    } catch (error: any) {
        console.warn(`HF Error (${model}):`, error.message);
    }
  }

  throw new Error("Failed to generate visualization (All models failed).");
};

// --- Code Execution & Review ---

export const runCodeWithAI = async (language: string, code: string): Promise<string> => {
  if (apiKey === "missing_api_key") return "Error: API Key missing.";
  try {
    const prompt = `Act as a strictly deterministic compiler/interpreter for ${language}.
EXECUTE the code and return ONLY the stdout/stderr.
Code:
${code}`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt
    });
    let text = response.text || "";
    text = text.replace(/^```[\w]*\n?/, '').replace(/\n?```$/, '');
    return text.trim() || "[No Output]";
  } catch (error: any) {
    console.error("Run Code Error:", error);
    return `Error executing code: ${error.message}`;
  }
};

export const reviewCodeWithAI = async (language: string, code: string): Promise<string> => {
  if (apiKey === "missing_api_key") return "Error: API Key missing.";
  const prompt = `Review this ${language} code for bugs and improvements:
${code}`;

  try {
    // Try DeepSeek first for code review (Secondary usage of DeepSeek as "Expert Reviewer")
    const deepSeekReview = await generateWithDeepSeek(
        "You are an expert code reviewer. Provide concise feedback.", 
        prompt + "\nReturn JSON with 'content' field containing the review."
    );
    if (deepSeekReview) {
        return deepSeekReview.text + `\n\n[Reviewed by ${DEEPSEEK_MODEL}]`;
    }

    // Fallback to Gemini Pro
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt
    });
    return response.text || "No feedback generated.";
  } catch (error: any) {
    console.warn("Review failed with Pro/DeepSeek, trying Flash:", error.message);
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt
        });
        return response.text || "No feedback generated.";
    } catch (fallbackError: any) {
        console.error("Review Error:", fallbackError);
        return `Unable to review code. Error: ${fallbackError.message}`;
    }
  }
};

// --- Maps Grounding ---
export const getGeographicContext = async (query: string, lat?: number, lng?: number): Promise<{ text: string, grounding: GroundingChunk[] }> => {
  if (apiKey === "missing_api_key") return { text: "API Key missing.", grounding: [] };
  try {
      const config: any = { tools: [{ googleMaps: {} }] };
      if (lat && lng) {
          config.toolConfig = { retrievalConfig: { latLng: { latitude: lat, longitude: lng } } };
      }
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash', 
          contents: query,
          config
      });
      const grounding: GroundingChunk[] = [];
      if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
           response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
               if (chunk.maps) grounding.push({ maps: chunk.maps });
               if (chunk.web) grounding.push({ web: chunk.web });
           });
      }
      return { text: response.text || "No location info.", grounding };
  } catch (e) {
      return { text: "Geographic context currently unavailable.", grounding: [] };
  }
};

